INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5b0c1d2-e3f4-4a5b-86d7-e8f9a0b1c2d3', 'All disputes arising out of or relating to these Terms shall be resolved through confidential binding arbitration. The parties agree not to disclose the existence, content, or outcome of any arbitration proceeding to any third party, except as required by law or to enforce the arbitration award. The arbitration proceedings shall be governed by rules selected by the Company, and the arbitrator shall be chosen from a panel maintained by the Company''s preferred arbitration provider.', 'arbitration', '["tos"]'::jsonb, 'red', 'Confidential arbitration prevents consumers from learning about patterns of company misconduct. If the company loses an arbitration case, no one else ever finds out, so they can keep engaging in the same harmful practices. The company also controls which arbitration service is used and which arbitrator is selected, creating structural bias in its favor.', 'Disputes may be resolved through arbitration administered by a recognized, independent arbitration institution. The arbitrator shall be selected jointly by both parties from the institution''s panel. Either party may disclose the existence and outcome of arbitration proceedings. Nothing in this clause prevents either party from pursuing claims in small claims court.', 'EU Unfair Contract Terms Directive Annex 1(q) flags terms requiring arbitration not covered by legal provisions. EU Directive 2013/11 on consumer ADR requires accessible, independent dispute resolution. US courts have occasionally struck down arbitration clauses as unconscionable where the company controls arbitrator selection (Armendariz v. Foundation Health Psychcare, Cal. 2000). UK Arbitration Act 1996 Section 89-91 provides consumer protections.', '[0.012410711,-0.04759301,0.009807917,-0.005458983,-0.06966126,-0.0064156