,0.019382326,-0.00227338,-0.028628478,0.015989836,-0.03873858,0.018913073,0.004686778,0.010701003,-0.012558764,0.010457737,-0.021740744,0.076734364,-0.025271075,0.01791158,-0.016120248,0.027174525,-0.007076067,0.013905223,-0.008352841,-0.01637592,-0.035703026,-0.0150107,-0.03569981,-0.032099936,0.036204003,0.024907235,-0.002387558,0.02323361,0.018230107,-0.007840414,-0.03294244,-0.000482582,0.003692633,-0.001022912,0.012065767,-0.018102422,0.001342082,0.033478282,0.02491703,-0.042468052]'::vector, '2026-03-14T19:51:56.569Z');
INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5d4e5f6-a7b8-4c9d-a0f1-a2b3c4d5e6f7', 'Any dispute, claim, or controversy arising out of or relating to these Terms or the breach, termination, enforcement, interpretation, or validity thereof, including the determination of the scope or applicability of this agreement to arbitrate, shall be determined exclusively by binding arbitration administered by a private arbitration service selected by the Company. The arbitration shall be conducted in San Francisco, California. The arbitrator''s decision shall be final and binding and may be entered as a judgment in any court of competent jurisdiction. YOU AGREE THAT YOU MAY BRING CLAIMS AGAINST THE COMPANY ONLY IN YOUR INDIVIDUAL CAPACITY AND NOT AS A PLAINTIFF OR CLASS MEMBER IN ANY PURPORTED CLASS OR REPRESENTATIVE PROCEEDING.', 'arbitration', '["tos"]'::jsonb, 'red', 'This forces you to settle disputes through private arbitration (a process where a private judge decides instead of a court) in San Francisco, which is expensive and impractical for most users. The company chooses the arbitration service, creating a built-in bias. The class action waiver means even if the company harms millions of users, each must fight alone, making small claims economically impossible to pursue.', 'We encourage resolution of disputes through our customer support team. If informal resolution fails, either party may initiate arbitration through a mutually agreed-upon, nationally recognized arbitration service. Arbitration may be conducted remotely or in the claimant''s home jurisdiction. For claims under $10,000, the Company will bear all arbitration costs. Nothing in this clause prevents you from bringing claims in small claims court or limits your right to seek injunctive relief in any court of competent jurisdiction.', 'EU Unfair Contract Terms Directive Annex 1(q) flags terms requiring disputes to be taken exclusively to arbitration not covered by legal provisions. CJEU case Océano Grupo (C-240/98) held jurisdiction clauses requiring consumers to litigate far from home are unfair. US Supreme Court in AT&T Mobility v. Concepcion (2011) upheld class action waivers in arbitration, but state laws vary. UK CRA 2015 Schedule 2 para 20 grey-lists terms requiring arbitration.', '[-0.000256932,-0.000816838,0.023636833,0.008363576,-0.025777789,0.02860939,-0.018465372,0.020623969,0.030121401,0.054596145,0.006830842,-0.043708034,0.04260777,-0.08630677,-0.011532529,0.022830443,-0.007245891,0.030680226,-0.00754131,0.01688569,-0.043689374,-0.007934499,-0.027937667,-0.020232834,-0.001334397,-0.016786264,0.06316627,-0.003184235,-0.001070162,0.06946039,0.011752333,0.06027741,0.036856256,-0.05776121,0.012030891,8.289e-06,-0.00521725,0.017751945,0.004185014,-0.054069776,0.018854586,0.014040592,0.015538671,0.00609342,0.042671595,0.021293148,-0.03211695,0.016231323,-0.006313728,-0.05608353,0.038405754,-0.026910217,0.002640747,0.020161744,-0.015830636,0.042368498,0.040411998,0.030384714,-0.04206833,-0.012429636,0.04536658,0.00498629,0.00779689,0.059737988,0.013438731,-0.05404327,-0.012537363,0.009930505,0.03263469,-0.016278256,0.03915197,0.028018728,-0.012668326,0.018073224,0.014616998,-0.005029165,0.010851141,0.038499422,0.056766767,0.002119957,-0.030823141,-0.015235383,-0.071507394,0.02431076,-0.000847408,0.017824292,-0.003278264,0.048027735,0.062216267,0.04869949,-0.024783907,-0.011335269,0.053485885,0.014761218,-0.0070864,-0.016499188,0.008267345,-0.035422903,-0.009551772,-0.032981317,-0.046507318,0.013315125,-0.028369254,0.009196284,0.049869765,0.00921023,0.00022018,-0.030411035,0.001598937,0.065838486,-0.006251604,-0.025594577,0.017040063,0.03191786,0.03872906,0.00255131,-0.026361013,0.002281462,0.023375032,-0.044016577,-0.012835555,-0.016102584,0.021835985,0.011798103,0.043619055,0.006927594,0.001806713,-0.04557513,0.060911536,0.049989544,0.042