INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4d2e3f4-5a6b-4c7d-9e0f-1a2b3c4d5e6f', 'Any and all disputes, claims, or controversies arising out of or relating to this Agreement, the Employee''s employment, or the termination thereof, including but not limited to claims of discrimination, harassment, retaliation, wrongful termination, or wage and hour violations, shall be resolved exclusively by final and binding arbitration administered by a neutral arbitration service selected by the Company. The arbitration shall be conducted on an individual basis only; the Employee waives any right to participate in a class action, collective action, or representative proceeding of any kind.', 'arbitration', '["employment"]'::jsonb, 'red', 'This clause forces all disputes into private arbitration chosen by the company and eliminates your right to join a class action. Arbitration is conducted behind closed doors, meaning systemic problems like widespread wage theft or discrimination can be hidden. The company picks the arbitration service, creating a structural advantage. Waiving class actions means each employee must fight individually, which is often economically impractical for small claims, effectively giving the company immunity from accountability.', 'The parties agree to attempt good-faith mediation of any dispute arising under this Agreement before initiating arbitration or litigation. If mediation is unsuccessful, either party may submit the dispute to binding arbitration administered by a mutually agreed-upon arbitration service, with the arbitrator selected jointly from a panel. The Company shall bear all arbitration fees and costs exceeding what the Employee would have paid in court filing fees. Nothing in this clause prevents the Employee from filing a charge with the Equal Employment Opportunity Commission, a state labor agency, or other government body, or from participating in a class, collective, or representative action regarding wage and hour claims.', 'US Supreme Court in Epic Systems Corp. v. Lewis (2018) upheld class action waivers in arbitration agreements under the Federal Arbitration Act, but states are pushing back. California''s PAGA (Private Attorneys General Act) claims cannot be waived per Iskanian v. CLS Transportation (2014), partially limited by Viking River Cruises v. Moriana (2022). NLRA section 7 protects concerted activity, and the NLRB has challenged overbroad arbitration clauses. UK Employment Rights Act 1996 section 203 prohibits contracting out of statutory employment rights, including the right to bring tribunal claims.', '[-0.000243933,-0.012265,0.009912502,0.02065578,-0.05019477,0.049983893,-0.02324607,0.0277277,-0.012665112,0.050672982,-0.006966098,-0.047060344,0.026148032,-0.030577151,0.015037166,0.001882071,-0.006121268,0.018663902,-0.006967599,0.014593759,-0.03833871,-0.010636535,-0.021632977,-0.000520135,0.039979093,-0.06230795,0.020883232,-0.000203537,0.00060964,0.026570473,0.021900214,0.07359679,0.020084342,-0.041242927,0.009634951,0.008508878,0.012303203,-0.016403247,0.035972457,-0.021731753,-0.009941809,0.019987887,0.06795211,0.035831857,0.02626642,0.009043708,-0.006786212,0.049365588,-0.016922915,-0.001583858,0.032064278,-0.008337889,-0.034893375,0.045015894,0.033892103,0.02545125,0.043940388,0.037879083,-0.0247652,-0.032525558,0.07340044,-0.025236288,-0.00072039,0.0613801,-0.036505055,-0.049614154,0.008738692,-0.023912637,0.014946764,0.00834163,0.0729954,0.04239776,-0.001877288,0.022903295,0.003573917,0.003394551,-0.033557836,0.019057263,0.048215594,0.023121258,-0.077460654,-0.054233737,0.003031971,0.019003948,-0.013374081,0.010867157,0.000753205,0.023847412,0.062316068,0.06539675,-0.032294393,-0.000444128,0.041801438,-0.001030031,0.032516096,0.023433138,0.023011029,-0.007209437,0.01259281,-0.01749745,-0.076217175,0.008544659,-0.02774029,0.015099045,0.03829764,0.