INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5a5b6c7-d8e9-4f0a-b1c2-d3e4f5a6b7c8', 'Any proceedings to resolve or litigate any dispute in any forum shall be conducted solely on an individual basis. Neither you nor the Company shall seek to have any dispute heard as a class action, private attorney general action, or in any other proceeding in which either party acts or proposes to act in a representative capacity. No arbitration or proceeding shall be combined with another without the prior written consent of all parties to all affected arbitrations or proceedings.', 'arbitration', '["tos"]'::jsonb, 'red', 'Class action waivers prevent consumers from banding together to challenge company misconduct. If a company overcharges 10 million users by $5 each, no individual will spend thousands on a lawyer for $5. Class actions are the only practical remedy for widespread small-dollar harm. This clause effectively grants the company immunity for small-scale but systemic abuse.', 'For individual claims under $10,000, either party may elect individual arbitration or small claims court. This clause does not waive your right to participate in a class action or representative proceeding for claims arising from data breaches, systematic billing errors, or violations of consumer protection statutes.', 'US Supreme Court in AT&T Mobility v. Concepcion (2011) upheld class action waivers under the Federal Arbitration Act, but Epic Systems v. Lewis (2018) was more nuanced. EU Directive 2020/1828 on representative actions for consumer protection explicitly enables collective redress. UK Competition Appeal Tribunal allows opt-out class actions. CFPB attempted to ban class action waivers in financial contracts (later overturned by Congress).', '[-0.003980781,0.040515237,-0.05173176,0.04364469,-0.021708464,0.01211481,-0.016623294,0.024740163,0.028962051,0.07269111,