INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5a3b4c5-d6e7-4f8a-b9c0-d1e2f3a4b5c6', 'You agree that any cause of action or claim arising out of or related to your use of the Services must be commenced within one (1) year after the cause of action accrues. Otherwise, such cause of action or claim is permanently barred. You acknowledge that this limitation period may be shorter than the statute of limitations that would otherwise apply under applicable law, and you knowingly and voluntarily waive any longer limitations period.', 'arbitration', '["tos"]'::jsonb, 'yellow', 'This cuts the time you have to file a lawsuit from the normal legal deadline (often 2-6 years depending on the claim) to just one year. Many people don''t discover they''ve been harmed until well after a year, especially with data breaches or billing disputes. By the time you realize something is wrong, your right to take action may already be gone.', 'Any claim arising under these Terms must be commenced within the statute of limitations applicable under the governing law. We will not enforce a contractual limitations period shorter than two (2) years or shorter than the applicable statutory limitation, whichever is longer.', 'EU Unfair Contract Terms Directive Annex 1(q) flags terms unduly restricting evidence or imposing burden of proof. UK Limitation Act 1980 sets statutory limitation periods that consumer contracts cannot shorten below the statutory minimum. Some US states (e.g., California Civil Code Section 2468) prohibit contractual shortening of statutes of limitations for consumer contracts.', '[0.009959583,-0.019227153,-0.014729712,0.046840027,-0.061597332,0.013962359,0.005496158,-0.005397055,-0.004285671,0.045224015,0.001282755,-0.023950214,-0.013769991,-0.043289255,0.006928426,0.04371792,0.003727847,0.02260194,0.011311344,0.09809382,-0.026024165,-0.014151975,-0.08