INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4f4a5b6-7c8d-4e9f-8a2b-3c4d5e6f7a8b', 'In the event of any dispute subject to arbitration under this Agreement, each party shall bear its own attorneys'' fees and costs, regardless of the outcome. The Employee acknowledges that the Company shall have the right to select the arbitration forum, and the arbitration shall take place in the county and state where the Company''s principal offices are located.', 'arbitration', '["employment"]'::jsonb, 'yellow', 'This clause stacks the deck in two ways. First, the company picks both the arbitration forum and the location, meaning you might have to travel across the country to arbitrate. Second, each side pays their own legal fees regardless of who wins, which removes the fee-shifting that employment laws like Title VII normally provide to successful discrimination claimants. This makes it economically impossible for most employees to bring valid claims, since the cost of an attorney and travel could exceed the potential recovery.', 'Arbitration shall be conducted by a mutually agreed-upon arbitration service. If the parties cannot agree, the arbitration service shall be selected by alternating strikes from a list provided by the American Arbitration Association. The arbitration shall take place in the metropolitan area where the Employee was primarily employed. The Company shall bear all filing fees and arbitrator costs. The arbitrator shall have authority to award attorneys'' fees and costs to the prevailing party consistent with applicable statutory fee-shifting provisions.', 'US Supreme Court in Green Tree Financial Corp. v. Randolph (2000) held that arbitration agreements may be unenforceable if prohibitively expensive for the employee. The EEOC has stated that employer-selected arbitration forums create an appearance of bias. Title VII (42 USC section 2000e-5(k)) provides for fee-shifting to prevailing plaintiffs in discrimination cases; clauses that eliminate statutory fee-shifting may be unenforceable. California Code of Civil Procedure section 1284.3 limits employee arbitration costs.', '[-0.042880494,-0.006633476,-0.02620626,-0.012642651,-0.02736367,0.019196881,-0.010041767,0.005031829,-0.001508827,0.049953297,0.002739859,0.047750663,0.035809122,-0.015009403,0.051765624,0.022817414,0.004238646,0.03332724,0.010728516,7.2246e-05,0.001919896,-0.034281757,0.01116514,0.03453195,0.027051907,0.001720024,0.011319567,-0.000828107,-0.002969973,0.037357915,0.02813513,-0.013430499,0.010386859,-0.052740343,-0.012044619,-0.017924173,-0.005097173,-0.001188194,-0.027155116,0.009852212,0.007513414,0.030543951,0.07287301,0.037159543,0.02562118,0.022335965,0.046588287,0.014921649,0.010885741,-0.015868962,0.042965733,-0.011606753,-0.04533722,0.005821888,-0.010685047,-0.007109596,-0.041130845,-0.01700341,-0.03042988,0.007225936,0.0685324,0.016036697,-0.046340603,0.017048415,-0.02577096,-0.07865577,-0.02535745,0.049372572,0.015455664,0.011680678,0.012031189,-0.010017289,-0.006826775,0.031872638,0.024771981,-0.025268497,-0.035205714,0.029489424,0.007247682,0.02396516,-0.028493602,-0.021628873,-0.000318896,0.018303055,-0.014099891,-0.024173152,-0.001205113,0.000987737,0.04570557,0.03431983,-0.023418846,-0.056549735,0.043402947,0.012862271,0.01017372,0.019116398,-0.010030158,0.001494301,0.044247236,-0.018260267,-0.030899575,-0.012544706,0.006099514,0.021257875,0.014959433,0.025982007,0.015964856,0.021814657,0.007732345,0.035629287,0.006771232,-0.021165,0.008287375,0.033605684,0.02199287,-0.021836549,-0.025218343,-0.010829643,0.04056923,0.043048296,-0.034230314,-0.011683785,-0.031175198,0.006342875,-0.007757626,-0.002283026,0.004809127,-0.050009876,0.07494468,0.020720905,0.018165005,0.033021033,0.00733099,-0.01057981,-0.010101655,0.049445868,0.03198128,0.012967857,-0.01483627,0.02417855,-0.027623907,-0.014291585,0.010410943,0.082411