INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5e5f6a7-b8c9-4d0e-b1a2-b3c4d5e6f7a8', 'Your subscription will automatically renew for successive renewal periods of the same duration as the initial subscription period at the then-current rate, which may be higher than your initial rate, unless you cancel at least thirty (30) days before the end of the current billing period. You may cancel your subscription by contacting our support team via registered mail or by visiting the account management page (where available). Cancellation will take effect at the end of the current billing period; no refunds or credits will be issued for partial billing periods, unused time, or any fees already charged.', 'auto_renewal', '["tos"]'::jsonb, 'yellow', 'The subscription auto-renews at potentially higher prices without guaranteed advance notice of the increase. The 30-day cancellation window is easy to miss, and requiring ''registered mail'' makes cancellation deliberately difficult. No partial refunds means you could pay for a full year and lose access after one month if you miss the window.', 'Your subscription will automatically renew at the same rate unless we notify you of any price change at least 30 days in advance, giving you the option to cancel before the new rate applies. You may cancel your subscription at any time through your account settings. If you cancel, you will retain access until the end of your current billing period. For annual plans, you may request a pro-rated refund for unused months within 30 days of renewal.', 'EU Consumer Rights Directive (2011/83/EU) Article 8(2) requires clear disclosure of auto-renewal terms before purchase. FTC guidelines on negative option marketing require clear disclosure and simple cancellation mechanisms. California ARL (Business & Professions Code Section 17600-17606) requires clear auto-renewal disclosu