INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5c1d2e3-f4a5-4b6c-97e8-f9a0b1c2d3e4', 'We may offer a free trial period for certain subscription plans. If you do not cancel before the free trial ends, you will be automatically enrolled in the paid subscription and your payment method on file will be charged at the full subscription rate. You acknowledge that the Company is not required to provide a reminder or notification before the trial period ends and your paid subscription begins. The initial charge may include the full annual subscription amount if you selected an annual plan.', 'auto_renewal', '["tos"]'::jsonb, 'yellow', 'Free trials that silently convert to paid subscriptions without a reminder are a classic dark pattern. Many users forget they signed up. Charging a full annual fee with no warning is especially aggressive: you could be hit with hundreds of dollars because you forgot about a trial. The explicit disclaimer that they don''t need to remind you shows they know this catches people off guard.', 'At the end of your free trial, we will send you a reminder at least 7 days before the trial expires, informing you of the upcoming charge and the subscription rate. Your paid subscription will begin only after you confirm your intent to continue. If you do not confirm, your trial will end and no charges will be applied to your payment method.', 'FTC has brought enforcement actions under Section 5 against free-to-paid subscription traps (e.g., FTC v. ABCmouse). EU Consumer Rights Directive (2011/83/EU) Article 8(2) requires clear disclosure of total costs before consumer is bound. California ARL requires clear disclosure of automatic renewal offer terms and affirmative consent. UK CRA 2015 Sections 62-64 require transparency in consumer contract terms.', '[-0.018338975,0.046088178,0.035552204,-0.001944721,-0.0669657,0.013390417,-0.04312