INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4a5b6c7-8d9e-4f0a-9b3c-4d5e6f7a8b9c', 'In the event the Employee voluntarily resigns or is terminated for Cause within thirty-six (36) months of completing any training program, professional development course, certification, or educational program funded or subsidized in whole or in part by the Company, the Employee shall repay the Company the full cost of such training, including tuition, fees, materials, travel expenses, and the Employee''s salary during training periods, within sixty (60) days of the Employee''s last day of employment.', 'benefits_clawback', '["employment"]'::jsonb, 'red', 'This is a Training Repayment Agreement Provision (TRAP). It requires full repayment of all training costs -- including your own salary during training -- for three years, with no reduction over time. This can amount to tens of thousands of dollars and effectively traps you in your job because you cannot afford to leave. Including your salary as a ''training cost'' means you are repaying the company for paying you to work. Regulators and courts increasingly view TRAPs as a form of debt bondage that suppresses worker mobility and wages.', 'If the Employee voluntarily resigns within twelve (12) months of completing an external certification program costing more than five thousand dollars ($5,000) funded by the Company, the Employee shall repay a pro-rated portion of the direct tuition and certification fees (excluding salary, travel, and internal training costs), calculated as the remaining months of the twelve-month period divided by twelve. No repayment shall be required if the Employee is terminated by the Company for any reason, resigns due to a material adverse change in working conditions, or if the training is required by the Company for the Employee''s current role.', 'The CFPB issued a report in 2023 identifying TRAPs as a form of employer-driven debt that may violate consumer financial protection laws. Several state attorneys general have challenged TRAPs. California Labor Code section 2802 requires employers to bear the cost of necessary training. The FTC''s 2024 Non-Compete Rule commentary identified TRAPs as de facto non-competes. UK law treats penalty clauses as unenforceable if disproportionate to the employer''s legitimate interest (Cavendish Square Holding BV v Talal El Makdessi [2015] UKSC 67). Restatement (Second) of Contracts section 356 prohibits penalties disguised as liquidated damages.', '[0.005831921,0.04117206,-0.058052517,0.008361737,-0.007634772,0.039412007,-0.009760337,0.002600397,-0.053398907,-0.001465979,-0.006117503,-0.006244785,0.005229303,-0.039020255,0.049871027,0.025303984,0.002121117,0.023613567,0.042422563,0.01831458,0.013579569,0.025053011,0.014679141,-0.008063124,-0.013382231,-0.015181897,-0.003037312,0.050378986,-0.029441586,0.03162849,0.04461801,-0.009217526,-0.004284555,-0.013518801,0.028725868,0.01600224,0.00361002,-0.006292485,0.047740832,0.021498084,-0.011890636,0.039897114,0.020600565,-0.004855439,-0.027309876,0.005393769,0.07485099,0.05912111,0.005326609,-0.007910197,0.014934253,-0.040545087,-0.03211411,0.005473663,0.009216622,-0.008469071,-0.025954321,0.03243285,-0.00802615,0.035843503,-0.03241567,0.005744534,-0.010246671,0.011462971,-0.029869221,-0.022654234,0.041898586,0.006971105,-0.017146517,0.021356562,0.026562927,0.04337389,-0.005137607,0.03912254,-0.017944211,0.050606772,-0.006856264,0.021598421,0.02393856,0.01807832,0.002292484,0.000699793,0.018321985,-0.012541639,-0.049481474,-0.034160636,-0.02395613,-0.005909412,0.009282932,0.028236795,-0.02079428,0.009385878,0.06698671,0.02429837,-0.025966275,0.045855768,0.001082606,-0.004188334,-0.010680961,0.009482702,-0.053228404,0.003304394,0.005520497,0.016931811,-0.009632085,-0.032924064,-0.021585649,0.001976235,0.019594047,-0.033869814,0.029458828,-0.008166711,0.022952706