INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4b6c7d8-9e0f-4a1b-ac4d-5e6f7a8b9c0d', 'In the event the Employee voluntarily terminates employment or is terminated for Cause within twelve (12) months of the Employee''s relocation date, the Employee shall repay the Company one hundred percent (100%) of all relocation benefits provided, including moving costs, temporary housing, travel, real estate transaction costs, and any relocation bonus or allowance. The Company shall be entitled to deduct such amounts from the Employee''s final paycheck, accrued paid time off payout, or any other amounts owed to the Employee.', 'benefits_clawback', '["employment"]'::jsonb, 'yellow', 'This clawback provision requires full repayment of all relocation costs if you leave within a year, with no proration. The company can also deduct these amounts directly from your final paycheck and PTO payout, which in many states is illegal without your written authorization at the time of deduction. If you relocated your family across the country for this job and it does not work out, you could owe tens of thousands of dollars while also needing to fund another move -- and you may not even receive your final pay.', 'If the Employee voluntarily resigns (other than for Good Reason) within twelve (12) months of the relocation date, the Employee shall repay a pro-rated portion of the direct moving and temporary housing costs (excluding real estate transaction costs, which shall not be subject to repayment) based on the number of full months remaining in the twelve-month period. No repayment shall be required if the Company terminates the Employee for any reason or if the Employee resigns due to a material change in role, compensation, or work location. Repayment shall be made in equal monthly installments over six (6) months and shall not be deducted from the Employee''s final paycheck without separate written authorization.', 'Many US states restrict deductions from final paychecks. California Labor Code section 221 prohibits deduction of wages already earned. New York Labor Law section 193 limits permissible wage deductions. Illinois Wage Payment and Collection Act (820 ILCS 115/9) restricts deductions to those authorized in writing at the time. UK Employment Rights Act 1996 section 13 prohibits unauthorized deductions from wages. Restatement (Second) of Contracts section 356 applies reasonableness test to repayment obligations.', '[0.025297718,0.036486935,-0.038001288,0.01696172,-0.012602675,0.007075161,-0.01357228,-0.007679991,-0.0291638,-0.027985847,-0.008769263,0.014480781,-0.020711029,-0.04498944,0.035971478,-0.000863556,-0.017627459,0.0379613,-0.002645108,0.025696585,0.017451886,0.000216332,0.01093343,-0.002708939,0.001199689,-0.0397001,-0.027810479,0.03373738,-0.025667414,-0.009539767,0.035698533,0.017407116,-0.007597475,-0.00056862,-0.03320334,-0.026281342,0.05429334,-0.036837384,0.009346844,0.006050939,-0.028847955,0.034103747,0.04111201,0.00570629,-0.005137591,0.005329451,0.031472884,0.04549584,0.036905333,0.01520166,4.3934e-05,-0.06767998,-0.023411272,0.040236846,0.021976944,0.007610551,-0.014515976,0.029107321,0.019777665,-0.028050447,0.002339619,0.031104619,0.028707974,0.020265965,0.011383312,-0.007741908,0.018930672,0.027682647,-0.009024241,-0.002729356,0.03568862,0.05003175,-0.04345041,0.006241552,0.00608281,0.04184629,0.005916388,-0.03474738,0.009569595,0.036123898,-0.00202312,-0.018272895,0.006339108,-0.010321677,-0.037775215,-0.02957003,0.012060575,-0.022042215,0.029787173,0.018935591,-0.042420577,-0.006990171,0.037129875,-0.031520568,-0.020616816,0.041830365,0.005338036,-0.01858615,-0.04224523,0.030766021,-0.031490404,-0.009082704,0.027829826,0.013476638,0.018040812,-0.020500256,-0.009278326,0.003584961,0.02601988,0.000981716,0.016118862,-0.06358362,0.019313581,0.005576869,0.018882344,-0.041339554,0.019171428,-0.038871