INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3d0e1f2-a3b4-4c5d-ae7f-9a0b1c2d3e4f', 'Nothing in this Agreement shall be construed to create a right or obligation for the Receiving Party to disclose Confidential Information to any governmental, regulatory, or law enforcement authority, and the Receiving Party waives any right to report potential violations of law to such authorities using the Disclosing Party''s Confidential Information.', 'carve_outs', '["nda"]'::jsonb, 'red', 'This is an illegal gag clause. It tries to stop you from reporting crimes, fraud, or other illegal activity to law enforcement or regulators. US federal law (the Defend Trade Secrets Act) explicitly gives you immunity for disclosing trade secrets to the government for the purpose of reporting a suspected violation of law. This clause is not just unenforceable — it''s actually illegal to include in an NDA without the required DTSA whistleblower notice.', 'Nothing in this Agreement shall prohibit or restrict the Receiving Party from (a) reporting possible violations of federal, state, or local law or regulation to any governmental agency or entity, (b) making disclosures protected under the whistleblower provisions of applicable law, or (c) cooperating with any governmental investigation. The Receiving Party is hereby notified that, pursuant to 18 U.S.C. Section 1833(b), an individual may not be held criminally or civilly liable under any federal or state trade secret law for disclosure of a trade secret made in confidence to a government official or attorney solely for the purpose of reporting or investigating a suspected violation of law.', 'US: DTSA 18 U.S.C. Section 1833(b) — mandatory whistleblower immunity notice required in all NDAs. Employers who fail to include this notice cannot recover exemplary damages or attorney''s fees in trade secret claims. Dodd-Frank Act Section 922 protects SEC whistleblowers. EU: Trade Secrets Directive 2016/943 Article 5(b) — disclosure for revealing misconduct is permitted. Directive (EU) 2019/1937 (Whistleblower Protection Directive). UK: Public Interest Disclosure Act 1998 — NDA terms cannot override statutory whistleblower protections.', '[-0.009447446,-0.064607404,-0.010513892,0.009241487,-0.048250537,0.007685017,-0.026747847,0.037416976,-0.0372281,0.05090336,-0.026189052,-0.02859152,-0.05161047,-0.001731672,-0.059036218,0.030776987,-0.047769953,0.035682045,-0.04117477,0.041004565,-0.07828957,-0.030400569,-0.040013477,-0.004502087,0.003630513,-0.053798325,0.03588716,0.003494126,-0.022691052,-0.011685102,-0.030758735,-0.005339081,0.010756588,0.012408744,-0.011239551,0.031703476,0.02223793,-0.03273522,0.002111768,0.002902305,-0.005552985,0.028813032,-0.031887833,-0.026985379,0.022863021,-0.02072313,-0.016375018,0.08273712,-0.01797132,0.019259714,-0.000485703,-0.006875983,0.039169226,0.010376951,0.0546516,0.003716719,0.007385558,-0.004901801,0.020807847,0.045115873,-0.003204584,-0.0420615,-0.026243238,-0.014326892,0.005599374,0.041944355,-0.016957525,0.013071082,0.025516462,-0.005422485,0.078301646,0.027365746,-0.001899033,0.047386076,0.009771721,0.007613217,-0.032538388,0.028140057,-0.006485403,-0.01838759,-0.013433135,-0.048158377,-0.012256269,-0.029911844,-0.027367124,-0.004780971,0.028578715,0.012969554,0.025307875,-0.026568906,-0.019764759,-0.015224472,0.059030678,-0.049177866,0.007691748,-0.027157063,-0.018413715,0.012873641,0.006013757,-0.000451897,-0.036477394,0.02624399,0.016404996,0.002813078,0.020276163,0.016507313,-0.019986669,0.015388985,-0.05487124,-0.026269335,-0.065165654,0.039459772,0.045288827,0.044014636,0.04427431,-0.041628014,0.017790115,0.047361415,0.023747114,-0.010034759,-0.038991384,-0.052214336,-0.023196377,-0.00098589,0.01382433,-0.04419775,-0.032178234,-0.03244451,0.04677571,0.000165089,0.003329129,0.021890735,0.000546722,0.03801784,-0.01143036,0.018022995,0.008899