INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3e1f2a3-b4c5-4d6e-bf8a-0b1c2d3e4f5a', 'The Receiving Party shall not be entitled to assert as a defense to any breach of this Agreement that the Confidential Information was independently developed by the Receiving Party or was already known to the Receiving Party prior to disclosure, unless such independent development or prior knowledge is evidenced by written records created and dated prior to the Effective Date and certified by a licensed notary public.', 'carve_outs', '["nda"]'::jsonb, 'yellow', 'While a prior knowledge defense is technically allowed here, the notarized written records requirement makes it nearly impossible to use in practice. Most people don''t notarize their internal notes, emails, or work product. This effectively eliminates the standard NDA carve-out for independently developed or previously known information by setting an unrealistically high bar for proof.', 'Confidential Information shall not include information that the Receiving Party can demonstrate by reasonable evidence, including but not limited to written or electronic records, emails, documents, or witness testimony, was (a) already in the Receiving Party''s possession prior to disclosure by the Disclosing Party, or (b) independently developed by the Receiving Party without use of or reference to the Disclosing Party''s Confidential Information.', 'US: Under UTSA and DTSA, independent development and prior knowledge are fundamental defenses. Imposing unreasonable evidentiary burdens may be unconscionable under Restatement (Second) of Contracts Section 208. EU: Trade Secrets Directive 2016/943 Article 3(1)(a)-(b) — independent discovery and observation are lawful acquisition methods without special evidentiary requirements. UK: Trade Secrets Regulations 2018 reg. 3 — no special evidentiary standard is required f