INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3f2a3b4-c5d6-4e7f-8a9b-1c2d3e4f5a6b', 'The Receiving Party acknowledges and agrees that no public domain or general knowledge exception shall apply to Confidential Information that was compiled, organized, or aggregated by the Disclosing Party, even if the individual components of such Confidential Information are publicly available.', 'carve_outs', '["nda"]'::jsonb, 'yellow', 'This clause claims that even if every individual piece of information is publicly available, the way the disclosing party organized or combined those pieces is still confidential. While there is some legal support for protecting unique compilations (like a curated customer database), this clause is so broadly written it could cover something as simple as a spreadsheet of publicly available data. It effectively eliminates the public domain exception for any information the discloser has assembled.', 'Confidential Information may include compilations of otherwise publicly available information, provided that the specific selection, arrangement, or coordination of such information constitutes a trade secret under applicable law and derives independent economic value from not being generally known in that particular compiled form.', 'US: Compilations can qualify as trade secrets under UTSA if their specific arrangement adds value — but individual publicly known components remain unprotected. See Restatement (Third) of Unfair Competition Section 39 comment f. EU: Trade Secrets Directive 2016/943 Article 2(1) — the compilation itself must meet the trade secret definition. UK: Coco v. A.N. Clark (Engineers) Ltd — the compilation must have the necessary quality of confidence.', '[0.04647352,0.024498925,-0.03283807,0.05519273,0.003765689,-0.00434327,-0.014217354,0.02222504,0.009110114,0.026100835,-0.06685199,-0.045441683,-0.02689057