INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4a9b0c1-2d3e-4f4a-9b7c-8d9e0f1a2b3c', 'The Employee''s base salary shall be reviewed annually but the Company reserves the right, in its sole discretion, to reduce the Employee''s base salary by up to twenty percent (20%) at any time based on individual performance, changes in market conditions, Company financial performance, or restructuring needs. The Employee''s continued employment following any salary reduction shall constitute acceptance of the revised compensation.', 'compensation', '["employment"]'::jsonb, 'red', 'This clause allows the company to cut your pay by up to 20% at any time, for vague reasons like ''market conditions,'' and deems your continued employment as acceptance. In practice, this means you face a choice between taking a massive pay cut or quitting -- and if you quit, you may trigger repayment obligations or lose unvested benefits. This one-sided discretion to reduce compensation is considered a fundamental breach of contract in many jurisdictions and can constitute constructive dismissal.', 'The Employee''s base salary shall not be reduced below the amount stated in this Agreement without the Employee''s prior written consent. If the Company proposes a salary reduction exceeding five percent (5%) due to a company-wide restructuring affecting all similarly situated employees, the Employee shall have thirty (30) days to accept or reject the proposal. If the Employee rejects the reduction, either party may terminate the agreement on sixty (60) days'' notice with full severance as set forth in Section X.', 'UK Employment Rights Act 1996 treats unilateral pay reductions as a fundamental breach entitling the employee to claim constructive dismissal. In Cantor Fitzgerald v Callaghan [1999] ICR 639, the UK Court of Appeal held that discretionary pay clauses must still be exercised in good faith. US courts in cases like Torosyan v Boehringer Ingelheim Pharmaceuticals (1999, Connecticut) found unilateral pay reductions may breach implied contract terms. EU Directive 2019/1152 requires clear, predictable working conditions including compensation.', '[-0.06261315,0.082232386,-0.002881412,-0.006872111,-0.001397614,0.04821422,-0.017561581,-0.03295731,0.005800371,0.055981994,-0.04719125,-0.00047659,-0.04875427,-0.031629857,0.008442518,-0.012342507,0.010297147,0.025648529,0.032634463,0.033322636,0.020166041,0.029484112,0.014617302,0.03954873,0.003234102,0.022342395,0.003344277,0.015016811,-0.002993721,-0.015427683,0.04239023,0.035251334,-0.018202545,0.019407885,0.04366016,-0.018737659,0.065762326,-0.003279264,-0.029511461,0.007256848,-0.010042168,0.048272565,0.055529814,0.033178687,-0.001403104,-0.016737357,-0.035796367,0.000509789,-0.05768028,-0.005939398,0.023586003,-0.012497675,-0.06435578,0.022084506,0.024226232,-0.008221169,0.013173374,0.034858085,0.02202568,0.009927763,0.0550437,-0.012026665,0.004864956,0.047642294,-0.017884018,-0.044868477,-0.011046317,-0.025658356,-0.03583906,0.03319167,0.04180929,0.041243732,0.017902305,0.0591824,0.010197426,0.019260837,-0.005187011,0.018063428,-0.014277265,0.044496823,-0.032864083,-0.002025818,0.026539305,0.038390584,-0.02116876,-0.022797452,-0.015774421,-0.031612374,0.015636073,0.05274192,-0.015683543,0.01960648,-0.019022565,0.026877787,0.069869,0.046244025,-0.005444082,0.007334678,0.055657033,0.018084057,-0.042674504,-0.003778411,-0.017051648,0.02173564,0.024586143,-0.05218347,-0.016044743,0.016110161,-0.01659443,0.009086116,0.001714005,-0.051106304,0.033190772,-0.028952848,-0.019582743,-0.025939766,-0.039028678,-0.06372899,0.019991513,0.036091764,-0.038510326,0.027903475,0.007984824,0.008320226,-0.008014674,0.023860924,0.045708925,-0.001198285,0.009229769,0.022186708,-0.034594808,0.01276616,-0.015854713,-0.005999613,-0.022172395,0.061483063,0.045289442,-0.024731133,-0.030041287,0.008247407,0.058020107