INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4b0c1d2-3e4f-4a5b-ac8d-9e0f1a2b3c4d', 'The Employee acknowledges that their position is classified as exempt from overtime under the Fair Labor Standards Act and applicable state law. The Employee agrees to work such hours as are necessary to fulfill the duties and responsibilities of the position, which may regularly exceed forty (40) hours per week, without additional compensation, overtime pay, or compensatory time off.', 'compensation', '["employment"]'::jsonb, 'yellow', 'Whether you are actually ''exempt'' from overtime depends on your specific job duties and salary level, not on what the contract says. Many employers misclassify workers as exempt to avoid paying overtime. If your actual duties do not meet the legal tests for exemption (executive, administrative, professional, or outside sales), this clause is void and the company owes you overtime. The clause also tries to make you agree to unlimited hours with no extra pay, which could violate working time regulations.', 'The Employee''s position is classified as [exempt/non-exempt] under the Fair Labor Standards Act based on the duties described in Schedule A. If the Employee''s duties materially change such that the exemption classification may no longer apply, the Company shall promptly review the classification. The Employee''s standard working hours are forty (40) hours per week. Any hours worked in excess of forty-five (45) hours per week on a sustained basis shall be reviewed by Human Resources, and the Company shall provide additional compensatory time off or supplemental compensation as appropriate.', 'FLSA section 13(a)(1) exemptions require meeting specific salary and duties tests; misclassification exposes employers to back-pay liability. US Department of Labor 2024 final rule raised the salary threshold for FLSA white-collar exemptions. EU Working Time Directive 2003/88/EC Article 6 caps average working hours at 48 per week. UK Working Time Regulations 1998 implement the EU directive and require opt-in for hours exceeding 48 per week. Misclassification cases: Encino Motorcars LLC v. Navarro (2018) (Supreme Court on exemption interpretation).', '[-0.03782629,-0.02063128,-0.026422292,0.01908721,-0.060495984,0.004268344,0.01926445,0.017472345,0.012853983,0.003200799,-0.0162447,-0.013100152,-0.018881287,-0.009227761,-0.007486589,-0.04290697,0.002449571,0.006033676,-0.05020774,0.007695378,0.005109636,0.02556378,-0.055009343,0.027323432,0.01701405,-0.06795734,-0.060762573,0.028225407,-0.042530842,0.005877529,-0.014440303,-0.01166114,-0.04252208,0.02200113,-0.009840818,0.013005774,0.021858102,-0.0076245,0.031492412,0.003178517,-0.018214352,0.009622931,0.050570894,-0.014719697,-0.014575426,0.00057996,0.05289121,0.027256949,-0.025740251,0.039503653,0.032127,0.04752476,-0.020097384,-0.000904598,-0.004149262,-0.021902524,-0.013010269,0.07617153,0.04062329,-0.06797627,0.005084268,-0.012295319,0.049885582,0.039437115,0.000549711,-0.03383005,-0.045158677,-0.042232033,-0.021551162,-0.027626041,0.05186441,-0.032338567,0.019343114,0.051920883,0.015903749,-0.042022906,-0.03751909,-0.029707752,0.0491051,0.023915958,-0.040083762,-0.033636052,-0.017797839,-0.04021666,-0.006931021,-0.005480712,-0.001286345,-0.039998956,0.04764073,0.055337697,-0.006546469,-0.024207354,-0.03891789,-0.006466321,0.05077339,0.019019566,0.032907825,-0.027415046,-0.030468581,0.060457367,-0.062497217,-0.007800816,-0.048395548,-0.009999325,-0.012733203,-0.004929638,0.01771138,-0.022525469,-0.018372018,0.035685025,-0.019717794,-0.07615132,0.040822126,0.022233836,0.017434442,-0.02617418,-0.007805118,0.040863384,0.025421685,-0.003022419,0.05370343,-0.000922783,0.007005628,0.01843225,0.039098926,0.000899546,-0.043627825,0.018767053,-0.004900146,0.05411598,-0.006344112,0.03488371,-0.021503946,-0.01626044,0.02606136,0.012992191,0.01441338,-0