INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4c1d2e3-4f5a-4b6c-8d9e-0f1a2b3c4d5e', 'Any bonus payment is entirely discretionary and shall be determined by the Company in its sole discretion based on such factors as the Company deems relevant. To be eligible to receive any bonus, the Employee must remain continuously employed by the Company through the date on which the bonus is actually paid. The Employee acknowledges that no bonus shall be considered ''earned'' until it has been paid. In the event the Employee''s employment terminates for any reason prior to the bonus payment date, no bonus or pro-rated portion thereof shall be payable.', 'compensation', '["employment"]'::jsonb, 'yellow', 'This clause ensures you only get a bonus if you are still employed on the payment date, not when you actually did the work to earn it. Companies often pay annual bonuses in March for the previous year''s performance, meaning if you leave in January, you lose an entire year''s bonus that you already earned. The ''not earned until paid'' language tries to redefine when compensation is earned, allowing the company to fire you right before the payout and owe you nothing.', 'The Employee shall be eligible for an annual performance bonus with a target of [X]% of base salary, based on achievement of performance objectives established in writing at the beginning of each fiscal year. A bonus shall be considered earned upon the completion of the applicable performance period. If the Employee''s employment terminates after the end of a completed performance period but before the bonus payment date, the earned bonus shall be paid on the regular bonus payment date. If employment terminates during a performance period, the Employee shall receive a pro-rated bonus based on actual performance to the termination date.', 'UK case law in Commerzbank AG v Keen [2007] ICR 623 addressed when discretionary bonuses become contractual entitlements. The UK Equality Act 2010 prohibits discriminatory exercise of bonus discretion. Several US states, including New York (NY Labor Law section 191) and Illinois (820 ILCS 115), require payment of earned compensation upon termination regardless of continued employment requirements. Restatement (Second) of Contracts section 205 duty of good faith constrains discretionary bonus decisions.', '[-0.058840808,0.033610668,0.023788054,0.028540943,-0.028108956,0.049095098,-0.032456484,-0.004292489,-0.019052632,-0.016740136,-0.004008208,-0.035685558,-0.032780055,-0.000994582,0.07984058,0.010222503,-0.025022501,0.027889641,0.005183188,0.0309049,0.009305108,0.084287345,0.022194974,0.011050226,0.003961314,-0.021799376,-0.009843135,0.002490837,-0.01078906,0.018233297,0.051067945,-0.003879876,-0.032751977,-0.009242672,0.02879045,0.033713866,0.05017986,-0.057563443,0.011188488,0.01579577,0.06851247,0.023158712,0.001851157,0.038642798,-0.002715968,-0.08471304,-0.0080633,0.020973124,-0.018059064,-0.006934705,0.004549148,-0.041753445,-0.054344565,0.001121018,0.025073312,0.024145322,-0.010786589,0.043374255,0.041445456,-0.043970972,0.038189627,0.015095948,0.015165992,0.020669637,-0.022114014,-0.02435458,0.01073761,-0.048659384,0.034657262,0.002747298,0.0479844,0.025631977,0.01871374,0.031881135,0.050547525,0.000146444,-0.029568281,0.07841969,-0.022805175,0.024252491,-0.05019088,-0.00828702,-0.011414181,0.038227394,-0.033429425,-0.011914918,-0.007566791,-0.001889094,-0.019018497,0.061580773,0.02918758,-0.055282995,0.017643996,-0.012433105,0.037247844,0.038123492,-0.015766611,-0.02530428,0.011356963,-0.012822235,-0.024602419,-0.015849035,0.003666129,0.027730219,-0.018700883,0.005538378,0.05125876,0.006105043,0.004998994,0.003471157,0.019110959,-0.05212027,0.031446036,0.021478383,0.016819568,-0.03856008,0.009513212,-0.012366525,0.010693422,0.01114404,0.003497981,-0.011967957,0.01221172,0.02066519,-0.007088247,0.03805295,0.