INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2828384-8586-4788-898a-8b8c8d8e8f90', 'Contractor shall not use any aspect of the Work Product, Client''s name, Client''s logo, or a description of the Services performed in any portfolio, case study, marketing material, website, or social media without the prior written consent of Client, which may be withheld in Client''s sole discretion.', 'confidentiality', '["freelance"]'::jsonb, 'yellow', 'This prevents you from showing your work in your portfolio or even mentioning you worked with the client -- unless they give permission, which they can refuse for any reason. For freelancers, a portfolio is essential for getting future work. Doing invisible work that you can never reference seriously limits your career growth.', 'Contractor may include a general description of the Services and non-confidential aspects of the Work Product in Contractor''s portfolio and marketing materials after project completion. Use of Client''s name and logo in portfolio materials requires Client''s consent, which shall not be unreasonably withheld. Client shall respond to portfolio use requests within ten (10) business days.', 'While portfolio restrictions are generally enforceable, unreasonable refusal may violate the duty of good faith under Restatement (Second) of Contracts Section 205. IPSE (UK) advises freelancers to negotiate portfolio rights as standard. In the creative industries, portfolio rights are considered a key term by the Association of Independent Professionals and the Self-Employed.', '[0.001434481,-0.013596098,-0.03482868,0.004628427,-0.061914712,-0.015536397,-0.00968622,-0.002681438,-0.051970452,0.011018275,-0.041059125,0.018304784,-0.051523946,-0.040385123,0.04469075,-0.000860536,-0.030393679,-0.06460022,-0.009149466,0.011972352,-0.09092455,-0.011670851,-0.07452793,-0.00415487,0.03935043,-0.03886792