INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2727374-7576-4778-897a-7b7c7d7e7f80', 'Contractor shall keep strictly confidential all information, whether written, oral, or electronic, disclosed by or on behalf of Client during the term of this Agreement and in perpetuity thereafter. Confidential Information shall include, without limitation, all business plans, client lists, financial data, technical information, processes, strategies, and any other information of any nature whatsoever.', 'confidentiality', '["freelance"]'::jsonb, 'yellow', 'This NDA has no expiration date (''in perpetuity''), no exceptions for publicly available information, and the definition of ''confidential'' is so broad (''any information of any nature whatsoever'') that it covers everything. Even information you already knew, or that becomes public, would technically be covered. This could prevent you from discussing your work experience.', 'Contractor shall keep confidential all proprietary information specifically designated as confidential by Client in writing for a period of two (2) years following termination. Confidential Information does not include information that: (a) is or becomes publicly available through no fault of Contractor; (b) was known to Contractor prior to disclosure; (c) is independently developed by Contractor; or (d) is disclosed pursuant to a legal obligation.', 'Perpetual NDAs without exclusions may be unenforceable as unreasonable restraints on trade under Restatement (Second) of Contracts Section 188. UK courts have held that confidentiality clauses must be reasonable in scope and duration (Faccenda Chicken Ltd v Fowler [1987]). EU Directive 93/13/EEC Article 3(1) assesses significant imbalance; a perpetual blanket NDA creates such imbalance.', '[-0.043709643,-0.017799586,-0.020198602,-0.00088145,-0.07774789,0.016181974,-0.030750288,0.04038