INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2929394-9596-4798-899a-9b9c9d9e9fa0', 'The Confidential Information obligations herein shall survive termination of this Agreement indefinitely. Contractor shall, upon termination or upon Client''s request, immediately return or destroy all materials containing Confidential Information and provide a signed certification of destruction. Contractor further agrees not to retain any copies, summaries, notes, or extracts of Confidential Information in any form.', 'confidentiality', '["freelance"]'::jsonb, 'yellow', 'The indefinite survival combined with the requirement to destroy all notes and extracts is excessive. You''d need to purge your own working notes, email records, and any learning you documented. The ''certification of destruction'' creates legal liability if you miss any copy on a backup drive or cloud sync.', 'Confidential Information obligations shall survive for two (2) years following termination. Upon termination, Contractor shall return or destroy Client''s proprietary materials and confirm in writing. Contractor may retain copies of correspondence and personal working notes, subject to the ongoing confidentiality obligations.', 'Indefinite confidentiality obligations may be unreasonable restraints on trade under Restatement (Second) of Contracts Section 188. The EU Trade Secrets Directive 2016/943 Article 4 defines unlawful use but does not support indefinite obligations. UK courts assess reasonableness of duration in non-disclosure agreements (Vestergaard Frandsen v Bestnet Europe [2013]).', '[-0.009599011,-0.003532759,-0.031853374,0.027141439,-0.06788209,0.04095691,-0.033156954,0.004771101,-0.09294985,0.04713934,-0.059024565,-0.01675824,-0.0360932,-0.03876659,-0.021089138,-0.03595083,-0.005694284,-0.05139672,0.025305208,-0.012733307,-0.003452114,-0.002272865,-0.006224313,-0.0032442