INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5b4c5d6-e7f8-4a9b-80d1-e2f3a4b5c6d7', 'By submitting feedback, suggestions, ideas, enhancement requests, recommendations, or other communications regarding the Services (''Feedback''), you assign to the Company all right, title, and interest in and to the Feedback, including all intellectual property rights therein. You agree that the Company shall own such Feedback and is entitled to use and disseminate the Feedback for any purpose, commercial or otherwise, without acknowledgment, compensation, or other obligation to you.', 'content_ownership', '["tos"]'::jsonb, 'yellow', 'This transfers ownership of any idea or suggestion you share with the company. If you suggest a feature that becomes worth millions, you get nothing. The broad definition of ''Feedback'' could include casual comments in support tickets or forum posts. You permanently lose all rights to your ideas the moment you share them.', 'By submitting Feedback, you grant the Company a non-exclusive, royalty-free license to use, incorporate, and modify the Feedback to improve the Services. You retain ownership of your Feedback. If we incorporate your Feedback in a way that generates significant commercial value, we will make reasonable efforts to attribute and acknowledge your contribution.', 'EU Unfair Contract Terms Directive Annex 1(b) flags terms inappropriately restricting consumer rights. Assignment of IP rights in consumer contracts may be challenged under UK CRA 2015 Section 62 fairness test. Under US copyright law (17 USC Section 201), assignments must be in writing, but clicking ''I agree'' to ToS may satisfy this requirement.', '[-0.050077826,0.009860625,0.022612203,-0.041482963,-0.012789808,0.003067279,-0.011304463,-0.041583754,0.037323564,0.05857477,-0.028423412,0.003716133,-0.002937551,-0.016566008,0.023289137,-0.01844388,0.05