INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5f8a9b0-c1d2-4e3f-a4b5-c6d7e8f9a0b1', 'You grant us the right to use your name, likeness, company name, logo, and trademarks in our marketing materials, customer lists, case studies, and promotional content, including on our website and social media channels. You may revoke this right by providing written notice, but such revocation shall only apply to future use and shall not require us to remove or alter materials already published or in production.', 'content_ownership', '["tos"]'::jsonb, 'yellow', 'By agreeing to the Terms, you unknowingly consent to the company using your name and brand as a marketing endorsement. Most users never notice this buried in ToS text. The revocation provision is weak because anything already published stays forever, potentially implying endorsement you never intended.', 'We will not use your name, likeness, or trademarks for marketing purposes without obtaining your separate, explicit written consent for each specific use. You may withdraw consent at any time, and we will remove such materials within 30 days of receiving your request.', 'GDPR Article 6(1)(a) requires freely given, specific consent for processing, which bundling marketing rights into ToS undermines. Many US states have publicity rights statutes (e.g., California Civil Code Section 3344). UK GDPR similarly requires explicit consent for marketing use of personal data.', '[-0.02379769,0.01219645,-0.029086836,0.005124985,-0.04744174,-0.009752234,-0.001167178,-0.030685596,-0.063560635,-0.002353539,-0.042003937,0.029322442,-0.0254313,-0.02092291,0.019996725,0.019049795,0.018860454,-0.024990402,-0.029266182,0.054671887,-0.09289528,0.01233238,-0.049126793,0.03550901,0.020397974,-0.020114403,0.006862537,-0.001372188,0.03831951,-0.01178495,0.024284163,0.021747068,0.003062095,-0.006855676,-0.000791706,-0.03352