INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5f4a5b6-c7d8-4e9f-a0b1-c2d3e4f5a6b7', 'You agree that we may retain your personal data for as long as we deem necessary for our business purposes, even after you have terminated your account. We may retain and use your information as necessary to comply with our legal obligations, resolve disputes, and enforce our agreements. You acknowledge that deletion of your account does not guarantee deletion of all data we hold about you.', 'data_usage', '["tos"]'::jsonb, 'red', 'This claims the right to keep your personal data indefinitely, even after you leave the service. ''As long as we deem necessary for business purposes'' is completely open-ended. This directly conflicts with your right to have data deleted (the ''right to be forgotten''). The final sentence effectively says that deleting your account may be meaningless for your privacy.', 'Upon termination of your account, we will delete your personal data within 90 days, except where retention is required by specific legal obligations (e.g., tax records for the statutory period). We will inform you of any data we are legally required to retain, the reason for retention, and the expected deletion date. You may exercise your right to erasure at any time by contacting us.', 'GDPR Article 17 establishes the right to erasure (''right to be forgotten''). GDPR Article 5(1)(e) requires storage limitation: data kept only as long as necessary for the purpose. CCPA Section 1798.105 gives consumers the right to request deletion of personal information. UK GDPR mirrors the EU right to erasure provisions.', '[-0.044047233,-0.051767174,-0.023904799,-0.00956115,-0.028748482,0.020607669,0.005128205,0.0593003,-0.001906514,0.015458783,-0.018516859,-0.026038243,-0.011358195,-0.040722568,-0.039838254,-0.008302213,0.004665299,0.03944983,-0.017783916,0.02738432,-0.073125