INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5a9b0c1-d2e3-4f4a-b5c6-d7e8f9a0b1c2', 'You agree that we may collect information from your device, including but not limited to device identifiers, operating system, browser type, IP address, GPS location data, Wi-Fi connection information, accelerometer data, and information from cookies, pixels, web beacons, and similar technologies. We may combine this information with data obtained from third-party sources, including data brokers, advertising partners, and publicly available databases, to create enhanced profiles for the purposes of service personalization and targeted advertising.', 'data_usage', '["tos"]'::jsonb, 'red', 'This authorizes invasive device surveillance including GPS tracking, Wi-Fi monitoring, and even motion sensor data. Combining this with data bought from third-party brokers creates a detailed profile of your movements, habits, and identity far beyond what any reasonable user would expect. This goes well beyond what''s needed to provide the service.', 'We collect device information necessary for security and service functionality, such as device type and operating system version. We collect location data only when you explicitly enable location features, and you may disable this at any time. We do not purchase personal data from third-party data brokers. Our Privacy Policy describes exactly what data we collect and how it is used.', 'GDPR Article 5(1)(c) mandates data minimization: only collecting data adequate, relevant, and limited to what is necessary. ePrivacy Directive (2002/58/EC) Article 5(3) requires informed consent for storing or accessing device information (cookies, tracking). CCPA/CPRA gives consumers the right to know and opt out of cross-context behavioral advertising. EU DMA Article 5(2) restricts gatekeepers from combining personal data across services without consent.', '[0.017987885,-0.04365101,0.026045943,0.010584691,-0.015494031,0.001165703,-0.037941623,0.061931264,0.03203189,0.02102324,-0.029393407,-0.014901609,0.027906265,-0.005948623,0.055472907,-0.0251639,-0.016091716,0.025257843,0.006265228,0.004545749,-0.014470087,-0.011081564,0.01851657,0.003977211,0.012701824,-0.044120915,0.032750223,0.04487189,0.022431629,0.05145791,-0.005347834,0.045134176,0.024131602,-0.014397464,0.016357495,0.032761794,0.04115619,0.007031369,0.018854832,0.026634386,-0.016274678,-0.042079773,-0.01111712,0.03138731,0.04894707,-0.019476116,-0.008414062,0.06510172,-0.022870757,0.023786169,0.014528976,-0.030089432,-0.009824382,0.03431998,0.001601483,0.012725003,0.05046082,0.0311129,-2.665e-05,0.08573876,0.02000148,-0.03109732,0.016711747,-0.01777548,-0.015946262,-0.008561702,0.048854284,0.017499728,0.048403457,-0.0487466,0.026344495,0.009322564,-0.046747897,0.038715906,-0.010611759,0.006136671,0.00575279,0.033095933,-0.014938351,-0.021310318,-0.037090465,0.019912682,-0.020159662,-0.005818297,-0.049316306,-0.020737946,-0.00651435,0.010792184,0.017501203,0.035225596,-0.031277064,0.00164513,0.051639993,-0.013389425,0.009720293,-0.028604928,0.020691806,-0.033990547,-0.009073061,-0.000896525,0.030994497,-0.036611423,-0.019589014,-0.035637006,0.016122049,0.000437144,0.002461805,0.016903378,-0.07214544,0.07553068,-0.067607865,0.021284262,-0.001377646,0.0871143,-0.009422739,0.030408463,-0.03321196,0.013299566,0.005795341,-0.031809106,-0.0567992,-0.013977993,-0.001514639,-0.035889708,0.004057537,0.038110506,-0.01893052,0.012843554,0.068168014,0.050480053,0.011020775,-0.011019984,0.032376483,-0.030282587,0.014024368,-0.01567607,-0.015353466,0.023600867,-0.016684815,-0.012972132,-0.03722348,-0.002085288,-0.005016594,0.032001093,0.06468294,-0.023344567,-0.064316414,-0.020386638,-0.023854664,0.009942062,-0.021225968,-0.004616681,0.006299545,-0.031991076,-0.035999116,-0.01557355,0.00539244,-0.01810667,0.005449762,-0.046797436,-0.009797034,0.010608855,0.016