INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5f2a3b4-c5d6-4e7f-a8b9-c0d1e2f3a4b5', 'We may share your personal data with third-party advertising networks, data brokers, analytics providers, and business partners for the purpose of delivering targeted advertising, conducting market research, and other commercial purposes. By using the Services, you consent to the sale of your personal information as described in this section. You may opt out of the sale of your personal information by submitting a written request to our privacy team, which will be processed within ninety (90) business days.', 'data_usage', '["tos"]'::jsonb, 'red', 'This explicitly authorizes selling your personal data to data brokers and advertisers. Burying consent to data sales in the Terms of Service means most users agree without realizing it. The 90-business-day opt-out window (roughly 4.5 months) is unreasonably long, and requiring a written request adds friction that discourages people from exercising their rights.', 'We do not sell your personal information to third parties. We share data with third-party service providers only as necessary to operate the Services, as detailed in our Privacy Policy. You may opt out of personalized advertising at any time through your account settings. Opt-out requests are processed within 15 business days.', 'GDPR Article 7(2) requires consent to be clearly distinguishable and not bundled with other terms. CCPA Section 1798.120 gives consumers the right to opt out of sale of personal information with a clear ''Do Not Sell'' link, and CPRA requires opt-out to be processed within 15 business days. FTC has taken enforcement action against companies with deceptive data-sharing practices.', '[-0.00022989,-0.02009278,-0.049617022,0.008366239,0.015673587,-0.03486194,-0.05026415,0.002348449,0.03714343,0.035001293,-0.014580168,0.013011294,0.02