INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5b8c9d0-e1f2-4a3b-84d5-e6f7a8b9c0d1', 'You acknowledge and agree that we may use, process, and analyze data derived from your use of the Services, including but not limited to usage patterns, search queries, interaction data, and content preferences, for the purpose of developing, training, improving, and enhancing our artificial intelligence and machine learning models and systems. Such derived data and any models trained thereon shall be our exclusive property. This right shall survive termination of your account.', 'data_usage', '["tos"]'::jsonb, 'red', 'This lets the company feed your personal activity, including search queries and content you interact with, into AI training. The company claims permanent ownership of anything their AI learns from your behavior. This continues even after you delete your account, meaning your data effectively becomes permanently embedded in their commercial products with no way to remove it.', 'We may use anonymized, aggregated usage data to improve our Services. We will not use your personal data or content to train machine learning models without your explicit, informed consent, which you may withdraw at any time. If you withdraw consent, we will make commercially reasonable efforts to remove your data''s influence from models not yet deployed. This use of anonymized data is described in detail in our Privacy Policy.', 'GDPR Article 6 requires lawful basis for processing; Article 7 requires freely given, specific, informed consent, which must be withdrawable. GDPR Article 22 gives rights regarding automated decision-making and profiling. EU AI Act may impose additional requirements on training data governance. CCPA/CPRA Section 1798.120 gives consumers the right to opt out of the sale or sharing of personal information.', '[-0.03266726,-0.035910733,0.031426545