INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5b2c3d4-e5f6-4a7b-88d9-e0f1a2b3c4d5', 'We may collect, use, store, and process information about you, including personal data, usage data, device information, location data, browsing history, and content data. We may share this information with our affiliates, subsidiaries, business partners, advertisers, analytics providers, and other third parties as we determine in our sole discretion to be necessary or appropriate for our business purposes.', 'data_usage', '["tos"]'::jsonb, 'red', 'This clause lets the company collect almost every type of personal information and share it with an unlimited, unnamed group of companies. ''Sole discretion'' and ''business purposes'' are so vague they place no real limit on what the company can do with your data. You have no say in who gets your information.', 'We collect personal data as described in our Privacy Policy, limited to what is necessary to provide, maintain, and improve the Services. We share personal data only with specifically identified service providers who are bound by data processing agreements, and only for the purposes described in our Privacy Policy. We will not sell your personal data to third parties. You may request a list of all third parties with whom your data has been shared.', 'GDPR Article 6 requires a lawful basis for processing; ''business purposes'' alone is insufficient. GDPR Article 13(1)(e) requires identifying specific recipients or categories of recipients. GDPR Article 5(1)(b) mandates purpose limitation. CCPA/CPRA gives California consumers the right to know which third parties receive their data and to opt out of data sales.', '[0.007210228,-0.028465074,0.021145869,0.011213642,-0.010065979,0.000165796,-0.038260978,0.028557776,0.037368815,0.02910923,-0.015646553,-0.023665108,0.03355604,0.009116028,0.028377408,-0.017005375,-