INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2d2d3d4-d5d6-47d8-89da-dbdc0d0e0f10', 'Any dispute arising out of or relating to this Agreement shall be resolved exclusively by binding arbitration administered by the American Arbitration Association in the state of Client''s principal office. The arbitrator''s decision shall be final and binding, and judgment upon the award may be entered in any court of competent jurisdiction. Each party shall bear its own costs, except that the losing party shall reimburse the prevailing party''s reasonable attorneys'' fees and arbitration costs.', 'dispute_resolution', '["freelance"]'::jsonb, 'yellow', 'You must travel to wherever the client is located for arbitration, which could be expensive and inconvenient. The ''loser pays'' provision for attorneys'' fees creates a massive financial risk that discourages you from pursuing legitimate claims -- if you lose, you pay both sides'' legal bills. Mandatory arbitration also means you give up your right to a court trial and, typically, your right to appeal.', 'Any dispute arising out of this Agreement shall first be submitted to mediation. If mediation fails within thirty (30) days, the dispute shall be resolved by binding arbitration conducted virtually or in a mutually agreed location. Each party shall bear its own attorneys'' fees and costs regardless of outcome. For disputes under $10,000, the parties agree to use small claims court in the jurisdiction where the defendant resides.', 'The Federal Arbitration Act (9 U.S.C. Sections 1-16) generally enforces arbitration clauses, but courts can invalidate them if unconscionable (AT&T Mobility v Concepcion, 2011 -- though this case upheld arbitration). EU Directive 93/13/EEC Annex paragraph 1(q) flags terms requiring the consumer to take disputes exclusively to arbitration not covered by legal provisions. UK Arbitration Act 1996 Section 89 provides protections for consumers in arbitration.', '[-0.018228289,-0.05883791,-0.0289211,-0.006973973,-0.041854106,0.023486331,-0.003053819,0.03413484,0.02377366,0.028332235,-0.00306295,-0.01349124,0.01987774,-0.043512825,0.031973056,0.041185647,-0.029970894,-0.004476652,0.015365023,0.018249394,-0.024439424,-0.02889207,-0.005628301,0.002654151,-0.001631924,0.005849211,0.034634866,-0.003833926,0.025556527,0.017053973,0.000220475,0.002595866,0.018522318,-0.046296693,-0.006307587,0.010748364,0.003449728,0.018300094,-0.001154332,0.005818115,0.0270341,0.037923917,0.015303728,0.026989302,0.0100309,0.010485079,0.008717542,0.021261364,-0.004250304,-0.057359096,0.0341091,-0.018569544,0.022461459,-0.002672572,-0.009795978,-0.032501724,-0.006563892,-0.007650146,-0.046164487,0.01870276,0.037374396,-0.023396395,-0.026178634,0.0477787,-0.005285779,-0.07414401,-0.011074895,0.025214937,0.0333191,0.022930756,0.03165168,-0.000359638,-0.013931441,0.046910252,0.016186683,0.00499997,-0.039753493,0.024143519,0.059103094,0.01330357,0.013225869,0.00448108,0.005012932,0.012892812,-0.01930119,-0.03024232,0.053988688,0.027842911,0.027887806,0.041594516,-0.050488558,-0.06478095,0.035211597,-0.006068363,0.007170847,0.028219592,-0.021373296,-0.005608186,0.019529695,-0.010535541,-0.03612047,-0.04281958,-0.007751734,0.024737572,0.037448697,0.02181736,0.00204245,-0.010378614,-0.003566442,0.04272595,0.007737685,0.025938446,-0.008665299,0.022924969,0.05677796,-0.039171968,-0.008613165,0.030052034,-0.016599484,0.008948659,-0.017773258,-0.029369697,-0.044761915,0.020675778,0.018943978,-0.013276041,0.013035422,-0.063240305,0.038623955,-0.007065076,0.043703407,0.013212729,0.04070284,0.010241435,0.00374663,-0.026789896,0.007786528,0.050595984,0.018900096,0.011989071,-0.031501163,-0.008272446,0.02330915,0.036009595,0.000917997,-0.013185739,-0.002627707,0.006935739,-0.04042403,0.012269867,0.013034389,-0.05746705,0.019875567,-0.007354,0.00323883,-0.018783469,0.018225808,-0.0091255