INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2e2e3e4-e5e6-47e8-89ea-ebec0d0e0f10', 'Contractor acknowledges that any breach of the confidentiality, non-compete, or intellectual property provisions of this Agreement would cause irreparable harm to Client. Contractor consents to the entry of injunctive relief without the necessity of Client posting bond and without Client having to prove actual damages, in any court of competent jurisdiction.', 'dispute_resolution', '["freelance"]'::jsonb, 'yellow', 'You''ve pre-agreed that the client can get a court order to stop you from working (an injunction) without proving they were actually harmed and without posting a bond (a financial guarantee in case the injunction was wrongful). This gives the client an extremely cheap and powerful weapon to threaten you with -- they can halt your business without proving anything.', 'Both parties acknowledge that breach of confidentiality or intellectual property provisions may cause irreparable harm. Either party may seek injunctive relief in a court of competent jurisdiction, subject to the court''s discretion regarding the posting of a reasonable bond and the demonstration of likely irreparable harm.', 'US courts require a showing of irreparable harm for injunctive relief (eBay Inc. v MercExchange, 2006). Pre-agreed waiver of bond requirements may be unenforceable in some jurisdictions (e.g., California Code of Civil Procedure Section 529). UK courts grant injunctions based on the American Cyanamid test, requiring a serious question to be tried. EU Directive 93/13/EEC Annex paragraph 1(q) flags terms unduly restricting the consumer''s access to legal remedies.', '[0.016968014,0.007838502,-0.04382206,0.012469811,-0.030144647,-0.005114001,0.016377324,0.015376423,-0.03669891,0.054642905,-0.038538642,-0.025984522,-0.040666014,-0.06328746,0.02595281,-0.028276872,0.0