INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3a7b8c9-d0e1-4f2a-bb4c-6d7e8f9a0b1c', 'This Agreement shall have no fixed term and shall remain in effect unless terminated by the Disclosing Party upon written notice to the Receiving Party, provided that all obligations of confidentiality shall survive any such termination indefinitely.', 'duration', '["nda"]'::jsonb, 'red', 'This is a double trap: only the disclosing party can end the agreement (you can''t), AND even after they do end it, your secrecy obligations last forever. You''re locked in with no way out and no end date. The disclosing party can terminate their own responsibilities whenever convenient while yours never expire. This one-sided structure is a hallmark of an unconscionable contract term.', 'This Agreement shall remain in effect for a period of two (2) years from the Effective Date, unless earlier terminated by either party upon thirty (30) days'' written notice. Upon termination or expiration, the obligations of confidentiality shall continue for a period of three (3) years from the date of disclosure of the applicable Confidential Information.', 'US: Restatement (Second) of Contracts Section 208 — unconscionability where one party has no meaningful choice. Unilateral termination rights create significant imbalance. EU: Unfair Contract Terms Directive 93/13/EEC Article 3(1) and Annex para. 1(f) — terms enabling the trader to terminate at will while binding the consumer are potentially unfair. UK: CRA 2015 Schedule 2 para. 7 — unfair if trader can terminate at will but not the consumer.', '[-0.013593186,-0.010010737,-0.030067423,0.023923388,-0.07789935,0.008621441,-0.020012842,0.01600592,-0.04423033,0.03630121,-0.01401024,-0.030317554,0.021028478,-0.020061022,-0.035559006,0.03944345,-0.0304886,0.02350748,-0.000740246,0.003751996,-0.049841296,0.022712434,-0.05282027,0.013869495