INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3e5f6a7-b8c9-4d0e-9f2a-4b5c6d7e8f9a', 'The Receiving Party''s obligations of confidentiality and non-use hereunder shall continue in perpetuity and shall survive any termination or expiration of this Agreement without limitation as to time.', 'duration', '["nda"]'::jsonb, 'red', 'This clause means you''re bound to keep information secret forever — literally until you die and beyond. While perpetual protection may be reasonable for genuine trade secrets (like the Coca-Cola formula), applying it to ALL confidential information is extreme. Business information loses its value over time as markets change, products launch, and companies evolve. A perpetual obligation for non-trade-secret information is often struck down as an unreasonable restraint.', 'The Receiving Party''s obligations of confidentiality and non-use hereunder shall continue for a period of three (3) years following the date of disclosure of each item of Confidential Information, except that obligations with respect to trade secrets shall continue for so long as such information remains a trade secret under applicable law.', 'US: Perpetual NDAs for non-trade-secret info may be unenforceable as unreasonable restraint of trade under Restatement (Second) of Contracts Section 188. UTSA provides perpetual protection only for actual trade secrets. EU: Unfair Contract Terms Directive 93/13/EEC Annex para. 1(q) — terms that inappropriately exclude or limit rights may be unfair. UK: Common law restraint of trade doctrine requires restrictions to be reasonable in duration.', '[-0.007153852,-0.037355613,-0.02437745,0.008935913,-0.061949894,-0.03991613,-0.040880375,0.005090019,-0.05933814,0.02677762,-0.06487772,-0.008512571,-0.003113499,-0.045962684,-0.016662952,0.03614128,0.019123655,0.014115736,-0.007548352,0.051643178,-0.028541196,0.025289023,-