INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3b8c9d0-e1f2-4a3b-8c5d-7e8f9a0b1c2d', 'The obligations of this Agreement shall survive in perpetuity with respect to all Confidential Information, and no lapse of time or other circumstance, including the subsequent public availability of any Confidential Information, shall relieve the Receiving Party of its obligations hereunder.', 'duration', '["nda"]'::jsonb, 'red', 'This clause says your obligations never end — and shockingly, they continue even if the information becomes public knowledge through no fault of yours. If the disclosing party publishes their own information, or it appears in a news article, you''d still technically be in breach for discussing it. This contradicts the fundamental legal principle that publicly available information cannot be a trade secret, and courts routinely refuse to enforce such provisions.', 'The obligations under this Agreement shall terminate with respect to any particular item of Confidential Information if and when such information (a) becomes publicly available through no act or omission of the Receiving Party, (b) ceases to qualify as a trade secret under applicable law, or (c) is disclosed by the Disclosing Party to third parties without restriction. All remaining obligations shall expire three (3) years from the date of disclosure.', 'US: UTSA Section 1(4) and DTSA 18 U.S.C. Section 1839(3) — trade secret status is lost when information becomes generally known. Silvaco Data Systems v. Intel Corp. (information in public domain cannot be protected). EU: Trade Secrets Directive 2016/943 Article 2(1)(a) — secrecy is a constitutive element. UK: Trade Secrets Regulations 2018 — information must not be generally known or readily accessible.', '[-0.021055505,-0.037539907,-0.017115979,0.038694955,-0.050108846,-0.0251522,-0.053392634,-0.003114614,-0.06419982,0.0