INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3f6a7b8-c9d0-4e1f-aa3b-5c6d7e8f9a0b', 'The obligations set forth herein shall remain in full force and effect for a period of fifteen (15) years from the Effective Date of this Agreement, regardless of whether the business relationship between the parties has terminated.', 'duration', '["nda"]'::jsonb, 'yellow', 'Fifteen years is extraordinarily long for an NDA, especially for general business information that will likely be outdated in 2-3 years. While not perpetual, it far exceeds industry norms of 2-5 years for most commercial NDAs. The longer the duration, the harder it is for you to remember what was covered and the more likely you''ll accidentally breach it years after the business relationship ended.', 'The obligations set forth herein shall remain in full force and effect for a period of three (3) years from the date of disclosure of the applicable Confidential Information, or two (2) years following the termination of this Agreement, whichever is later. Obligations regarding trade secrets shall survive for so long as such information qualifies as a trade secret under applicable law.', 'US: While no statutory maximum exists, courts evaluate reasonableness under Restatement (Second) of Contracts Section 188. Industry standard is 2-5 years for non-trade-secret info. EU: Trade Secrets Directive 2016/943 does not prescribe duration but national courts apply proportionality. UK: Reasonableness assessed under restraint of trade doctrine — Thomas v. Farr plc (duration must be proportionate to legitimate interest).', '[-0.004557673,-0.0353675,-0.014168072,-0.011083298,-0.06354713,0.018882971,0.029465778,0.02193681,-0.05820292,0.01496824,-0.04593536,-0.026003346,-0.000426625,-0.028804984,0.007165472,0.004658964,0.021593453,0.043643054,-0.004986662,0.05095654,-0.03797254,0.060436543,-0.054879222,0.0