INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5d0e1f2-a3b4-4c5d-a6f7-a8b9c0d1e2f3', 'These Terms and any action related thereto shall be governed by and construed in accordance with the laws of the State of Delaware, United States, without regard to its conflict of laws provisions. You irrevocably consent to the exclusive jurisdiction and venue of the state and federal courts located in Wilmington, Delaware, for the adjudication of any dispute arising out of or relating to these Terms. You hereby waive any objection to such jurisdiction or venue, including any objection based on inconvenient forum.', 'governing_law', '["tos"]'::jsonb, 'yellow', 'This forces you to travel to Delaware to resolve any dispute, regardless of where you live. For most consumers, the cost and inconvenience of litigating in a distant state makes it effectively impossible to challenge the company. The clause also tries to override consumer protection laws in your home country or state, which may offer you stronger rights.', 'These Terms shall be governed by the laws of the jurisdiction in which you reside, to the extent required by applicable consumer protection law. For disputes that cannot be resolved informally, you may bring a claim in the courts of your home jurisdiction. Nothing in these Terms deprives you of mandatory consumer protections available under the laws of your country of residence.', 'CJEU case Océano Grupo Editorial (C-240/98) held that jurisdiction clauses requiring consumers to litigate far from home are unfair under Directive 93/13/EEC. EU Brussels I Regulation (1215/2012) Article 18 allows consumers to sue in their home courts. UK CRA 2015 Section 74 preserves mandatory rules of the consumer''s habitual residence. Rome I Regulation Article 6(2) prevents choice of law from depriving consumers of home-country protections.', '[-0.014055554,-0.033458