INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-a001-4a00-8000-000000000039', 'Tenant agrees to maintain renters'' insurance with minimum coverage of $500,000 in personal liability and $100,000 in personal property coverage, naming Landlord as primary beneficiary and additional insured. Tenant shall not make any insurance claim without Landlord''s prior written approval.', 'insurance', '["lease"]'::jsonb, 'yellow', 'Requiring renter''s insurance is reasonable, but $500,000 in liability coverage is excessive for most residential tenants -- typical policies are $100,000-$300,000. Naming the landlord as ''primary beneficiary'' of your renter''s insurance means the landlord gets paid before you do from your own policy. Requiring the landlord''s approval before filing a claim effectively prevents you from using the insurance you are paying for. Your renter''s insurance should protect you, not the landlord.', 'Tenant shall maintain renters'' insurance with minimum coverage of $100,000 in personal liability and personal property coverage sufficient to protect Tenant''s belongings. Landlord may be named as an ''interested party'' for notification purposes, but not as a beneficiary or additional insured. Tenant shall have the unrestricted right to file claims on Tenant''s own policy.', 'While most US states allow landlords to require renter''s insurance, naming landlord as primary beneficiary is not standard and may conflict with insurance contract terms. California Insurance Code Section 533.5 and public policy limit insurance restrictions. UK Financial Conduct Authority guidelines protect consumer insurance rights. EU Directive 93/13/EEC Annex paragraph (b) prohibits terms inappropriately excluding or limiting consumer legal rights.', '[-0.021970889,-0.039898686,0.002455674,-0.0661584,-0.03160569,-0.058594387,-0.022794804,0.021273408,0.0454847