INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4a7b8c9-0d1e-4f2a-8b5c-6d7e8f9a0b1c', 'The Employee acknowledges and agrees that any intellectual property conceived, created, or developed by the Employee during the six (6) month period immediately following the termination of employment shall be presumed to have been conceived during the term of employment and shall be the sole and exclusive property of the Company. The burden shall be on the Employee to demonstrate otherwise.', 'ip_assignment', '["employment"]'::jsonb, 'red', 'This clause claims ownership of your inventions for six months after you leave the company, and puts the burden on you to prove the work was not conceived during your employment. This is an IP ''trailer clause'' that effectively extends your obligations well beyond your actual employment. It means anything you create at a new job or as a personal project could be claimed by your former employer unless you can prove it was entirely new -- which is extremely difficult to do.', 'The Employee agrees to promptly disclose to the Company any invention or work of authorship that relates to the Company''s business and that the Employee conceives within sixty (60) days of termination, to the extent such invention or work is based on or derived from the Company''s confidential information. The Company shall have thirty (30) days to review the disclosure and assert a good-faith claim of ownership; otherwise all rights vest in the Employee.', 'California Labor Code section 2870 limits IP assignment to work related to the employer''s business and created using company resources; post-employment extensions are viewed skeptically by California courts. UK Patents Act 1977 section 39 limits employer ownership to inventions made in the course of normal duties or specifically assigned duties. Restatement (Second) of Contracts section 188 ap