INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4f6a7b8-9c0d-4e1f-ba4b-5c6d7e8f9a0b', 'The Employee hereby assigns, and agrees to assign, to the Company the Employee''s entire right, title, and interest in and to any and all inventions, discoveries, designs, developments, improvements, copyrightable works, trade secrets, and other intellectual property, whether or not patentable or registrable, that the Employee may solely or jointly conceive, develop, or reduce to practice during the period of employment, regardless of whether (a) such intellectual property is related to the Company''s current or anticipated business, (b) such intellectual property was created during working hours or using Company resources, or (c) such intellectual property was created at the Employee''s personal residence using the Employee''s personal equipment.', 'ip_assignment', '["employment"]'::jsonb, 'red', 'This clause claims ownership of everything you create while employed -- including personal side projects, open-source contributions, a novel you write on weekends, or an app you build on your own laptop at home that has nothing to do with the company''s business. It explicitly covers work done on your own time with your own equipment. Several US states have laws specifically banning this kind of overreach, recognizing that employers should only own work related to their business.', 'The Employee hereby assigns to the Company all right, title, and interest in inventions, discoveries, designs, and copyrightable works that (a) are made within the scope of the Employee''s employment duties, (b) relate to the Company''s current business or demonstrably anticipated research and development, and (c) are created using Company time, equipment, supplies, or proprietary information. This assignment does not apply to inventions that the Employee develops entirely on their own time without using Company resources and that do not relate to the Company''s business. The Employee may list pre-existing inventions on Schedule C.', 'California Labor Code section 2870 prohibits employers from claiming inventions developed entirely on the employee''s own time without company resources that don''t relate to the employer''s business. Similar statutes exist in Delaware (19 Del. C. section 805), Illinois (765 ILCS 1060/2), Minnesota (Minn. Stat. section 181.78), and Washington (RCW 49.44.140). UK Copyright, Designs and Patents Act 1988 section 11(2) limits employer ownership to works created in the course of employment.', '[0.012706432,0.025195105,0.006124529,0.05416154,-0.05405337,0.04131656,-0.00441316,0.011130721,0.002118276,0.06201774,-0.027016824,0.02767022,-0.01329891,-0.005496308,0.014792027,-0.031266414,-0.013099548,0.04792563,0.000190023,0.052208062,0.04108268,0.03209612,0.024513861,-0.007184115,0.028436158,-0.026341956,-0.002831921,-0.003153325,0.012177455,0.03698214,0.052231677,0.0261237,-0.0315035,-0.012617678,-0.018340753,-0.041420255,0.05223326,-0.016216943,0.004186612,0.018783236,-0.038346324,0.010810107,0.032205254,0.04065695,-0.006111421,-0.014926184,-0.001488296,0.029405069,-0.023195716,-0.00642187,0.023594063,-0.020434236,-0.029126557,0.0159868,0.039327767,0.03507155,0.00240677,-0.004941249,0.02770353,-0.017996041,0.069271035,-0.054116525,-0.016328754,0.004531278,0.012986117,-0.08442663,0.052992344,0.007508457,-0.016008377,0.017456565,0.0442552,0.031945918,0.013888543,0.029434564,-0.028424012,-0.022250349,-0.05568505,-0.021008914,-0.015292542,0.030865181,-0.068666674,-0.005893103,0.000777153,0.039532527,-0.053969536,-0.002759823,-0.060958657,-0.007856064,0.014987205,0.07339971,0.017934471,-0.10109186,0.000166777,-0.032850187,0.043904394,-0.009446541,0.047734037,-0.031231046,-0.001867106,0.041071787,-0.04980515,0.03452033,-0.011409018,-0.01597298,0.028679077,-0.000960547,-0.011681743,0.000200781,0.009121663,0.030983428,0.022218943,-0