INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4d0e1f2-3a4b-4c5d-be8f-9a0b1c2d3e4f', 'The Employee agrees that any use of the Employee''s personal computer, mobile device, home internet connection, or other personal equipment or resources for any work-related purpose shall constitute use of ''Company Resources'' for purposes of the intellectual property assignment provisions of this Agreement, and all works created using such resources shall be the sole property of the Company.', 'ip_assignment', '["employment"]'::jsonb, 'red', 'This clause redefines your personal laptop, phone, and home internet as ''Company Resources'' the moment you check a work email or join a video call from home. Since nearly everyone uses personal devices for some work activity, this effectively converts all your personal equipment into company equipment for IP purposes. Anything you create on your personal computer could be claimed by the company. This is especially dangerous for remote and hybrid workers who routinely use personal devices.', '''Company Resources'' means equipment, software, networks, and supplies provided and owned by the Company. The Employee''s personal computers, devices, internet connections, and other personal property shall not constitute Company Resources regardless of whether they are incidentally used for work-related purposes. The IP assignment provisions of this Agreement apply only to works created using Company Resources as defined herein or during the Employee''s scheduled working hours.', 'California Labor Code section 2870 protects inventions made on the employee''s own time without company equipment, and redefining personal equipment as company equipment would likely be viewed as an attempt to circumvent this protection. Similar protections exist in Illinois (765 ILCS 1060/2), Minnesota (Minn. Stat. section 181.78), and Washington (RCW 49.44.140). UK Employment Rights Act 1996 does not permit employers to unilaterally redefine the nature of employees'' personal property.', '[-0.022766989,0.03763205,0.019867685,0.08417394,-0.06302217,0.028838648,0.000901229,-0.015457349,-0.018436113,0.016644036,-0.017798292,0.035968784,-0.023715349,-0.029477252,0.049702957,-0.007641901,0.009887262,0.03712113,0.017059892,-0.01778967,-0.013247226,0.027794294,-0.024583384,0.0202884,0.043220967,-0.040011723,0.01982747,0.034415573,-0.003777323,0.04277375,0.037692063,0.011060288,-0.009165059,-0.027897252,0.003740349,-0.030673882,0.04510931,-0.039866675,-0.041287843,0.029872209,-0.06542625,-0.010057832,0.030011708,-0.009549672,0.005875425,0.009994389,-0.002267807,0.026579205,-0.011179656,-0.021738611,-0.003029581,-0.036245365,-0.005023104,0.022164345,-0.005967438,0.07307169,0.034586094,0.016011922,0.02317315,0.010503712,0.042179458,-0.033998094,-0.01023169,0.009810224,-0.013313393,-0.08748346,-0.014892349,0.057410747,-0.03144147,0.018159276,0.041724354,0.059440322,0.008551051,0.01462281,-0.051620003,-0.014915731,-0.036386874,-0.053984247,0.010804324,0.027294336,-0.07853644,-0.0315742,-0.016446192,-0.00079207,-0.04984152,0.00224646,-0.021692382,0.015914494,0.010274782,0.05077992,-0.005250875,-0.08646758,0.013757839,0.002038332,0.02968878,-0.018633034,0.010700202,-0.04791776,-0.046478577,0.080475405,-0.03854717,0.040750425,0.013059743,0.001607556,0.025326015,-0.02033147,-0.02185351,-0.016774451,0.03705102,0.01811018,0.043514516,-0.049537964,-0.016898038,0.006044637,-0.0411892,0.04768298,-0.030517032,0.004066237,0.059583258,0.000533703,-0.05667805,-0.00573921,-0.010167298,0.031186976,-0.04407666,0.023485221,-0.017604457,-0.010463397,0.015449587,0.011642443,0.018812312,0.02890485,0.03784526,-0.040247846,-0.032783642,0.015243568,-0.009998392,0.014551208,-0.003908627,-0.020772459,-0.023224853,-0.04492217,-0.004918841,0.032645613,0.009353794,-0.032998215,-0.032589253,0.03448732,-0.003051775,0.006419308,-0.022828132,-0.05557548