INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4b8c9d0-1e2f-4a3b-9c6d-7e8f9a0b1c2d', 'To the maximum extent permitted by applicable law, the Employee hereby irrevocably waives all moral rights (including the right of attribution, the right of integrity, and the right to object to derogatory treatment) in any works created in the course of employment, whether now known or hereafter recognized, in all media and jurisdictions throughout the world.', 'ip_assignment', '["employment"]'::jsonb, 'yellow', 'Moral rights are your right to be credited as the creator of your work and to prevent it from being distorted or mutilated. This clause waives those rights globally and permanently. While some countries allow waiver of moral rights (like the UK for employee-created works), others consider them inalienable -- meaning they cannot be given away regardless of what you sign. If you are a designer, writer, or other creative professional, this means the company could strip your name from your work or alter it in ways you find objectionable.', 'To the extent permitted by applicable law, the Employee consents to the Company''s reasonable use and modification of works created in the course of employment for legitimate business purposes. The Company shall use reasonable efforts to provide attribution to the Employee where practicable. Nothing in this clause shall require the Employee to waive moral rights in jurisdictions where such waiver is prohibited by law.', 'UK Copyright, Designs and Patents Act 1988 section 87 allows waiver of moral rights, but section 79(3) provides that the right of attribution does not apply to employee works by default. French Intellectual Property Code Article L121-1 treats moral rights as inalienable and perpetual. German Copyright Act (UrhG) section 12-14 treats moral rights as non-transferable. US has limited moral rights under 