INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4c9d0e1-2f3a-4b4c-ad7e-8f9a0b1c2d3e', 'The Employee shall disclose to the Company a complete list of all inventions, original works of authorship, developments, improvements, and trade secrets, whether or not patentable or registrable, that the Employee has, alone or jointly with others, conceived, developed, or reduced to practice prior to the commencement of employment (''Prior Inventions''). Any intellectual property not disclosed on the Prior Inventions list shall be presumed to have been created during the term of employment and shall be the property of the Company.', 'ip_assignment', '["employment"]'::jsonb, 'yellow', 'This clause requires you to list every idea and creation you have ever had before starting the job. Anything you forget to list is automatically claimed by the company. Most people cannot produce a comprehensive inventory of every project, code repository, design, or idea they have ever worked on. The presumption of company ownership for unlisted work creates a trap: if you later develop something based on a pre-existing idea you forgot to list, the company can claim it was created during your employment.', 'The Employee may, but is not required to, identify prior inventions on Schedule C at or before the commencement of employment. Failure to list a prior invention on Schedule C shall not create any presumption of Company ownership. The Company''s rights under this Agreement extend only to intellectual property meeting the criteria set forth in the IP Assignment clause above. Any dispute over whether an invention is a Prior Invention shall be resolved by reference to objective evidence of the date of conception.', 'California Labor Code section 2870 protects employee inventions made on their own time and unrelated to the employer''s business regardless of disclosure. Delaware Code Title 19 section 805 similarly limits employer claims. Under UK common law, the burden of proving an invention was created in the course of employment falls on the employer (LIFFE Administration and Management v Pinkava [2007] EWCA Civ 217).', '[0.021718645,-0.018070038,0.023548499,0.029754318,-0.028086182,0.04610174,-0.006155091,0.015700977,0.006872711,0.06494839,-0.07154802,0.026416482,-0.020541858,-0.028831467,0.013965154,-0.038273495,-0.011212908,0.017962553,0.006449661,0.073287025,0.014871999,0.015038804,0.055721622,-0.010632613,0.024570081,-0.027651135,-0.015208168,0.002421446,0.020510288,0.027861234,0.049896177,0.030654812,-0.009240908,-0.015815986,-0.012878861,-0.038082205,0.029425584,-0.04125124,0.024573157,0.030803503,-0.006762622,-0.002096684,-0.028504776,-0.012654897,-0.02591669,-0.026625382,0.02849616,0.001813419,-0.003102029,0.003076439,-0.01555273,-0.013202803,-0.014513619,0.006109957,0.018650642,0.035726834,-0.000300799,-0.010318553,0.033154014,-0.047094207,0.053006105,-0.04788371,-0.01088869,-0.00217759,0.001126901,-0.054669205,0.05969669,-0.029193217,0.008865128,-0.01451801,0.04203938,0.025242444,-0.030007586,-0.018706258,-0.031042974,-0.020080639,-0.04131724,-0.009305445,0.007563246,0.02871371,-0.035933647,-0.005679181,0.011193983,0.014286427,-0.05333209,0.022769433,-0.063737586,-0.0210638,0.01983579,0.040591083,-0.013200145,-0.0742855,0.03291572,-0.04992875,0.020300075,-0.03844083,0.04714767,-0.0452304,-0.00797802,0.009587608,-0.004855221,0.027352242,-0.023502368,-0.041864373,0.050773993,-0.013385484,-0.024252174,-0.009250139,-0.001081299,0.02090171,0.03215559,-0.023175837,0.006343095,-0.000877339,-0.01239822,0.025654135,-0.05306681,-0.017327094,0.028609369,0.005728457,-0.028626537,-0.035710964,-0.012979407,-0.021766275,-0.01764101,-0.018897286,-0.026425228,0.035508018,0.022502936,-0.035723943,-0.015262247,-0.024602273,-0.022913251,0.015468916,-0.025834342,-0.01735604,-0.004698786,0.01106496,-0.017836642,-0.018523479,-0.023353612,0.00191883