INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2a1c3d4-e5f6-4a7b-8c9d-0e1f2a3b4c5d', 'All Work Product, including but not limited to ideas, concepts, inventions, designs, code, documentation, and any other materials created, conceived, or developed by Contractor during the term of this Agreement, whether or not related to the Services, shall be the sole and exclusive property of Client. Contractor hereby irrevocably assigns to Client all right, title, and interest in and to such Work Product, including all intellectual property rights therein.', 'ip_ownership', '["freelance"]'::jsonb, 'red', 'This assigns ALL intellectual property you create while the contract is active -- even personal projects, side work, or tools you build for other clients -- to this one client. The phrase ''whether or not related to the Services'' is the trap. It means your weekend app, your blog post, your open source contribution could all legally belong to them.', 'All Work Product created by Contractor specifically in the performance of the Services described in the applicable Statement of Work shall be the property of Client. Contractor retains all right, title, and interest in pre-existing intellectual property, tools, methodologies, and any work created outside the scope of the Services.', 'Under 17 U.S.C. Section 101, ''work made for hire'' only applies to employees or to independent contractors in 9 narrow categories (and only with a signed written agreement). Overly broad IP assignment to contractors may be challenged as unconscionable under Restatement (Second) of Contracts Section 208. In the EU, Directive 93/13/EEC Article 3(1) may render such terms unfair if they cause a significant imbalance in the parties'' rights.', '[-0.022825044,0.003613779,-0.03140431,0.028573915,-0.055512536,0.008264459,-0.02536936,-0.01643515,-0.016387576,0.04155341,-0.023591949,-0.0