INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2d4e5f6-a7b8-4c9d-8e1f-2a3b4c5d6e7f', 'Client shall have a perpetual, irrevocable, worldwide, royalty-free license to use, modify, sublicense, and create derivative works from any Work Product, concepts, designs, or deliverables produced by Contractor during the engagement, including work that is rejected, not approved, or not included in the final deliverables.', 'ip_ownership', '["freelance"]'::jsonb, 'yellow', 'This gives the client a permanent free license to use even your rejected or unused work -- including drafts, alternative concepts, and ideas you pitched but they didn''t pick. That unused work might be something you could repurpose for another client. The sublicense right means they could also let third parties use your rejected work.', 'Client shall have a perpetual, irrevocable, worldwide, royalty-free license to use, modify, and create derivative works from final approved Work Product only. All rejected, unused, or unapproved concepts and drafts remain the property of Contractor.', 'Under EU Directive 93/13/EEC Article 3(1), a term not individually negotiated that creates a significant imbalance to the consumer''s detriment may be regarded as unfair. Retaining license to rejected work may qualify under Annex paragraph 1(b) as inappropriately limiting the other party''s rights. US courts have found overly broad license grants unconscionable under UCC Section 2-302.', '[-0.003839234,0.000851301,-0.010886558,-0.036977585,-0.070264116,0.005410457,-0.01507611,0.012089948,-0.03896798,0.041450236,-0.026437316,-0.023117874,-0.020203551,-0.05083793,0.0120463,0.029448332,-0.07030733,-0.005217231,-0.010044949,0.009692032,-0.024406334,-0.040834285,-0.012186414,-0.012308956,0.016748296,-0.003459589,0.01268982,0.06910077,-0.03044322,0.017818375,0.01729435,-0.001768567,-0.031010607,-0.007428542,-0.0