INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-3004-4a00-9a00-000000000015', 'Rent shall be payable in advance on the first day of each month. If Tenant fails to pay rent by the first day, a late fee of $150 or 15% of the monthly rent (whichever is greater) shall be immediately due. An additional $50 per day shall accrue for each day rent remains unpaid.', 'late_fees', '["lease"]'::jsonb, 'red', 'There is no grace period at all -- you owe a penalty the instant the calendar turns to the 1st. The 15% fee is far above what most jurisdictions allow (typically 4-6%). The $50/day compounding penalty means that being two weeks late adds $700 on top of the base late fee and your rent. Courts treat excessive late fees as unenforceable penalties because they do not reflect the landlord''s actual loss from a late payment.', 'Rent shall be due on the first day of each month. A grace period of 5 business days shall apply. If rent is not received by the 5th business day, a one-time late fee of 4% of the monthly rent shall be assessed. No additional daily or compounding charges shall apply. Landlord shall provide written notice of any outstanding balance before imposing the late fee.', 'California Civil Code Section 1671 requires late fees to be a reasonable estimate of actual damages. Texas Property Code Section 92.019 requires a grace period of at least 2 days and caps late fees at reasonable amounts. New York courts routinely strike down late fees exceeding 4-5% as penalties. UK Consumer Rights Act 2015 Schedule 2 paragraph 6 prohibits disproportionately high compensation. EU Directive 93/13/EEC Annex paragraph (e) flags disproportionate penalties.', '[-0.044073634,0.03783855,-0.029702943,-0.04801298,-0.060570035,-0.012551939,-0.03692758,-0.040573314,0.08651955,0.021840867,0.004284023,-0.01570778,-0.040618937,-0.06323349,0.07139661,-0.015460465,-0