INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-3006-4a00-9000-000000000017', 'If rent remains unpaid for more than five (5) days past the due date, Landlord shall have the immediate right to deduct any amounts owed, including rent, late fees, and administrative charges, directly from Tenant''s security deposit without notice.', 'late_fees', '["lease"]'::jsonb, 'red', 'Your security deposit is not a rent account the landlord can dip into whenever they choose. The deposit exists to cover damage at the end of the lease. If the landlord drains your deposit mid-lease for late rent, you have no protection at move-out and may be forced to pay a new deposit. Most jurisdictions strictly limit when and how deposits can be applied, and raiding it for late fees (which may themselves be unenforceable) compounds the problem.', 'The security deposit shall not be applied to rent, late fees, or any other charges during the lease term. The deposit shall be held solely as security against damage to the Premises and unpaid obligations at lease termination, in accordance with applicable law. If Tenant is in arrears, Landlord shall follow the notice and cure procedures set forth in this Lease before pursuing any remedies.', 'California Civil Code Section 1950.5 limits deposit deductions to end-of-tenancy damages. New York GOL Section 7-108 prohibits using deposits as rent during the tenancy. UK Tenant Fees Act 2019 restricts deposit use to specified end-of-tenancy purposes. EU Directive 93/13/EEC Annex paragraph (d) restricts forfeiture of sums paid by the consumer.', '[-0.033802524,0.007047476,-0.002703404,-0.005892148,-0.019863283,-0.014686263,-0.03596154,-0.0422352,0.03126703,0.008517565,0.005658721,-0.044947535,-0.025417788,-0.0553888,0.03324817,0.016467057,-0.016526071,0.011489396,0.003895144,-0.017543424,0.0692862,-0.033101477,-0.009472394,0.031742986