INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-3005-4a00-b000-000000000016', 'In the event of late payment, Landlord shall be entitled to charge a non-refundable administrative processing fee of $250 per occurrence in addition to any late fees, and Tenant''s credit report may be updated to reflect the delinquency.', 'late_fees', '["lease"]'::jsonb, 'yellow', 'Stacking a $250 ''administrative fee'' on top of late fees is a penalty disguised as a cost. Processing a late payment does not cost $250. The credit reporting threat adds coercive pressure -- a single late rent payment reported to credit bureaus can damage your credit score for years, affecting your ability to rent, borrow, or even get a job. Many jurisdictions require specific procedures before reporting to credit agencies.', 'Late payment charges shall consist solely of the late fee specified in this Lease. No additional administrative, processing, or service fees shall be imposed for late payment. Landlord shall not report a payment as delinquent to any credit reporting agency unless payment remains outstanding for more than 30 days and Landlord has first provided Tenant with written notice and a 10-day cure period.', 'US Fair Credit Reporting Act (15 U.S.C. Section 1681s-2) imposes accuracy obligations on furnishers of credit information. California Civil Code Section 1785.25 requires reasonable procedures to ensure accuracy. UK Consumer Rights Act 2015 Schedule 2 paragraph 6 prohibits disproportionate charges. EU Directive 93/13/EEC Annex paragraph (e) addresses disproportionate penalties.', '[-0.056102544,0.03442379,0.023657234,-0.022063648,0.003322804,-0.00705768,0.001520475,-0.03596615,0.012720576,-0.038706508,0.021783777,-0.055134643,-0.035547752,-0.055033717,0.083876684,-0.031324055,-0.024715148,-0.005996822,0.04439559,0.030138645,0.01775919,-0.02096082,0.007909279,0.02