INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2222324-2526-4728-892a-2b2c2d2e2f30', 'Contractor agrees that Contractor is liable for any and all damages, including but not limited to consequential, incidental, and special damages, arising from defects, errors, or omissions in the Work Product, without limitation as to amount or time, even after Client has accepted and approved the Work Product.', 'liability', '["freelance"]'::jsonb, 'red', 'You have unlimited financial liability forever -- even after the client has reviewed, approved, and accepted your work. If a website you built has a bug discovered three years later, you''re on the hook for all damages with no cap. Acceptance by the client usually ends the defect liability period, but this clause overrides that protection.', 'Contractor warrants that the Work Product will substantially conform to the agreed specifications for a period of thirty (30) days following Client''s acceptance. Contractor''s liability for defects shall be limited to re-performing the defective Services at no additional cost, or, at Contractor''s option, refunding the fees attributable to the defective Work Product. In no event shall Contractor''s total liability exceed the total fees paid under this Agreement.', 'Unlimited, perpetual liability is likely unconscionable under Restatement (Second) of Contracts Section 208. UK Supply of Goods and Services Act 1982 Section 13 implies a duty to perform with reasonable care and skill, but does not impose unlimited liability. Post-acceptance warranty periods in commercial contracts are typically 30-90 days. EU Directive 93/13/EEC Annex paragraph 1(b) addresses inappropriate exclusion or limitation of rights.', '[0.010971013,-0.002232641,-0.016262513,0.012255836,-0.035790745,-0.036489647,-0.02382588,0.03033438,-0.011224547,0.05793448,-0.002094323,-0.04770885,-0.014243153,-0