INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2f1f2f3-f4f5-46f7-88f9-fafb0c0d0e0f', 'Contractor shall indemnify, defend, and hold harmless Client, its officers, directors, employees, agents, affiliates, and assigns from and against any and all claims, losses, damages, liabilities, costs, and expenses (including reasonable attorneys'' fees) arising out of or related to the Services, the Work Product, or Contractor''s performance under this Agreement, regardless of cause or fault.', 'liability', '["freelance"]'::jsonb, 'red', 'You must pay for ALL legal claims against the client related to the project -- even if it''s the client''s fault (''regardless of cause or fault''). If the client uses your deliverable irresponsibly and gets sued, you pay their legal bills. If the client makes changes to your work that cause problems, you still pay. There''s no limit on the amount and no requirement that you actually did anything wrong.', 'Contractor shall indemnify Client against third-party claims arising directly from Contractor''s material breach of this Agreement or Contractor''s gross negligence or willful misconduct. Client shall indemnify Contractor against claims arising from Client''s use of the Work Product in a manner not contemplated by this Agreement. Each party''s indemnification obligation shall not exceed the total fees paid under this Agreement.', 'One-sided indemnity ''regardless of fault'' may be unconscionable under Restatement (Second) of Contracts Section 208. UK Unfair Contract Terms Act 1977 Sections 2-3 restrict exclusion and limitation clauses including indemnities in standard-form contracts. EU Directive 93/13/EEC Annex paragraph 1(b) flags terms inappropriately excluding or limiting the consumer''s legal rights.', '[-0.017976107,-0.011152971,-0.044926286,0.052482057,-0.056498006,-0.028608378,-0.01904174,-0.013550248,-0.0307068