INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2020304-0506-4708-890a-0b0c0d0e0f10', 'IN NO EVENT SHALL CLIENT BE LIABLE TO CONTRACTOR FOR ANY INDIRECT, INCIDENTAL, SPECIAL, CONSEQUENTIAL, OR PUNITIVE DAMAGES. CLIENT''S TOTAL AGGREGATE LIABILITY SHALL NOT EXCEED THE LESSER OF THE FEES PAID IN THE THREE (3) MONTHS PRECEDING THE CLAIM OR FIVE HUNDRED DOLLARS ($500).', 'liability', '["freelance"]'::jsonb, 'yellow', 'The client caps their liability at $500 or three months of fees (whichever is LESS), while you have no corresponding protection. If the client causes you to lose other contracts, damages your reputation, or leaks your confidential information, the most you can recover is $500. Meanwhile, your liability to them is typically unlimited.', 'NEITHER PARTY SHALL BE LIABLE FOR INDIRECT, INCIDENTAL, SPECIAL, CONSEQUENTIAL, OR PUNITIVE DAMAGES. EACH PARTY''S TOTAL AGGREGATE LIABILITY SHALL NOT EXCEED THE TOTAL FEES PAID OR PAYABLE UNDER THIS AGREEMENT IN THE TWELVE (12) MONTHS PRECEDING THE CLAIM.', 'Asymmetric liability caps may be challenged under Restatement (Second) of Contracts Section 208 (unconscionability). UK Unfair Contract Terms Act 1977 Section 3 restricts limitation of liability in standard-form contracts; the clause must satisfy the reasonableness test in Section 11. EU Directive 93/13/EEC Annex paragraph 1(b) targets terms inappropriately excluding or limiting the consumer''s legal rights.', '[0.000741692,0.004256897,-0.028342994,0.022975828,-0.019812519,-0.019071262,-0.008329074,-0.006894491,-0.006610359,0.049675737,-0.01688639,-0.05228587,-0.023519913,-0.042842273,0.055697586,0.028045587,-0.044824623,-0.02434241,0.010812702,0.01828269,0.01697816,-0.021603279,-0.007473269,0.01510982,-0.019767713,-0.012711004,0.050612267,-0.004161461,-0.045244996,-0.008585333,-0.013648694,-0.011685529,-0.045221727,0.000660586,0.027943887,0.02777