INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-6003-4a00-9a00-000000000030', 'Tenant agrees to indemnify, defend, and hold harmless Landlord from any and all claims, damages, losses, costs, and expenses (including attorney fees) arising from any cause whatsoever in connection with the Premises, regardless of fault.', 'liability_waiver', '["lease"]'::jsonb, 'red', 'An indemnification clause (meaning you agree to pay for someone else''s losses) that says ''regardless of fault'' means you must pay the landlord''s legal bills and damages even when the landlord is at fault. If a guest slips on an icy staircase the landlord failed to maintain, this clause would make you -- not the landlord -- financially responsible. A ''regardless of fault'' indemnification in a residential lease is unconscionable because tenants have no ability to control the landlord''s behavior or building-wide conditions.', 'Tenant shall indemnify Landlord only against claims arising directly from Tenant''s own negligent or willful acts within the Premises. This indemnification shall not apply to claims arising from Landlord''s negligence, failure to maintain the Premises or common areas, or any condition that Landlord is obligated to repair under this Lease or applicable law.', 'California Civil Code Section 1953 voids lease provisions that shift liability for landlord''s negligence to tenant. Restatement (Second) of Contracts Section 208 provides that unconscionable terms are unenforceable. UK Unfair Contract Terms Act 1977 Section 2 restricts exclusion of negligence liability. EU Directive 93/13/EEC Article 3(1) targets terms that cause significant imbalance contrary to good faith.', '[-0.04038247,0.02989354,-0.038255483,0.003654794,-0.039007958,-0.053837758,-0.026140383,0.024654526,0.035719015,0.006249513,0.023306431,-0.03252405,-0.047384188,-0.045499228,0.005775455