INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5d6e7f8-a9b0-4c1d-a2f3-a4b5c6d7e8f9', 'IN NO EVENT SHALL THE COMPANY''S TOTAL AGGREGATE LIABILITY ARISING OUT OF OR RELATED TO THESE TERMS OR YOUR USE OF THE SERVICES EXCEED THE GREATER OF (A) THE AMOUNTS PAID BY YOU TO THE COMPANY IN THE THREE (3) MONTHS PRECEDING THE CLAIM, OR (B) ONE DOLLAR ($1.00 USD). THIS LIMITATION APPLIES TO ALL CLAIMS, WHETHER BASED ON WARRANTY, CONTRACT, TORT, STRICT LIABILITY, OR ANY OTHER LEGAL THEORY, AND WHETHER OR NOT THE COMPANY HAS BEEN ADVISED OF THE POSSIBILITY OF SUCH DAMAGES.', 'liability_waiver', '["tos"]'::jsonb, 'red', 'This caps the company''s total liability at 3 months of fees or one dollar, whichever is more. If they cause thousands of dollars in damages through a data breach or service failure, you can recover at most a few dollars. For free-tier users, the cap is literally one dollar. This makes it economically impossible to hold the company accountable for any harm.', 'Our total aggregate liability for claims arising under these Terms shall not exceed the greater of (a) the amounts paid by you in the twelve (12) months preceding the claim, or (b) five hundred dollars ($500.00 USD). This limitation does not apply to claims arising from our breach of data protection obligations, gross negligence, or willful misconduct. Nothing in these Terms limits liability that cannot be excluded by law.', 'EU Unfair Contract Terms Directive Annex 1(a) flags terms excluding or limiting liability for consumer harm. UK CRA 2015 Section 57 prevents excluding liability for breach of terms implied by Sections 49-52. Extremely low liability caps may be unconscionable under US Restatement (Second) of Contracts Section 208. German BGB Section 309(7) prohibits exclusion of liability for gross negligence.', '[0.016716551,0.04676962,-0.005859016,0.02542463,-0.003807459,-0.00064