INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-6001-4a00-a000-000000000028', 'Tenant hereby waives any and all claims against Landlord for personal injury, property damage, or loss of personal property occurring in or about the Premises, including claims arising from Landlord''s negligence, gross negligence, or willful misconduct.', 'liability_waiver', '["lease"]'::jsonb, 'red', 'This clause tries to protect the landlord from ALL liability, even for injuries caused by the landlord''s own gross negligence or intentional wrongdoing. If the landlord knows a staircase railing is broken and someone falls, this clause would shield them from any responsibility. Courts universally refuse to enforce waivers of liability for gross negligence and willful misconduct. Even waivers of ordinary negligence in residential leases are void in many jurisdictions because of the unequal bargaining power.', 'Landlord shall maintain the Premises and common areas in a reasonably safe condition. Landlord shall be liable for personal injury or property damage caused by Landlord''s negligence in maintaining the Premises or common areas. Nothing in this Lease shall operate to exclude or limit Landlord''s liability for death or personal injury caused by negligence, or for fraud or fraudulent misrepresentation.', 'California Civil Code Section 1953 voids any lease provision waiving tenant''s rights regarding habitability or landlord negligence. Illinois 765 ILCS 705/1 makes lease exculpatory clauses void and unenforceable. UK Consumer Rights Act 2015 Section 65 prevents excluding liability for death or personal injury from negligence. EU Directive 93/13/EEC Annex paragraph (a) prohibits terms excluding liability for death or personal injury due to the supplier''s act or omission.', '[-0.02701995,0.04401511,0.009456762,0.024314504,-0.054824017,-0.08212477,-0.05078821