INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5c3d4e5-f6a7-4b8c-99e0-f1a2b3c4d5e6', 'TO THE FULLEST EXTENT PERMITTED BY APPLICABLE LAW, THE COMPANY, ITS OFFICERS, DIRECTORS, EMPLOYEES, AND AGENTS SHALL NOT BE LIABLE FOR ANY INDIRECT, INCIDENTAL, SPECIAL, CONSEQUENTIAL, OR PUNITIVE DAMAGES, OR ANY LOSS OF PROFITS, DATA, GOODWILL, OR OTHER INTANGIBLE LOSSES, RESULTING FROM (I) YOUR ACCESS TO OR USE OF OR INABILITY TO ACCESS OR USE THE SERVICES; (II) ANY CONDUCT OR CONTENT OF ANY THIRD PARTY ON THE SERVICES; (III) ANY UNAUTHORIZED ACCESS, USE, OR ALTERATION OF YOUR TRANSMISSIONS OR CONTENT; OR (IV) ANY OTHER MATTER RELATING TO THE SERVICES, REGARDLESS OF WHETHER WE HAVE BEEN INFORMED OF THE POSSIBILITY OF SUCH DAMAGE, AND EVEN IF A REMEDY SET FORTH HEREIN IS FOUND TO HAVE FAILED OF ITS ESSENTIAL PURPOSE.', 'liability_waiver', '["tos"]'::jsonb, 'red', 'This tries to eliminate the company''s responsibility for essentially all harm, including when their own security failures expose your data. The all-caps format and sweeping language are designed to discourage reading. Point (iii) is especially alarming: they disclaim liability even if hackers steal your data through their negligence.', 'Our liability for indirect, incidental, or consequential damages is limited to the amount you have paid us in the 12 months preceding the claim, except that this limitation does not apply to damages arising from our gross negligence, willful misconduct, or breach of data protection obligations. Nothing in these Terms limits our liability for death or personal injury caused by our negligence, fraud, or any liability that cannot be excluded by law.', 'EU Unfair Contract Terms Directive Article 3 and Annex 1(a) flags terms excluding liability for death or personal injury caused by negligence. UK CRA 2015 Section 65 prohibits excluding liability for death or personal i