4,0.0209719,-0.003215519,-0.07940336,-0.01359458,-0.032198615,0.0419946,0.05947529,-0.030548768,0.05685246,-0.040669095,0.01737361,0.041002896,-0.052320648,-0.004632035,-0.014380037,-0.030723697,0.018509693,0.022324601,0.054716818,-0.021830268,-0.02129881,0.0392759,0.021330178,0.003308146,0.010609642,-0.007270186,0.002764552,-0.003119759,9.7158e-05,-0.098443456,0.03782825,0.068925664,-0.046557162,0.026091332,-0.019047687,-0.015557198,-0.028884575,-0.038609374,-0.005856675,0.005796701,-0.046143804,0.034415923,-0.005356362,-0.016527804,0.016565789,0.006831093,0.006240269,0.058728784,0.000116301,-0.012229622,-0.013208389,-0.021395687,0.08871223,0.004201379,0.011444069]'::vector, '2026-03-14T19:51:56.569Z');
INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-a002-4a00-9a00-000000000040', 'Tenant hereby agrees that in the event of any dispute arising out of or related to this Lease, Tenant shall submit such dispute to binding arbitration administered by an arbitration service selected by Landlord. Tenant waives all rights to a jury trial, to participate in class action proceedings, and to appeal any arbitration award. Tenant shall bear all costs of arbitration regardless of the outcome.', 'liability_waiver', '["lease"]'::jsonb, 'red', 'This clause stacks the deck against you in every possible way. The landlord chooses the arbitrator (who may favor repeat clients like landlords). You lose your right to a jury trial, cannot join with other tenants in a class action, cannot appeal even a clearly wrong decision, and must pay all costs even if you win. Mandatory arbitration with all these restrictions makes it financially impossible for most tenants to pursue legitimate claims and effectively places the landlord above the law.', 'In the event of any dispute arising under this Lease, the parties agree to attempt good-faith mediation before a mutually agreed-upon mediator. If mediation does not resolve the dispute within 30 days, either party may pursue resolution through the courts. Each party shall bear its own costs of mediation. Nothing in this Lease shall be construed as waiving either party''s right to a jury trial, to participate in class action proceedings, or to seek remedies available under applicable law.', 'US Federal Arbitration Act Section 2 permits arbitration clauses but courts scrutinize unconscionable terms. AT&T Mobility v. Concepcion, 563 U.S. 333 (2011) addressed enforceability limits. California Code of Civil Procedure Section 1281.97 requires arbitration fees to be paid timely or clause is waived. UK Consumer Rights Act 2015 Section 62 subjects arbitration clauses in consumer contracts to the unfairness test; Arbitration Act 1996 Section 91 limits compulsory consumer arbitration. EU Directive 93/13/EEC Annex paragraph (q) prohibits terms excluding or hindering the consumer''s right to take legal action.', '[-0.022584757,-0.007633794,-0.008681468,-0.025409816,-0.013357762,-0.0150388,-0.000581593,0.018985124,0.06755694,0.029497227,-0.001883711,0.001229557,0.03650888,-0.045721218,0.015323402,0.030649042,0.00015439,0.008246563,0.035856426,-0.023708519,0.019194951,-0.036046922,0.013412815,0.009586124,-0.010597557,0.016258722,-0.015739439,-0.015647402,-0.043497514,0.003374756,0.060462695,0.02975536,-4.2839e-05,-0.001844518,0.02638966,-0.011802162,-0.009095086,-0.002165459,0.003897223,-0.004214972,-0.002901931,0.01903866,0.024884887,0.02461395,0.026165796,-0.021175418,0.06824496,0.032973792,-0.05153093,0.008363014,0.054692797,-0.019342426,0.014429891,0.015988456,-0.001041519,-0.010488406,0.020755565,-0.036206346,-0.06902381,0.044142056,0.000318108,-0.011680353,-0.020899793,0.02763025,-0.037907016,-0.0448237,0.018515656,0.012407579,0.01562225,-0.03815337,0.07751956,0.03571112,0.03394145,0.017759882,-0.009051035,-0.001462804,-0.02194238,0.020881018,0.024451463,0.007344889,-0.031981777,-0.062388718,0.01955749,-0.018068349,0.03333623,0.00284517,0.03603306,0.037077744,0.03164007,0.034309745,-0.03956547,-0.027604587,0.0061407,0.037813626,0.038749848,-0.003151355,0.015963305,0.008352262,-0.013944252,-0.009349584,-0.008806722,-0.010224732,-0.004171713,-0.001352755,-0.017898533,0.0348364,-0.025990527,-0.05463735,-0.011152749,0.037878823,0.010120177,-0.045862693,-0.003580413,-0.001128997,0.035175666,-0.002146323,-0.057121817,-0.005865438,0.017845454,0.024557253,-0.006104143,0.04034888,0.014203274,-0.000534965,0.02841904,0.000960799,-0.014855077,-0.025127184,0.048206836,-0.011327933,-0.004201645,-0.009343815,0.020952595,-0.019234773,0.025743721,0.035688285,0.03938878,-0.004572516,-0.01942614,0.005181784,-0.