INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5e1f2a3-b4c5-4d6e-b7a8-b9c0d1e2f3a4', 'You acknowledge that the Services are provided on an ''AS IS'' and ''AS AVAILABLE'' basis. The Company expressly disclaims all warranties of any kind, whether express, implied, or statutory, including but not limited to the implied warranties of merchantability, fitness for a particular purpose, title, and non-infringement. The Company makes no warranty that the Services will meet your requirements, be available on an uninterrupted, timely, secure, or error-free basis, or that any defects will be corrected. No advice or information, whether oral or written, obtained by you from the Company shall create any warranty not expressly stated herein.', 'liability_waiver', '["tos"]'::jsonb, 'yellow', 'This disclaims every possible warranty, meaning the company promises absolutely nothing about the quality, security, or reliability of what you''re paying for. Even if the service is riddled with security holes that expose your data, they''ve disclaimed all responsibility. For a paid service, providing zero guarantees about basic functionality is heavily one-sided.', 'The Services are provided ''as is'' with respect to features not yet generally available (e.g., beta features). For generally available Services, we warrant that we will provide the Services with reasonable skill and care and in accordance with the applicable service description. We warrant that the Services will perform substantially in accordance with the documentation. This does not affect your statutory rights as a consumer.', 'EU Consumer Sales Directive (1999/44/EC) and its successor (Directive 2019/771) impose conformity requirements that cannot be waived. UK CRA 2015 Sections 49-52 imply terms of satisfactory quality and fitness for purpose into service contracts. US UCC Article 2 implied warrantie