INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-6004-4a00-b000-000000000031', 'Landlord shall not be liable for any damage to Tenant''s personal property caused by water leaks, flooding, burst pipes, sewage backup, fire, or any other occurrence in the Premises or building, regardless of cause.', 'liability_waiver', '["lease"]'::jsonb, 'yellow', 'While landlords are not insurers of your belongings, a blanket ''regardless of cause'' waiver means the landlord has no liability even if they caused the problem -- for instance, by neglecting to repair a known leaking pipe that eventually floods your apartment and destroys your furniture. This removes any incentive for the landlord to fix known problems that could damage your property. Renter''s insurance is advisable, but it should not be a substitute for the landlord maintaining the property.', 'Landlord shall not be liable for damage to Tenant''s personal property caused by events beyond Landlord''s reasonable control, provided Landlord has maintained all building systems in good working order. Landlord shall be liable for damage to Tenant''s personal property caused by Landlord''s negligence in maintaining the Premises, including failure to repair known defects. Tenant is encouraged to obtain renter''s insurance for additional protection.', 'Restatement (Second) of Torts Section 357 establishes landlord liability for defects landlord is obligated to repair. California Civil Code Section 1714 imposes general duty of reasonable care. UK Landlord and Tenant Act 1985 Section 11 makes landlord responsible for keeping installations in repair; breach creating liability for consequential damage. EU Directive 93/13/EEC Annex paragraph (b) prohibits inappropriately limiting consumer legal rights.', '[-0.013610183,0.03564855,0.00197322,0.02655876,-0.004272273,-0.038503725,-0.016923333,0.08200819,0.025