INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5c9d0e1-f2a3-4b4c-95e6-f7a8b9c0d1e2', 'You agree to indemnify, defend, and hold harmless the Company, its affiliates, officers, directors, employees, agents, licensors, and suppliers from and against all claims, losses, expenses, damages, and costs, including reasonable attorneys'' fees, arising out of or relating to your use of the Services, your violation of these Terms, or your violation of any rights of a third party. The Company reserves the right to assume the exclusive defense and control of any matter otherwise subject to indemnification by you, and you agree to cooperate with the Company''s defense of such claims.', 'liability_waiver', '["tos"]'::jsonb, 'yellow', 'Indemnification means you promise to pay the company''s legal costs if someone sues them because of something you did. While reasonable in some cases, this version is extremely broad: it covers anything ''relating to your use of the Services,'' which could include situations caused by the company''s own defects. The company also gets to take over your legal defense, meaning they control the strategy and you just pay.', 'You agree to indemnify the Company against claims arising directly from (a) your willful violation of these Terms, or (b) your infringement of a third party''s intellectual property rights through content you upload. This indemnification does not apply to claims arising from the Company''s negligence, defects in the Services, or the Company''s violation of applicable law. Each party shall bear its own legal costs unless a court orders otherwise.', 'EU Unfair Contract Terms Directive Annex 1(b) flags terms inappropriately excluding or limiting consumer rights. UK CRA 2015 Section 62 requires terms to be fair; one-sided indemnification clauses may fail the fairness test. Under US law, broad consumer indemnification clauses may be unconscionable per Restatement (Second) of Contracts Section 208.', '[-0.028742502,0.009263058,-0.011232704,0.010480198,-0.057136733,0.002000883,-0.032878987,-0.045050215,0.022658342,0.003843135,-0.013027565,-0.03007463,-0.022346666,-0.06591191,-0.001576069,-0.022837162,0.008623462,-0.019017896,0.000962405,0.050863154,-0.045385826,-0.043158893,-0.036962222,0.005241666,0.012999194,0.006236885,0.074619725,0.019019216,-0.019568473,0.025373891,0.004019833,-0.03217147,-0.009809552,-0.03494891,0.011208176,0.018315986,-0.000962356,0.014289086,5.4572e-05,0.006466766,0.037739176,-0.000390713,0.015160295,0.018137662,-0.004624005,-0.011765225,-0.037860133,0.054972485,0.03077904,-0.04406567,0.040964168,-0.04095088,-0.01525862,0.030773368,-0.041469112,-0.01268773,0.036051966,0.040026095,-0.017979536,0.039554864,0.03361542,0.009868604,-0.023459092,-0.018517172,0.04046907,-0.033404782,-0.048871424,0.028114174,0.023291185,-0.031136401,0.029399356,0.017653814,0.010346695,0.04345898,-0.008365021,-0.01678106,0.004276149,-0.014097692,-0.008496942,0.010220189,-0.028724713,0.02207995,-0.05791962,-0.038503,-0.006049984,-0.042362027,0.021214461,0.034176897,0.001861314,0.037432414,-0.009037681,-0.002253201,0.026244974,-0.04879837,-0.019831711,-0.005654322,0.027177619,0.005681888,-0.013000534,0.004922942,0.015968023,0.014169338,-0.012074254,0.0534856,0.04322055,0.001533282,-0.022486782,-0.019471172,-0.003332265,0.054751325,-0.042125553,0.001771644,0.024062132,0.041752104,0.053594954,0.010274623,-0.05476923,-0.015269449,0.03365221,-0.012813396,-0.06327955,-0.006082466,0.016872622,0.032379027,0.007690467,0.016453724,-0.009303702,-0.075235374,0.020847274,0.05395764,0.049994335,0.014313741,-0.020573923,0.020035278,0.006100649,0.04703831,-0.002687146,0.01864698,0.001272439,-0.00212022,-0.03563792,0.010687454,0.03530704,0.052430958,0.009190631,-0.004902085,0.006389178,0.002904771,0.03119797,-0.011375207,0.022886835,-0.062029403,0.011016118,0.022144604,0.007662088,-0.052802585,-0.02