INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-5001-4a00-a000-000000000023', 'Tenant shall be solely responsible for all repairs, maintenance, and upkeep of the Premises, including but not limited to plumbing, electrical systems, HVAC, structural components, the roof, and all appliances provided by Landlord, regardless of the cause of damage or deterioration.', 'maintenance', '["lease"]'::jsonb, 'red', 'Making you responsible for the roof, plumbing, electrical, HVAC, and structural elements is shifting the landlord''s core legal obligations onto you. These are the building''s major systems that can cost thousands to repair. The implied warranty of habitability -- a fundamental principle in landlord-tenant law -- requires landlords to maintain the property in livable condition, including working plumbing, heating, and a weatherproof structure. You cannot legally waive this in most jurisdictions.', 'Landlord shall be responsible for maintaining the structural integrity of the Premises, including the roof, foundation, exterior walls, plumbing, electrical systems, and HVAC. Landlord shall maintain all appliances provided at lease commencement in working order. Tenant shall be responsible for routine minor upkeep, including changing light bulbs, maintaining cleanliness, and promptly reporting any maintenance issues to Landlord.', 'Javins v. First National Realty Corp., 428 F.2d 1071 (D.C. Cir. 1970) established the implied warranty of habitability. Green v. Superior Court, 10 Cal.3d 616 (1974) held warranty cannot be waived. UK Landlord and Tenant Act 1985 Sections 11-14 impose repairing obligations on landlords for short leases. EU Directive 93/13/EEC Annex paragraph (b) prohibits terms inappropriately excluding consumer legal rights.', '[-0.024890725,0.038182717,-0.038613588,-0.039487883,-0.006753973,0.000546687,-0.020017179,0.021839656,0