INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-5004-4a00-b000-000000000026', 'Tenant acknowledges that the Premises are accepted in ''as-is'' condition and that Landlord makes no warranty or representation as to the fitness, condition, or suitability of the Premises for residential habitation.', 'maintenance', '["lease"]'::jsonb, 'red', 'An ''as-is'' clause in a residential lease tries to make you accept whatever condition the property is in, including code violations and health hazards. Unlike buying a car, where ''as-is'' may be valid, residential leases come with an implied warranty of habitability that cannot be disclaimed. This clause attempts to shift all risk to you from day one -- if the plumbing does not work when you move in, the landlord could argue you accepted it.', 'Prior to the commencement of the lease term, Landlord and Tenant shall conduct a joint walk-through inspection and document the condition of the Premises in a written move-in checklist signed by both parties. Landlord warrants that at commencement of the lease, the Premises shall comply with all applicable building and housing codes and shall be fit for residential habitation.', 'Green v. Superior Court, 10 Cal.3d 616 (1974) held ''as-is'' clauses cannot waive implied warranty of habitability in residential leases. Knight v. Hallsthammar, 29 Cal.3d 46 (1981) reinforced that waiver is void as against public policy. UK Landlord and Tenant Act 1985 Section 11 obligations are non-excludable for short residential leases. EU Directive 93/13/EEC Annex paragraph (b) prohibits limiting consumer''s legal rights.', '[-0.060030904,0.014487158,-0.038420543,0.001867823,-0.0700724,-0.07506299,-0.039779678,0.052562006,0.04284625,0.023995511,-0.001490174,-0.028742256,-0.032812826,-0.019763902,0.016513271,0.04209233,0.011276298,0.016599625,0.011916528,0.024761781,0.011200168,0.