INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-5002-4a00-8000-000000000024', 'Landlord shall not be liable for any failure to maintain the Premises in a habitable condition. Tenant expressly waives any and all claims arising from conditions of the Premises, including but not limited to mold, pest infestation, lead paint, lack of heat or hot water, or any health or safety hazard.', 'maintenance', '["lease"]'::jsonb, 'red', 'This asks you to waive your right to a safe, livable home. The implied warranty of habitability is a legal protection that exists specifically because housing is a basic necessity, not a luxury -- courts have ruled it cannot be waived by contract. Mold, lead paint, pest infestations, and lack of heat are serious health hazards. A clause that says ''live with toxic conditions and you cannot sue'' is unconscionable and unenforceable in virtually every jurisdiction.', 'Landlord warrants that the Premises shall be maintained in a habitable condition in compliance with all applicable building, health, and safety codes. Landlord shall address any conditions affecting habitability, including mold, pest infestation, plumbing failures, or heating deficiencies, within 72 hours of receiving written notice from Tenant, or immediately in cases posing an imminent health or safety risk.', 'Javins v. First National Realty Corp., 428 F.2d 1071 (D.C. Cir. 1970) and Green v. Superior Court, 10 Cal.3d 616 (1974) established that the warranty of habitability cannot be waived. New York Multiple Dwelling Law Section 78 requires habitability. UK Landlord and Tenant Act 1985 Section 11 imposes non-excludable repair obligations. UK Homes (Fitness for Human Habitation) Act 2018 provides tenants with remedies for unfit dwellings.', '[-0.045166075,0.01854316,-0.020296473,-0.014300017,-0.042752363,-0.05405766,-0.04811167,0.010956585,0.012572579,0