INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-5005-4a00-9000-000000000027', 'Tenant shall be responsible for pest control, including treatment for rodents, insects, bed bugs, and any other vermin, at Tenant''s sole expense, regardless of whether the infestation existed prior to Tenant''s occupancy or originates from common areas or adjacent units.', 'maintenance', '["lease"]'::jsonb, 'yellow', 'Bed bug and pest treatments can cost hundreds to thousands of dollars. Making you pay for infestations that existed before you moved in, or that come from other units or common areas you do not control, is unfair. If roaches are coming through shared walls from a neighboring apartment, that is a building-wide problem the landlord must address. Many cities have specific bed bug laws placing the burden on landlords for pre-existing and building-wide infestations.', 'Landlord shall be responsible for pest control in common areas and for addressing infestations that pre-date Tenant''s occupancy or that originate from building common areas or adjacent units. Tenant shall promptly notify Landlord of any pest sightings. Tenant shall be responsible for pest control only where the infestation is demonstrably caused by Tenant''s actions or negligence, as determined by a licensed pest control professional.', 'New York City Housing Maintenance Code Section 27-2018 requires landlords to keep premises pest-free. Chicago RLTO Section 5-12-110 places bed bug treatment obligations on landlords. California Civil Code Section 1942.5 prohibits retaliation against tenants who report habitability issues including infestations. UK Housing Health and Safety Rating System (HHSRS) identifies pest infestation as a Category 1 hazard requiring landlord action.', '[-0.009218916,0.04994576,-0.038486384,-0.046395313,-0.003612407,-0.045187883,-0.05471938,-0.019888137,0.0144988