INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-5003-4a00-9a00-000000000025', 'Tenant shall notify Landlord in writing of any needed repairs. Landlord shall have a reasonable time to complete repairs, which the parties agree shall be no less than 90 days from receipt of Tenant''s written notice.', 'maintenance', '["lease"]'::jsonb, 'yellow', 'Ninety days is an unreasonably long time to wait for repairs. If your heating breaks in December, this clause says the landlord has until March to fix it. While ''reasonable time'' is the standard, pre-defining it as three months guts the meaning of ''reasonable.'' Emergency repairs (burst pipes, no heat, electrical hazards) need to be addressed in hours or days, not months. This clause gives the landlord a shield against habitability complaints.', 'Tenant shall notify Landlord in writing of any needed repairs. Landlord shall respond to repair requests within the following timeframes: (a) emergency repairs affecting health, safety, or habitability within 24 hours; (b) urgent repairs affecting major systems within 7 days; (c) non-urgent repairs within 30 days. If Landlord fails to complete repairs within these timeframes, Tenant may arrange for repairs and deduct the reasonable cost from rent, upon providing 14 days'' additional written notice.', 'California Civil Code Section 1942 grants tenants repair and deduct remedies after 30 days of landlord inaction. Wisconsin Statutes Section 704.07(4) gives landlords a reasonable time but courts interpret this as days for health/safety issues. UK Landlord and Tenant Act 1985 Section 11 requires repairs within a reasonable period; Sheldon v. West Bromwich Corporation [1973] established that emergency repairs must be prompt.', '[-0.029125283,0.033931505,-0.055318665,-0.074825846,-0.007783225,-0.04143156,0.005525127,-0.039090592,0.054283302,0.014512468,0.0122