INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4c3d4e5-6f7a-4b8c-8d1e-2f3a4b5c6d7e', 'The Employee acknowledges and agrees that during the period of employment and for eighteen (18) months following the date of termination, the Employee shall not, directly or indirectly, engage in any business activity that is competitive with any product or service offered, under development, or planned by the Company or any of its affiliates, subsidiaries, or parent companies.', 'non_compete', '["employment"]'::jsonb, 'red', 'This clause extends the non-compete to cover not just the company itself but all of its affiliates, subsidiaries, and parent companies. If you work for a subsidiary of a large conglomerate, you could be locked out of dozens of industries. The inclusion of products ''under development or planned'' is especially problematic because it covers things that may never launch and that you may know nothing about. This makes it nearly impossible to know whether a future job would violate the restriction.', 'For a period of six (6) months following the date of termination, the Employee shall not accept employment in a role substantially similar to the Employee''s role at the Company with any business entity identified on the Company''s direct competitor list (Schedule B), which shall be limited to no more than ten (10) named entities and updated no more than once per year by mutual written agreement. This restriction applies only to products and services the Employee worked on directly.', 'California Business & Professions Code section 16600 prohibits non-competes regardless of scope. Under Restatement (Second) of Contracts section 188, extending restrictions to affiliates and planned products is likely unreasonable as it exceeds legitimate protectable interests. The UK Supreme Court in Egon Zehnder Ltd v Tillman [2019] UKSC 32 held that non-competes must be no wider than reasonably necessary. FTC 2024 Non-Compete Rule commentary specifically criticized affiliate-extension clauses.', '[0.009452911,0.000897496,0.001530522,0.03275508,-0.058501028,0.039400857,-0.016339578,0.008357778,-0.013889204,0.06298089,-0.031920023,0.0162614,-0.042228207,0.002673525,0.00019427,-0.005369678,-0.003088519,0.03973913,-0.011795754,0.03674442,-0.03053054,0.024122495,-0.03499455,0.006620564,0.00866162,-0.01733396,0.015819602,0.041595973,0.000648284,0.03669088,0.02596341,-0.005658407,-0.00754959,-0.01807664,0.002884985,-0.013132157,0.051885318,-0.006675181,0.022530291,0.02205629,0.002548276,0.05541147,0.029906143,-0.023917602,-0.033654574,-0.00236625,0.002231745,0.03695481,-0.006593342,0.07359027,0.0431802,-0.030474002,-0.059276633,0.023894878,-0.011753029,-0.029386044,0.019282172,0.083185785,-0.006302224,0.015107418,0.05473904,-0.026949862,-0.039392084,0.0498318,-0.037916493,-0.031853013,0.052677304,-0.019611122,0.000921613,0.020229217,0.10634887,0.028914696,-0.022704188,0.003846527,-0.008447676,0.012971063,-0.04216862,0.05439676,0.037705984,-0.000159624,-0.0705564,-0.022384208,-0.002813639,-0.002507564,-0.07427934,0.001610882,-0.019122155,-0.013736477,0.036042754,0.05542384,0.026112484,-0.052232563,0.044035938,-0.05016244,0.025681801,-0.005628505,-0.014040325,-0.019346433,-0.012320435,0.027878106,-0.002625936,0.012126312,0.023236409,0.00264196,0.067889184,-0.004504862,-0.009335459,-0.009147677,0.04362885,-0.003230749,0.008700883,-0.008185327,-0.021488504,0.01502639,0.016420234,-0.011194482,-0.067741804,-0.026985211,0.032658048,0.030826535,0.011911497,0.046343382,0.001894061,-0.027040636,-0.049850926,0.028228113,-0.017949762,-0.013944171,-0.007573853,0.031725634,0.015489819,-0.006033863,-0.040149614,0.024321703,-0.003209115,0.016343294,0.026476039,0.009876185,0.006835151,-0.025218185,0.0171299,0.024066925,0.034077257,0.020582004,-0.001024619,0.002837408,0.003226674,-0.02871562,-0.036844112,-0.03450935,-0.021633998,-0.037166532,-0