INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2919293-9495-4697-8899-9a9b9c9d9e9f', 'Contractor acknowledges that the skills, techniques, and professional knowledge gained during the performance of Services are proprietary to Client. Contractor shall not use such skills, techniques, or knowledge in any subsequent engagement for a period of twelve (12) months.', 'non_compete', '["freelance"]'::jsonb, 'red', 'This claims your general professional skills and knowledge belong to the client. Skills you bring to a project -- and naturally develop further during it -- are yours. A clause preventing you from using your own skills for a year is an extreme restraint on your ability to earn a living. Courts almost universally reject this.', 'Contractor shall not use or disclose Client''s specific trade secrets or proprietary business information in subsequent engagements. Contractor is free to use general skills, professional knowledge, and techniques in any future work.', 'Courts consistently distinguish between protectable trade secrets and general skill/knowledge. In Faccenda Chicken Ltd v Fowler [1987] (UK), the Court of Appeal held that general skill and knowledge gained during employment cannot be restricted. Restatement (Second) of Contracts Section 188 comment d notes that restraints on use of general skill are unreasonable. California Business and Professions Code Section 16600 voids such restrictions.', '[-0.012233571,-0.016431667,-0.057014603,-0.005469947,-0.041455764,-0.003920455,-0.022927923,0.001729303,-0.051433057,0.012007787,-0.04716522,-0.018023608,-0.032893345,-0.014046125,0.04200529,-0.022646632,-0.040938556,-0.0759256,-0.000579832,0.020136356,-0.040154576,-0.030915134,-0.07794589,0.011409114,0.027845293,-0.007273217,-0.018881926,0.098077476,-0.04327987,0.033154745,0.011466085,-0.011405634,-0.033013314,-0.029290501,0.00588771,-0.00156