INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2616263-6465-4667-8869-6a6b6c6d6e6f', 'Contractor agrees that for a period of twenty-four (24) months following the termination of this Agreement, Contractor shall not directly or indirectly provide services that are the same as or substantially similar to the Services to any person or entity within the industry in which Client operates, worldwide.', 'non_compete', '["freelance"]'::jsonb, 'red', 'This bans you from doing similar work for ANYONE in the client''s entire industry, ANYWHERE in the world, for two years. If you''re a web developer who built an e-commerce site, you couldn''t build any e-commerce site for any company on Earth for 24 months. This effectively prevents you from earning a living using your skills.', 'Contractor agrees that for a period of six (6) months following the termination of this Agreement, Contractor shall not provide services directly to the specific clients of Client listed in Exhibit A who were introduced to Contractor through this engagement. This restriction does not prevent Contractor from providing services to other entities in Client''s industry.', 'California Business and Professions Code Section 16600 voids non-compete clauses for independent contractors almost entirely. Under Restatement (Second) of Contracts Section 188, a restraint on trade is unreasonable if broader than needed to protect the promisee''s legitimate interest. UK courts apply a reasonableness test (Nordenfelt v Maxim Nordenfelt [1894]) and 24-month worldwide bans on contractors are almost certainly unenforceable. The FTC''s 2024 Non-Compete Rule (if in effect) bans most non-competes.', '[-0.019069184,-0.011838553,-0.06140146,0.031556908,-0.02321798,0.00144879,0.009887958,0.004432421,-0.031424176,0.003094867,-0.0363179,-0.022998203,-0.038578738,-0.03446714,0.006873512,0.013112918,-0.0192740