INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4a1b2c3-4d5e-4f6a-8b9c-0d1e2f3a4b5c', 'The Employee agrees that during the term of employment and for a period of twenty-four (24) months following termination for any reason, the Employee shall not, directly or indirectly, engage in, be employed by, consult for, or have any ownership interest in any business that competes with, or is substantially similar to, the business of the Company, anywhere in the world.', 'non_compete', '["employment"]'::jsonb, 'red', 'This clause bans you from working in your entire industry, anywhere on the planet, for two full years after leaving. A non-compete this broad is essentially a professional death sentence -- you cannot earn a living in your field. Courts in California, North Dakota, and Oklahoma refuse to enforce non-competes entirely. The FTC''s 2024 rule (currently enjoined) signaled federal intent to ban most non-competes. Even in states that allow them, courts routinely strike down clauses with no geographic limit and excessive duration.', 'The Employee agrees that for a period of six (6) months following the termination of employment, the Employee shall not be employed by or provide services to the specific companies listed in Schedule A (to be updated by mutual agreement no more than annually), within a fifty (50) mile radius of the Employee''s primary office location. The Company shall pay the Employee their base salary during the restricted period as garden leave compensation.', 'California Business & Professions Code section 16600 voids non-competes entirely. The FTC''s 2024 Non-Compete Clause Rule (16 CFR Part 910) attempted a near-total ban; currently enjoined by Ryan LLC v. FTC (N.D. Tex. 2024). Restatement (Second) of Contracts section 188 requires restraints be reasonable in time, geography, and scope. UK law treats unreasonable restraints as void under common law restraint of trade doctrine. EU Directive 2019/1152 Article 9 limits non-competes to cases where justified and requires compensation.', '[0.00075328,0.012681128,-0.005721393,0.027853454,-0.036100466,0.022128277,0.009071605,0.0331425,-0.005492201,0.05521984,-0.02230382,-0.012810147,-0.025116015,-0.006593418,-0.010329561,-0.002349147,0.029736998,0.032385837,-0.007229743,0.02466586,-0.03350216,0.016761778,-0.030141246,0.027509049,0.012863038,-0.030640822,0.025460085,0.028066952,-0.021765484,0.014268047,0.06711126,-0.005377472,-0.019544933,0.004935082,0.026707727,-0.015878893,0.05809077,-0.019643564,0.003260914,-0.001000097,0.019070214,0.06744131,0.045525372,-0.034997597,-0.013834353,-0.01992576,0.008470693,0.025061587,-0.002050646,0.040704034,0.029908977,-0.005211238,-0.08389868,0.03560549,-0.004450387,-0.003733744,0.008725716,0.07624672,0.008505057,0.037757244,0.04506435,-0.006473624,-0.028527454,0.05208506,-0.053470604,-0.0401357,0.037969634,-0.021718835,-0.006661947,0.01867369,0.08097011,0.03350805,0.007553551,0.024595374,-0.032590423,0.015546513,-0.06717939,0.023612456,0.04080763,0.015712513,-0.09829363,-0.05531039,-0.017000785,0.036632266,-0.045680076,0.007655413,0.001915404,-0.017257163,0.034778606,0.06008666,0.007152078,-0.03419092,0.05050718,-0.05432594,-0.00171475,-0.020775314,-0.009138137,-0.0047782,-0.000790293,0.03234337,-0.004992357,0.018053846,0.017430365,-0.0389674,0.053962898,0.012515406,-0.011937756,-0.052884374,0.05947325,0.01821485,0.02185841,-0.035358,-0.013725372,0.013327711,0.014790135,-0.006426361,-0.03913437,-0.02219467,0.04206714,0.034400817,-0.008682655,0.028826311,-0.004209479,0.010744211,-0.039061744,0.02862011,-0.013334583,-0.012639969,-0.005741463,0.015762711,0.036260832,0.036119916,-0.034615196,0.044198647,-0.01894491,0.049922302,0.038020708,0.016127193,-0.019396534,-0.024658572,0.02717459,0.005665832,0.04759203,0.01468792,-0.011389826,0.008759574,-0.032316476,-0.023910927,-0.032692026,0.000804019,-0.004062396,-0.00296