3866,0.123292774,-0.044500183,-0.023627888,-0.001240218,0.0066152,-0.020872917,-0.013975845,0.010454146,-0.08037915,-0.008207318,-0.008399618,-0.048616886,-0.015249014,0.046883747,-0.020138241,0.005427044,-0.02827448,0.003814992,-0.054653343,0.015241019,0.025075639,0.02239844,-0.026000302,-0.01814314,0.000965506,0.00398631,0.003046176,0.044538062,-0.033316437,0.014978749,-0.01129414,-0.003838796,0.009449122,-0.06400194,-0.037890766,0.07594402,-0.013366709,0.043636523,0.028868197,0.002126893,0.018965663,-0.010974254,-0.080426365,-0.03448963,-0.035823286,-0.04113918,0.015809681,-0.07018524,-0.013914274,0.029364716,-0.003005391,0.037741087,0.03548556,0.008889201]'::vector, '2026-03-14T19:51:47.730Z');
INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4e5f6a7-8b9c-4d0e-af3a-4b5c6d7e8f9a', 'The Company shall not be required to provide any compensation, payment, or other consideration to the Employee during the non-competition period following termination. The Employee acknowledges that the consideration received during the term of employment, including salary and access to confidential information, constitutes sufficient consideration for the post-employment restrictions set forth herein.', 'non_compete', '["employment"]'::jsonb, 'red', 'This clause says you get zero pay while being banned from working in your field after leaving. You are expected to survive with no income while honoring the non-compete. Many jurisdictions now require employers to pay employees during a non-compete restriction period (called ''garden leave''). Without compensation, courts are far more likely to void the non-compete as unconscionable -- meaning grossly unfair and one-sided.', 'During the non-competition period following termination, the Company shall pay the Employee a monthly sum equal to one hundred percent (100%) of the Employee''s base monthly salary at the time of termination (''Garden Leave Payment''). The Employee may terminate the non-competition obligations at any time upon thirty (30) days'' written notice if the Company fails to make a Garden Leave Payment when due.', 'EU Directive 2019/1152 Article 9(2) requires adequate compensation for post-employment non-compete periods. Germany requires at least 50% of the employee''s last compensation (section 74 HGB). Italy''s Civil Code Article 2125 requires adequate consideration proportional to the restriction. Massachusetts Noncompetition Agreement Act (2018) requires garden leave pay of at least 50% of base salary. Restatement (Second) of Contracts section 208 treats clauses imposing obligations without corresponding consideration as potentially unconscionable.', '[-0.025249122,0.030845497,0.005832615,0.01180429,-0.012876121,-0.008083112,-0.011379111,0.035929583,-0.018811727,0.016036052,-0.021474835,-0.00817591,-0.04913947,-0.05838274,0.03930529,-0.017200638,0.019326944,0.019745123,-0.044479832,-0.019453447,0.001311343,0.02000207,0.013316146,-0.004692769,0.013066029,-0.05654982,-0.06419232,0.019460779,0.002516459,0.02888827,0.037316866,-0.034004387,-0.038644716,-0.034760486,0.00019479,-0.020310998,0.010033534,0.003474111,0.000647044,-0.006410176,-0.012185862,0.06346779,0.04830517,0.016264915,-0.006054503,-0.019156097,-0.015464052,0.013558826,-0.050816234,0.024326254,0.013444148,-0.031129805,-0.040642187,0.019643897,-0.037486125,-0.08717613,0.058977645,0.050762415,-0.0165199,-0.015382282,0.074899495,-0.012507696,-0.041420504,0.002538272,-0.032883607,-0.008920214,0.022307668,-0.042015642,-0.015791342,-0.019253314,0.05149122,0.025885224,-0.016694259,0.02765781,0.010585249,-0.04039648,-0.012755202,0.068315394,0.002927989,0.021485144,-0.001365486,-0.020607317,-0.04948237,0.034666583,-0.027467787,0.021742143,-0.015135553,-0.002988564,0.021678545,0.057433065,0.03474458,-0.059524562,0.010498936,-0.044855975,0.014080835,0.030398462,-0.024173876,0.009200709,-0.005353214,0.037060585,-0.034544405,0.029646724,0.028813,-0.021725578,0.017988669,0.03929842,0.009170993,0.003560323,0.041467067,0.015226102,0.04829786,-0.032771282,0.017556403,0.002441183,0.02673435,-0.03840346,-0.023151811,-0.02315014,-0.003282736,0.010024684,0.000793131,-0.005825975,-0.011675394,-0.005587223,-0.06532052,0.008585987,0.009493982,-0.019912513,-0.02007755,0.005227673,0.017886048,0.030825526,-0.015800778,0.007954593,-0.03333864,0.034673538,-0.003990677,0.02538339,0.002394534,0.00855446,0.03695267,0.003255145,-0.018392779,0.005265745,-0.04363784,0.000489885,0.003711248,-0.00213367,-0.001582643,-0.043148834,-0.047491472,-0.03509088,0.014752579,0.019469488,0.04809163,-0.017710213,0.005426234,-0.032443266,0.0043