INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4d4e5f6-7a8b-4c9d-9e2f-3a4b5c6d7e8f', 'The Employee agrees that, during the Restricted Period, the Employee shall not, without the written consent of the Company, directly or indirectly contact, communicate with, or maintain any professional or social relationship with any person who is or was employed by, or engaged as a contractor by, the Company at any time during the two (2) years preceding the Employee''s termination.', 'non_compete', '["employment"]'::jsonb, 'red', 'This clause prevents you from maintaining any contact, including social relationships, with every current or former colleague from the past two years. This goes far beyond protecting trade secrets -- it isolates you from your professional network and even personal friendships formed at work. Courts increasingly view restrictions on social contact as an unreasonable restraint on personal liberty, and the NLRA protects workers'' rights to communicate with each other about working conditions.', 'For a period of six (6) months following termination, the Employee shall not directly recruit or solicit for employment any employee of the Company who holds a senior or managerial position and with whom the Employee worked directly during the final twelve (12) months of employment. This restriction does not limit personal or social contact or communications regarding working conditions.', 'US National Labor Relations Act section 7 protects employees'' rights to engage in concerted activity, including communicating with former colleagues about workplace conditions. UK courts in TFS Derivatives Ltd v Morgan [2004] EWHC 3181 (QB) held that non-solicitation of employees must be limited to those the employee actually worked with. Restatement (Second) of Contracts section 188 would likely find a blanket social contact ban unreasonable.', '[0.0173