INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2717273-7475-4677-8879-7a7b7c7d7e7f', 'During the term of this Agreement and for twelve (12) months thereafter, Contractor shall not provide services to any entity that competes with Client or any of Client''s affiliates, subsidiaries, or parent companies in any market in which Client or its affiliates conduct business.', 'non_compete', '["freelance"]'::jsonb, 'red', 'This extends the non-compete to all of the client''s parent companies, subsidiaries, and affiliates. If the client is part of a large corporate group, this could cover dozens of industries. The restriction applies to any market they operate in, which for a conglomerate could be virtually everything. A freelancer has no way to even know all the affiliates.', 'During the term of this Agreement, Contractor shall not provide services to entities listed in Exhibit B (Client''s Direct Competitors), limited to no more than five (5) named entities. This restriction expires upon termination of this Agreement.', 'Restatement (Second) of Contracts Section 188 requires that restraints protect only a ''legitimate interest'' and be no broader than necessary. Courts in the UK (TFS Derivatives Ltd v Morgan [2005]) have found non-competes covering affiliates overly broad. EU Directive 93/13/EEC Article 3(1) tests for significant imbalance in obligations. California Business and Professions Code Section 16600 would void this entirely.', '[0.003226209,-0.015814688,-0.01260299,0.00488736,-0.06837872,-0.002242366,-0.009823888,-0.006686407,-0.036675226,0.026842203,-0.049581476,-0.027899431,-0.040707536,-0.011605685,0.005489301,0.014992503,-0.035185702,-0.030721702,0.006109868,0.007214542,-0.04889618,-0.020620774,-0.034255695,-0.001791659,0.000346637,-0.008450216,0.04399135,0.0499765,-0.028721094,-0.004282568,0.01742884,-0.022616796,-0.006347775,-0.0298869