INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2818283-8485-4687-8889-8a8b8c8d8e8f', 'Contractor shall not, for a period of eighteen (18) months following termination, solicit, contact, or provide services to any client, customer, prospect, or lead of Client with whom Client has had any communication or business relationship during the preceding five (5) years.', 'non_compete', '["freelance"]'::jsonb, 'yellow', 'This prevents you from working with anyone the client has ever talked to in the last five years -- not just current clients, but old prospects and leads. ''Any communication'' is incredibly broad: a single cold email from the client to a company five years ago could block you from working with that company. The scope is unknowable to you.', 'Contractor shall not, for a period of six (6) months following termination, directly solicit clients of Client whom Contractor personally served during this engagement. This restriction does not apply to inbound inquiries or to relationships that pre-date this Agreement.', 'Non-solicitation clauses must be reasonable in scope and duration. UK courts in Patsystems Holdings Ltd v Neilly [2012] held that restrictions covering ''prospects'' or ''leads'' are harder to enforce than restrictions on actual clients. Restatement (Second) of Contracts Section 188(1)(a) requires that the restraint be no greater than needed. Five-year lookback periods are generally considered excessive.', '[-0.001875357,-0.03025813,-0.040123675,0.00958258,-0.046024688,0.014925893,-0.006484884,0.014781089,-0.076146245,0.02059493,-0.03707498,-0.029572442,-0.019966282,-0.00356219,0.003629816,0.004134382,-0.027474744,-0.03198298,0.005839955,0.015412157,-0.026156323,-0.012570402,-0.056821752,0.02096439,-0.030755322,-0.030899785,0.016428431,0.053095732,-0.04913471,-0.006758453,0.019660914,-0.0273896,0.00250408,-0.03894269,-0.00726908