INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4b2c3d4-5e6f-4a7b-9c0d-1e2f3a4b5c6d', 'During employment and for a period of twelve (12) months thereafter, the Employee shall not, without the prior written consent of the Company, directly or indirectly solicit, canvass, or approach any person who at any time during the final twenty-four (24) months of employment was a client, customer, or prospective customer of the Company, whether or not the Employee had direct dealings with such person.', 'non_compete', '["employment"]'::jsonb, 'yellow', 'This non-solicitation clause covers every client of the entire company for the past two years, even clients you never worked with and may never have heard of. The phrase ''prospective customer'' is especially dangerous because it could include anyone the company ever pitched to. You could unknowingly violate this simply by taking a job where one of your new employer''s clients happens to overlap with your former company''s prospect list.', 'For a period of six (6) months following the termination of employment, the Employee shall not directly solicit any client or customer of the Company with whom the Employee had material personal dealings during the final twelve (12) months of employment. This restriction does not apply to prospective customers, general advertising, or inbound inquiries initiated by the client.', 'UK courts enforce non-solicitation clauses only where limited to clients with whom the employee had personal dealings (Patsystems Holdings Ltd v Neilly [2012] EWHC 2609). Restatement (Second) of Contracts section 188 requires the restraint be no broader than needed to protect legitimate business interests. US courts in Reliable Fire Equipment Co. v. Arredondo (2011, Illinois) applied a three-factor test requiring the restriction be reasonable in scope.', '[0.014011756,0.00659026,-0.009087374,0.0