INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3f4a5b6-c7d8-4e9f-ba1b-3c4d5e6f7a8b', 'During the term of this Agreement and for a period of eighteen (18) months following its termination, the Receiving Party shall not, directly or indirectly, solicit, contact, or engage in any business transaction with any client, customer, vendor, supplier, or business contact of the Disclosing Party with whom the Receiving Party became acquainted or about whom the Receiving Party obtained information as a result of or in connection with this Agreement.', 'non_solicitation', '["nda"]'::jsonb, 'red', 'This clause bans you from doing business with anyone you learned about through the NDA relationship — not just the other party''s customers, but also their vendors, suppliers, and any ''business contacts.'' For 18 months, you cannot engage in any transaction with these entities. This goes far beyond protecting confidential information and amounts to a non-compete in disguise, potentially cutting you off from a wide swath of an entire industry.', 'The Receiving Party agrees not to use the Disclosing Party''s Confidential Information, including customer or client lists, to directly solicit the Disclosing Party''s existing customers for the purpose of diverting their business during the term of this Agreement. This restriction shall not apply to customers with whom the Receiving Party had a pre-existing business relationship or who independently approach the Receiving Party.', 'US: Overbroad non-solicitation provisions are frequently struck down. Restatement (Second) of Contracts Section 188 — must be no broader than reasonably necessary. See Boulanger v. Dunkin'' Donuts Inc. (overbroad customer non-solicitation struck down). EU: Must be proportionate to a legitimate interest under national law. EU Competition law (TFEU Article 101) may apply to restrictions between businesses. UK: Restraint of trade — scope must be limited to customers with whom the party actually had contact.', '[0.03397902,-0.027667286,-0.04469607,0.036598843,-0.07474517,-0.006460082,-0.03264045,0.026738504,-0.04655263,0.02620381,-0.014353006,-0.050215833,-0.01578007,-0.012381162,-0.012335056,0.022854501,-0.018061986,-0.01809614,0.007102751,0.010520904,-0.010707928,0.000426492,-0.060612507,0.03997555,0.001359089,-0.06514228,0.018901084,0.051753115,-0.03787055,-0.016089415,0.027765457,-0.001909051,0.01280527,-0.005140515,0.034321822,-0.010823615,0.012683067,-0.035891026,0.03687034,0.023420325,0.022720236,0.034065764,-0.01694363,-0.032417115,-0.013956469,-0.021527214,-0.032856993,0.025313664,-0.004271696,0.013258505,0.003885345,-0.003229025,-0.021636665,0.022970645,-0.004358622,-0.003090629,0.03257925,0.017556382,0.002189585,0.00596413,-0.000286498,-0.001997181,-0.007402498,0.04271701,-0.01606106,0.022266094,0.05771403,0.016262868,0.0311779,0.012728608,0.066699654,0.000621965,-0.025628828,-0.008967788,-0.006319735,0.008695595,-0.028503116,0.022138735,0.013148805,-0.040255755,0.000436682,-0.049082506,-0.033083573,0.020691616,-0.029033247,0.030008232,0.059341103,-0.003398432,0.037139047,0.032209292,-0.024019083,-0.06925605,0.057251193,-0.027795827,-0.036820535,-0.04966694,-0.003945121,-0.037419137,-0.049305145,0.015923578,0.014843258,-0.038271863,0.06782936,-0.000755328,0.08094304,0.00696173,0.000684501,-0.047584306,0.040243573,-0.005873015,-0.040545225,0.02953759,0.010511919,0.035053607,0.012629263,-0.010732904,-0.011112289,0.04322415,-0.012841401,0.001393253,0.01205636,0.006905896,-0.03290553,-0.010813502,-0.00475699,0.021876263,-0.026447292,-0.03979194,0.048093714,0.03593608,0.06958694,0.009009297,-0.001064623,0.002131928,0.019172536,0.02297432,0.003021834,0.016231822,0.005334426,-0.029995287,0.03098143,0.008302675,0.04866782,-0.033851445,0.053795096,-0.007655412,0.009498865,-0.014319675,-0.03969582,-0.050026063,0.016872333,-0.020727905,0.01127863,-0.0147942