INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3d2e3f4-a5b6-4c7d-8e9f-1a2b3c4d5e6f', 'During the term of this Agreement and for a period of two (2) years following its termination or expiration, the Receiving Party shall not, directly or indirectly, solicit, recruit, hire, or engage any employee, contractor, consultant, or agent of the Disclosing Party, or induce or attempt to induce any such person to terminate their relationship with the Disclosing Party.', 'non_solicitation', '["nda"]'::jsonb, 'yellow', 'This is a non-solicitation clause hiding inside an NDA. NDAs are supposed to protect confidential information — not prevent you from hiring people. A two-year ban on hiring any employee, contractor, or consultant of the other company is extremely broad and has nothing to do with protecting secrets. It could prevent you from hiring someone who applied to your company independently, or someone you had no idea worked for the other party.', 'During the term of this Agreement and for a period of six (6) months following its termination, neither party shall directly solicit for employment any employee of the other party who was personally involved in the exchange of Confidential Information under this Agreement, provided that this restriction shall not apply to (a) general advertising or recruitment efforts not specifically targeted at such individuals, or (b) any person who independently contacts the hiring party without solicitation.', 'US: Non-solicitation provisions must be reasonable in scope and duration under Restatement (Second) of Contracts Section 188. Several states (California, Oklahoma, North Dakota) severely restrict non-compete/non-solicit agreements under Cal. Bus. & Prof. Code Section 16600. EU: Non-solicitation clauses may violate freedom of labor principles and must be proportionate. UK: Common law restraint of trade — must protect a legitimate business interest and be reasonable in scope.', '[0.024353238,-0.002177946,-0.009204327,0.036918953,-0.06557338,-0.004944725,0.007638752,0.01976065,-0.039332464,0.032747883,-0.02822281,-0.04270837,-0.047894705,-0.007630992,-0.023555418,0.027435891,-0.011476856,-0.016645048,-0.032264695,0.047687918,-0.018458541,0.004011293,-0.05206049,0.053060565,0.030384446,-0.03891727,-0.009350932,0.05365371,-0.042831805,-0.016823625,0.052702077,0.026898699,0.014466302,-0.00050048,0.018696208,-0.028613914,-0.00084346,-0.04743997,0.034536157,-0.001864101,-0.002483103,0.04584411,-0.014373461,-0.040739622,0.015402425,-0.021213477,-0.03801486,0.05269809,-0.01602936,0.00672024,0.04730092,0.017543478,-0.025846343,0.04111367,-0.007687788,0.027754497,0.020392882,0.013398668,0.008238547,0.002038146,0.001465521,-0.038040645,-0.01686174,0.022196522,-0.030201102,0.006262586,0.020475095,-0.010918772,0.007056023,0.01800736,0.04569331,0.013141574,-0.028579025,-0.010324324,0.002518303,-0.006563384,-0.020954717,0.012539499,-0.00131512,-0.024722692,-0.007678481,-0.05341804,-0.012529791,-0.008828667,0.017991714,0.04545289,0.04537411,-0.044813517,0.054739837,0.045037664,0.00611573,-0.049165852,0.013208042,-0.021031676,-0.026336337,-0.07065781,-0.009041574,-0.052055437,-0.020575315,0.047142234,-0.012112075,-0.016131734,0.07612551,0.005082428,0.0626455,0.007194289,-0.01827859,-0.05425942,0.053343542,-0.003349259,-0.004095843,0.005740648,-0.008511261,0.037755944,0.006206882,-0.011460358,-0.025991915,0.014098018,-0.008776221,0.001508461,0.016639968,0.02598743,-0.03149015,-0.003797809,-0.009714202,0.016444607,-0.02007116,-0.024121134,0.021806391,0.04767643,0.07241984,0.006249065,0.009918912,0.031378508,-0.01518536,0.060746368,0.007003028,0.00395922,-0.010623635,-0.03414312,0.020244636,-0.00682109,0.06153015,-0.018469913,0.04227977,-0.015524304,0.0216252,0.013094138,-0.01954433,-0.022676496,-0.016529689,-0.0200197,-0.012493464,0.019976782,0.043214966,-0.036826197,-0.048262842,0.004888478,-