INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2414243-4445-4647-8849-4a4b4c4d4e4f', 'In the event Client terminates this Agreement for any reason, Contractor shall not be entitled to any cancellation fee, kill fee, or compensation for work-in-progress. All partial deliverables shall become the property of Client at no additional cost.', 'payment_terms', '["freelance"]'::jsonb, 'red', 'If the client cancels the project, you get nothing for work already completed -- and they still keep your partial deliverables. You could be weeks into a project, have turned down other work, and walk away with zero compensation while the client uses what you''ve built.', 'In the event of termination for convenience by Client, Contractor shall be compensated for all work completed through the date of termination at the agreed rate, plus a cancellation fee equal to 25% of the remaining contract value. Ownership of partial deliverables transfers to Client only upon payment in full for all completed work.', 'Failure to pay for work performed may constitute unjust enrichment under Restatement (Third) of Restitution Section 1. NYC Freelance Isn''t Free Act (Local Law 140 of 2016) requires payment for all work performed. EU Directive 93/13/EEC Annex paragraph 1(d) flags terms permitting the seller to retain sums where the seller cancels. UK Supply of Goods and Services Act 1982 Section 15 implies a duty to pay a reasonable price.', '[-0.045333568,0.039627895,-0.018280262,-0.020030312,-0.037866935,0.000464859,-0.000844065,0.007458541,-0.038408548,0.025508612,0.010372959,-0.020841952,-0.004137817,-0.05382708,0.03804624,-0.007120021,-0.038513534,-0.024457257,0.042279698,-0.01123672,-0.057166096,-0.031523336,-0.010200545,0.045033,-0.02094546,-0.020197678,-0.021359148,0.074116796,-0.03754634,-0.025611855,0.040506914,-0.02285605,-0.031058058,-0.003217076,-0.017913034,0.0744