INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2515253-5455-4657-8859-5a5b5c5d5e5f', 'Client reserves the right to retroactively adjust the agreed rate for Services if Client determines, in its sole discretion, that the scope of work was less complex than originally anticipated, or that market rates for comparable services have decreased.', 'payment_terms', '["freelance"]'::jsonb, 'red', 'The client can reduce your agreed rate AFTER you''ve done the work, claiming the work was simpler than expected or that ''market rates dropped.'' This makes your income completely unpredictable. You agreed to a rate, did the work, and now the client can unilaterally decide to pay you less.', 'The rate for Services shall be as set forth in the applicable Statement of Work and may only be modified by mutual written agreement of both parties. Any rate changes shall apply prospectively to future work only.', 'Unilateral modification of agreed consideration violates basic contract principles under Restatement (Second) of Contracts Section 73. EU Directive 93/13/EEC Annex paragraph 1(j) and (l) flag terms enabling the supplier to alter contract terms or price unilaterally. UK Consumer Rights Act 2015 Schedule 2 paragraph 11 addresses terms allowing unilateral variation.', '[-0.019025771,0.011577135,-0.047110796,0.001626709,-0.00467297,0.033418316,-0.027666979,0.0354482,-0.0569295,0.018930197,0.003492844,-0.034611944,-0.07354914,-0.019765262,0.042549733,0.006512557,-0.01607288,-0.031202324,0.007809602,0.014908668,-0.032444015,0.03373732,-0.021653716,0.005363184,0.011652212,0.010266175,0.032040868,0.023254935,-0.020877821,0.02741644,0.023172628,-0.020821705,-0.033555612,-0.043178387,0.053304255,0.008356377,0.02494431,0.058877733,-0.028499514,0.048031375,0.06764056,0.037486695,-0.009849784,0.0568216,0.026656562,-0.044885233,-0.069684826,0.052033868,-0.032613263,-0.045