INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2111213-1415-4617-8819-1a1b1c1d1e1f', 'Contractor shall be compensated on a pay-when-paid basis. Client''s obligation to pay Contractor is expressly contingent upon Client receiving payment from its end client for the project in which Contractor''s Services are utilized. In the event Client does not receive payment from the end client, Client shall have no obligation to pay Contractor.', 'payment_terms', '["freelance"]'::jsonb, 'red', 'You only get paid if the client gets paid by THEIR client. You''ve done the work, delivered value, but whether you see any money depends entirely on a business relationship you have no visibility into or control over. The client''s cash flow problems or bad client relationships become your problem.', 'Payment for completed Services shall be due within thirty (30) days of invoice submission, regardless of Client''s receipt of payment from any third party. Client''s obligation to compensate Contractor for accepted deliverables is unconditional.', 'Pay-when-paid clauses have been held unenforceable in many US jurisdictions in construction (e.g., New York Lien Law Section 34), and courts increasingly scrutinize them in service contracts. In the UK, such clauses may be challenged under the Unfair Contract Terms Act 1977 Section 3. EU Directive 93/13/EEC Article 3(1) and Annex paragraph 1(b) address terms that inappropriately exclude or limit the consumer''s legal rights in the event of non-performance.', '[-0.030866856,-0.000959336,-0.009959252,-0.05701224,-0.026262183,-0.001493059,-0.013093333,-0.007130995,-0.024468293,-0.009679972,-0.009295161,-0.035579234,-0.018365266,-0.028775994,0.044833913,-0.01204359,-0.065457635,-0.014664477,0.007452063,0.002738036,-0.003907447,0.046488725,-0.005285292,-0.009026467,0.012908009,-0.041238602,-0.000611017,0.032281887,-0.025742278,0.