INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2313233-3435-4637-8839-3a3b3c3d3e3f', 'Payment for each milestone shall be contingent upon Client''s written approval and acceptance of the deliverable in Client''s sole and absolute discretion. Client shall have unlimited time to review and approve or reject each deliverable, and no payment shall be due until such approval is provided.', 'payment_terms', '["freelance"]'::jsonb, 'red', 'The client can reject your work for any reason (''sole and absolute discretion'') and has unlimited time to review. This means they could use your completed work while endlessly ''reviewing'' it, never formally approving, and never paying you. There''s no objective acceptance criteria you can point to.', 'Client shall review each deliverable within ten (10) business days of submission and provide written approval or specific, actionable feedback for revision. If Client does not respond within ten (10) business days, the deliverable shall be deemed accepted. Acceptance shall not be unreasonably withheld.', 'Clauses granting sole discretion to one party violate the duty of good faith recognized in Restatement (Second) of Contracts Section 205. EU Directive 93/13/EEC Annex paragraph 1(c) flags terms allowing the seller to retain sums paid where the seller dissolves the contract. UK Consumer Rights Act 2015 Schedule 2 paragraph 14 addresses terms giving disproportionate discretion to one party.', '[-0.014515351,-0.010646935,-0.042086072,-0.04958751,-0.083145425,0.010095602,-0.003013998,0.024266347,-0.019677227,0.038846374,-0.004916365,0.015022763,-0.03270277,-0.072367184,0.05856464,0.011817685,-0.06508741,0.009625492,0.012551547,0.042713232,0.001701548,0.017305864,0.031900786,-0.028570853,-0.023682091,-0.05744735,-0.008399867,0.036947183,0.033341013,-0.023277089,-0.007610948,-0.03617153,-0.005315432,0.009871129,-0.0202