INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2212223-2425-4627-8829-2a2b2c2d2e2f', 'No interest, penalties, or late fees shall accrue on any overdue payments. Contractor''s sole remedy for late payment shall be to submit a written request to Client''s accounts payable department, and Contractor agrees to allow an additional sixty (60) day cure period before pursuing any other remedies.', 'payment_terms', '["freelance"]'::jsonb, 'yellow', 'This eliminates any financial consequence for paying you late. Without interest or penalties, the client has zero incentive to pay on time -- your invoice becomes an interest-free loan. The 60-day ''cure period'' on top of already-late payment means you could wait months with no recourse.', 'Overdue payments shall accrue interest at the rate of 1.5% per month or the maximum rate permitted by law, whichever is lower, calculated from the original due date. Contractor may suspend performance of Services upon fifteen (15) days written notice of non-payment.', 'The UK Late Payment of Commercial Debts (Interest) Act 1998 Section 1 gives an automatic statutory right to interest on late commercial payments that cannot be contracted out of (Section 9). EU Late Payment Directive 2011/7/EU Article 7 states that contractual terms excluding interest on late payment are grossly unfair and unenforceable. US Freelance Isn''t Free Act (NYC Admin Code Section 20-928) requires timely payment to freelancers.', '[-0.043357678,-0.017037084,-0.06834254,-0.026329692,-0.06095672,0.022779599,-0.038390525,0.001699007,-0.02015638,0.012426332,0.012943423,-0.048781674,-0.01326302,-0.047050014,0.07133942,-0.02147524,-0.061207656,-0.016789345,0.003434257,-0.01988434,-0.01761162,0.009294484,-0.00873869,-0.003415317,-0.013737044,-0.05693316,-0.003401941,0.05389401,-0.041529637,-0.034490936,-0.023301488,0.021093827,-0.042502433,-0.002918376,