INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-7003-4a00-8000-000000000034', 'Tenant acknowledges that noise from neighboring units, common areas, mechanical systems, and building operations is inherent to apartment living and shall not constitute a breach of the Lease or grounds for rent reduction. Tenant waives any claims for constructive eviction based on noise or disturbance.', 'quiet_enjoyment', '["lease"]'::jsonb, 'yellow', 'While some noise is normal in apartment buildings, this clause tries to preemptively excuse ALL noise, no matter how extreme, including from building operations the landlord controls. The waiver of constructive eviction claims (which is when conditions become so bad you are effectively forced out) means you cannot legally break the lease even if the noise makes the apartment uninhabitable. A landlord who decides to renovate the unit above you with round-the-clock jackhammering would be shielded from liability.', 'Tenant acknowledges that reasonable ambient noise is inherent to multi-unit residential living. However, Landlord shall take reasonable steps to address excessive noise from building operations, construction, or mechanical systems. Landlord shall enforce noise provisions of all tenant leases. Tenant retains the right to seek rent reduction if building-caused noise materially impairs use of the Premises for a continuous period exceeding 48 hours.', 'Reste Realty Corp. v. Cooper, 53 N.J. 444 (1969) established constructive eviction doctrine for conditions rendering premises substantially unsuitable. Barash v. Pennsylvania Terminal Real Estate Corp., 26 N.Y.2d 77 (1970) recognized noise as potential constructive eviction. UK Environmental Protection Act 1990 Sections 79-82 provide statutory nuisance remedies. EU Directive 93/13/EEC Annex paragraph (b) prohibits terms inappropriately excluding consumer legal rights.', '[-0.026777245,0.028266888,-0.058309905,0.033166714,-0.040788837,-0.03473869,0.008277078,-0.03135196,0.056315795,0.028097985,-0.000877097,-0.0279641,0.003927318,-0.023827253,-0.00312281,-0.002934368,-0.018766904,-0.033423983,0.014047699,0.02619726,0.026042106,-0.02100467,-0.02141274,0.03793017,0.012257414,0.012688486,-0.054706115,-0.001539881,-0.038730282,-0.010884808,0.045327906,0.004894757,-0.05787636,0.046386667,0.026444953,-0.005416284,0.077321686,0.00666822,-0.025723187,0.007593725,-0.022591718,0.026907029,-0.008055191,-0.020808,0.005892978,-0.060586274,0.024367398,0.037497327,-0.038121216,-0.01826155,0.021002278,-0.023730261,-0.02393154,0.020108296,0.005609535,-0.054570124,0.03533828,0.012850212,0.005551159,0.04189883,0.019990424,0.013991,-0.021238683,-0.007820835,0.005902991,-0.012621875,-0.013898361,0.031731535,-0.02314904,0.0200724,0.057163622,-0.010459711,0.014783399,0.011406865,0.039563753,-0.01898336,0.02408485,0.053349473,-0.04201752,-0.003019796,-0.025203967,-0.030924547,-0.01139395,0.029578187,-0.017958922,-0.059957094,0.016692908,-0.003701141,-0.009249832,0.043191675,-0.019147443,0.000986292,-0.01916969,0.060193557,0.004131119,-0.07767878,-0.013852227,0.03613311,-0.029713769,0.011279934,-0.006319651,-0.023761736,0.017542552,0.041396998,0.015954092,0.006792459,-0.007312219,-0.025836557,-0.001039846,0.018227588,-0.010791559,-0.03266352,0.009702396,0.008360023,0.018413464,0.017201044,-0.032167625,-0.011123192,0.053957697,-0.007732778,-0.02124035,0.054216806,-0.017183956,-0.001212389,0.000928141,0.055163596,-0.025626488,0.027288843,0.04005263,-0.00984693,-0.002901626,0.015833864,-0.03686091,-0.000548167,0.03978791,0.033886425,0.008168345,-0.023830751,0.001824265,0.008703296,0.01622661,0.01001007,0.054907843,0.011474434,0.010986157,0.014778889,-0.04971782,0.043939054,-0.064566545,0.010308741,0.015972575,-0.033809315,-0.008671314,0.011166105,0.033705667,-0.05730649,-0.011009101,0.010162264,0.006854523,0.011353585,0.017738858,0.028870268,-0.0