INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3b4c5d6-e7f8-4a9b-8c1d-3e4f5a6b7c8d', 'In the event of any breach of this Agreement by the Receiving Party, the Receiving Party shall pay to the Disclosing Party, as liquidated damages and not as a penalty, the sum of Five Hundred Thousand Dollars ($500,000) per occurrence of breach, in addition to any actual damages suffered by the Disclosing Party.', 'remedies', '["nda"]'::jsonb, 'red', 'This clause demands a $500,000 penalty for every single breach occurrence — AND actual damages on top of that. Liquidated damages (pre-agreed amounts) are only enforceable when they reasonably estimate the actual harm caused. A flat $500,000 that applies regardless of whether the breach caused $100 or $1 million of harm is almost certainly an unenforceable penalty. Adding actual damages on top makes it doubly punitive, since liquidated damages are supposed to substitute for actual damages, not stack on top.', 'In the event of a breach of this Agreement, the Disclosing Party shall be entitled to recover its actual, direct damages resulting from such breach, as proven with reasonable certainty. The Receiving Party shall not be liable for consequential, indirect, incidental, or punitive damages.', 'US: Restatement (Second) of Contracts Section 356 — liquidated damages must be reasonable in light of anticipated or actual harm. A term fixing unreasonably large damages is unenforceable as a penalty. UCC Section 2-718(1) similarly requires reasonableness. EU: Unfair Contract Terms Directive 93/13/EEC Annex para. 1(e) — terms requiring disproportionately high compensation are potentially unfair. UK: Cavendish Square Holding BV v. Makdessi [2015] — liquidated damages must not be out of all proportion to the legitimate interest.', '[0.034831785,-0.011423205,-0.060468324,0.024388881,-0.017842293,-0.056351222,-0.000988914,0