INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3a3b4c5-d6e7-4f8a-9b0c-2d3e4f5a6b7c', 'The Receiving Party acknowledges that any breach or threatened breach of this Agreement shall cause irreparable harm to the Disclosing Party for which monetary damages would be inadequate. Accordingly, the Disclosing Party shall be entitled to specific performance and injunctive relief as remedies for any such breach, without the necessity of proving actual damages, posting bond, or other security, and without need to demonstrate irreparable harm.', 'remedies', '["nda"]'::jsonb, 'yellow', 'This clause pre-decides that any breach causes irreparable harm (harm that money can''t fix), and waives the disclosing party''s obligation to actually prove it. Normally, to get an injunction (a court order to stop someone from doing something), you must show the court that you''ll suffer harm that money alone can''t compensate for. This clause tries to skip that proof, AND waives the requirement to post a bond (a deposit that compensates you if the injunction turns out to be wrongful). While courts often grant injunctions in trade secret cases, many refuse to enforce blanket waivers of the bond requirement.', 'Each party acknowledges that a breach of the confidentiality obligations herein may cause irreparable harm for which monetary damages may be an insufficient remedy. Accordingly, the non-breaching party may seek equitable relief, including injunction and specific performance, as a remedy for any such breach, in addition to all other remedies available at law or in equity. The availability of equitable relief shall be determined by the applicable court based on the circumstances at the time relief is sought.', 'US: Federal courts are split on enforceability of advance waivers of bond requirements under FRCP Rule 65(c). Many state courts require proof of irreparable harm regardless of contract language. Restatement (Second) of Contracts Section 208. EU: Directive 2004/48/EC on enforcement of IP rights — injunctions available but subject to proportionality. UK: American Cyanamid Co v. Ethicon Ltd — court retains discretion to assess balance of convenience regardless of contractual provisions.', '[0.008164123,-0.000441098,-0.05452502,0.03272527,-0.0324043,-0.030342728,-0.002227656,0.038423426,-0.046539757,0.036050323,-0.009612033,-0.058157276,0.021697963,-0.060959954,-0.007536776,0.023279749,0.008235183,0.013628558,-0.000817619,0.070080824,0.000142402,0.0073749,-0.060857415,0.020585941,0.014687969,-0.01011957,0.038508143,0.01934992,-0.03570152,-0.049213268,-0.024277357,0.009729126,0.035338283,0.047938954,0.015550752,0.028596986,0.015963264,-0.08549136,-0.009230414,-0.015347977,-0.030805156,0.029165028,-0.034420148,-0.03310857,0.026945995,-0.03823434,-0.018031307,0.027168805,-0.002911004,-0.001141662,-0.015262937,0.04479997,0.052123655,0.00907816,0.013755477,-0.046339173,0.029067582,0.0054276,-0.027477495,0.002403112,0.014366729,-0.011750665,0.010142785,0.019709177,-0.009115553,0.030870628,-0.004256786,0.032674618,0.011456798,-0.003744266,0.010530114,0.018361261,-0.0033594,0.009321393,0.012801908,0.001059526,0.011181314,0.003049188,0.014703508,-0.043507904,-0.03382197,-0.05628452,-0.01169668,-0.040249012,0.004595278,0.043278966,0.049266614,0.011377236,0.020234043,0.035979778,-0.028441802,-0.057590954,0.06964225,-0.02578289,0.020693319,-0.027532414,-0.001745512,0.001410893,-0.017199561,-0.029618414,-0.019116782,0.006425529,0.04412443,0.03108015,0.06906574,0.022341194,0.028698752,0.000288573,0.027932402,-0.007147948,0.002704116,0.033322725,0.003377834,0.03029935,0.0307308,-0.030243602,-0.001019944,0.04052215,0.03842988,0.004823032,0.00176923,-0.010355123,-0.008991165,-0.04437831,-0.038039435,0.011222214,-0.004591065,-0.0042587,0.040620208,0.08078569,0.07086706,0.002254215,0.023419624,0.029973453,0.002084843,0.054490887,-0.048644114,0.