INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-3001-4a00-9000-000000000012', 'Landlord reserves the right to increase the monthly rent at any time during the lease term by any amount, upon providing Tenant with 7 days'' written notice.', 'rent_increase', '["lease"]'::jsonb, 'red', 'A fixed-term lease is supposed to lock in your rent for the lease period -- that is one of the main benefits of signing a lease. This clause destroys that protection by allowing unlimited rent increases with only one week''s notice. You could sign a lease at a price you can afford, only to have rent doubled the next month. In rent-controlled areas, this is flatly illegal. Even without rent control, mid-lease increases without a cap violate the implied covenant of good faith and fair dealing.', 'The monthly rent shall remain fixed at the amount stated herein for the entire initial lease term. Any rent increase shall take effect only upon renewal of the Lease and shall not exceed 5% of the then-current rent or the applicable Consumer Price Index increase, whichever is lower. Landlord shall provide Tenant with at least 90 days'' written notice of any proposed increase.', 'California Civil Code Section 1947.12 (Tenant Protection Act) caps annual increases at 5% plus CPI or 10%, whichever is lower. New York City Rent Stabilization Law limits increases to percentages set by the Rent Guidelines Board. Oregon ORS 90.323 caps increases at 7% plus CPI. UK Housing Act 1988 Section 13 requires formal notice and allows tribunal challenge. EU Directive 93/13/EEC Annex paragraph (l) prohibits terms allowing the supplier to increase price without the consumer having the right to cancel.', '[-0.0835414,0.09524037,0.013434866,-0.058449462,-0.030465474,0.007666324,-0.03675451,-0.03050758,0.004570352,0.028415097,0.037023008,-0.020121556,-0.06110948,-0.0557948,0.049807347,0.0613