INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-3002-4a00-a000-000000000013', 'Upon renewal or extension of this Lease, the monthly rent shall automatically increase by the greater of (a) 10% of the prior year''s rent or (b) the percentage increase in the Consumer Price Index, compounding annually.', 'rent_increase', '["lease"]'::jsonb, 'yellow', 'A guaranteed minimum 10% annual increase is aggressive and compounds quickly -- after 5 years your rent would be at least 61% higher than when you started. While rent escalation clauses are not inherently unfair, a 10% floor with compounding means your rent rises far faster than wages and inflation. The ''greater of'' structure means you always get the worse outcome. In jurisdictions with rent caps, this likely exceeds legal limits.', 'Upon renewal of this Lease, rent may be adjusted by the lesser of (a) 3% or (b) the percentage increase in the Consumer Price Index for the preceding 12-month period. Any increase shall be communicated to Tenant in writing at least 90 days before the renewal date. Tenant shall have the right to decline the renewal and vacate without penalty.', 'California Tenant Protection Act (AB 1482) caps annual increases at 5% plus local CPI or 10% total. Oregon ORS 90.323 caps at 7% plus CPI. Many EU member states impose rent increase caps; Germany''s Mietpreisbremse limits increases to 10% above local reference rent. UK Housing Act 1988 Section 13(2) allows tenants to challenge unreasonable increases via a tribunal.', '[-0.055404548,0.09727704,0.002246371,0.019391458,-0.031793326,0.017697183,-0.003604327,-0.008509289,0.006246651,0.041870628,-0.020683456,-0.00637262,-0.053546693,-0.0541723,0.042757317,0.02680455,-0.013263955,0.025489086,0.060623158,0.03486704,0.043994512,0.014511684,0.061107535,0.02944131,-0.010420744,0.026615677,-0.05182359,-0.034828864,0.014177289,0.01557