INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-3003-4a00-8000-000000000014', 'Landlord may impose additional monthly charges at any time during the lease term for services including but not limited to trash collection, parking, pest control, landscaping, snow removal, and building amenity access, without amendment to this Lease.', 'rent_increase', '["lease"]'::jsonb, 'yellow', 'This is a disguised rent increase. By adding uncapped ''service charges'' without needing to amend the lease, the landlord can effectively raise your total monthly cost at will while technically keeping ''rent'' the same. This could also be used to circumvent rent control laws. You agreed to a specific monthly cost when you signed the lease, and this clause allows the landlord to unilaterally change that deal.', 'All services and amenities included in the monthly rent are listed in Schedule A of this Lease. No additional charges for services shall be imposed during the lease term unless (a) the service is genuinely new and was not available at lease signing, (b) Tenant is given 60 days'' written notice, and (c) Tenant may opt out of the new service without penalty.', 'UK Tenant Fees Act 2019 prohibits most fees beyond rent and a capped deposit. EU Directive 93/13/EEC Annex paragraph (l) prohibits unilateral price increases. Restatement (Second) of Contracts Section 205 imposes a duty of good faith and fair dealing that prohibits circumventing agreed terms.', '[-0.037784543,0.027340777,-0.00094157,-0.026511949,-0.030829426,0.012167,-0.063320465,-0.048936572,0.04021277,-0.041643202,0.029597605,-0.06312059,-0.015328093,-0.03552914,0.050917193,0.029594345,-0.020982122,-0.029643985,0.017393803,0.021000484,-0.035513986,0.01746925,0.02022816,-0.008402907,0.022993997,0.018406926,-0.06548775,0.015124912,-0.046669338,-0.006587467,-0.006481976,0.056763217,-0.07485466,-0.01