INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3b6c7d8-e9f0-4a1b-9c3d-5e6f7a8b9c0d', 'The Receiving Party acknowledges that any analyses, reports, studies, or other work product ("Derivative Works") created by the Receiving Party that are based upon, derived from, or incorporate any Confidential Information shall be the sole and exclusive property of the Disclosing Party. The Receiving Party hereby irrevocably assigns to the Disclosing Party all right, title, and interest in and to such Derivative Works, including all intellectual property rights therein.', 'residuals', '["nda"]'::jsonb, 'red', 'This NDA contains a hidden intellectual property assignment clause. It says that any work you create that''s even partly ''derived from'' confidential information automatically belongs to the other party. If you analyze their data and write an internal report, they own your report. If your engineers build a tool that was influenced by something they learned, the other party claims ownership of your tool. NDAs should protect secrecy, not transfer ownership of your own work product.', 'All right, title, and interest in any analyses, reports, or other work product created by the Receiving Party shall remain the property of the Receiving Party, subject to the confidentiality obligations set forth in this Agreement. Nothing in this Agreement shall operate to assign or transfer any intellectual property rights from one party to the other.', 'US: IP assignment requires clear and specific language — courts disfavor hidden assignments in NDAs. See Teets v. Chromalloy Gas Turbine Corp. Restatement (Second) of Contracts Section 208 — unconscionable terms may be unenforceable. EU: IP assignment must be explicit and is subject to national law requirements on form and consent. Directive 2004/48/EC on enforcement of IP rights. UK: IP assignment must be in writing and