INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3a5b6c7-d8e9-4f0a-8b2c-4d5e6f7a8b9c', 'The Receiving Party agrees that any knowledge, skills, experience, or expertise gained by the Receiving Party''s employees, contractors, or agents as a result of exposure to the Disclosing Party''s Confidential Information shall be deemed Confidential Information of the Disclosing Party and shall be subject to all restrictions of this Agreement, and the Receiving Party shall not permit any such person to utilize such knowledge, skills, experience, or expertise in any manner following the termination of this Agreement.', 'residuals', '["nda"]'::jsonb, 'red', 'This clause claims ownership over knowledge that your employees absorb just by doing their jobs. If your engineer reads a technical document under this NDA and learns a new concept, this says they can never use that understanding again — even general skills and industry knowledge. This is functionally an intellectual servitude clause. People cannot simply erase what they''ve learned, and courts recognize that general skills and knowledge retained in human memory (''residual knowledge'') cannot be restricted this way.', 'Nothing in this Agreement shall restrict the Receiving Party or its personnel from using Residual Knowledge. "Residual Knowledge" means ideas, concepts, know-how, and techniques that are retained in the unaided memory of persons who have had access to Confidential Information, without reference to or use of any written or recorded Confidential Information. This Section does not grant a license under any patent, copyright, or other intellectual property right.', 'US: Courts recognize the residual knowledge doctrine — employees cannot be prohibited from using general skills and knowledge. See Restatement (Third) of Unfair Competition Section 42. DTSA protects employee mobility. EU: Trade Secrets Directive 2016/943 Recital 14 — the Directive should not affect the use of information lawfully acquired in the normal course of employment. Article 1(3)(a) — exercise of autonomy by employees shall not be affected. UK: Faccenda Chicken Ltd v. Fowler [1987] — only trade secrets, not general skill and knowledge, can be restricted post-employment.', '[0.002735498,-0.016162338,-0.028252492,0.068688236,-0.0682535,-0.027259164,-0.045025602,0.01626665,-0.04459491,0.025810301,-0.010977045,-0.037089743,-0.035238396,-0.006904967,-0.003242953,-0.020062799,-0.05304604,-0.02499325,-0.04183272,0.025274733,-0.013952379,0.036738567,-0.04654798,0.023250122,0.00383405,-0.029619226,-0.0330074,0.05420428,-0.06567876,-0.001141108,-0.010032699,0.03754382,-0.013095137,0.009233435,0.02203953,-0.013161336,0.02524728,-0.08177086,-0.004490136,0.025174374,-0.011806538,-0.015930744,-0.01773965,-0.016612828,0.021199008,-0.034649555,-0.01071455,0.040328402,-0.007806079,0.018487528,0.013134914,0.003686432,0.018457351,-0.017251186,0.036220677,-0.005272255,-0.023880342,-0.008559048,0.005122507,0.013597251,0.002664965,0.001260901,-0.002791135,0.000350848,0.012929992,0.029263578,0.017115297,-0.001907681,-0.015144538,-0.004383349,0.037760783,0.03327775,0.012695968,0.023039984,0.001183906,-0.024393646,-0.056386273,-0.02385475,0.010911612,-0.01930093,-0.03400912,-0.067021325,-0.001426944,-0.013593276,-0.060327873,0.011911764,0.03310327,-0.016745564,0.010394788,0.020956848,0.002646517,-0.060934328,0.011657434,-0.011306323,-0.005958735,-0.0746635,-0.017152911,-0.04775291,-0.007695583,0.010483926,-0.051215317,-0.005996856,0.053063016,0.01766837,0.04845967,0.009228104,-0.017503629,-0.01835535,0.037573718,-0.021110775,-0.018129634,0.04671853,0.000254911,0.032152962,-0.012230126,-0.031958472,-0.029362097,0.050707147,0.013008551,0.00518406,0.012740533,0.002631833,-0.029135037,-0.020717692,-0.025767848,0.010826319,0.015956746,-0.021536022,0.0380754,0.002712454,0.02141874,0.010508288,0.001761201,-0.00743066