INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4f8a9b0-1c2d-4e3f-8a6b-7c8d9e0f1a2b', 'Following the termination of employment, the Employee shall, for a period of twelve (12) months, be available to provide reasonable transition assistance to the Company as requested, including but not limited to answering questions from the Employee''s successor, participating in client meetings, and providing consultation on ongoing projects, at no additional compensation beyond the Employee''s final paycheck.', 'restrictive_covenants', '["employment"]'::jsonb, 'yellow', 'This clause requires you to keep working for your former employer for up to a year after leaving -- for free. The word ''reasonable'' is subjective and undefined, meaning the company decides how much of your time they can claim. This could interfere with your new job and amounts to unpaid labor. It also gives the company leverage to claim you breached the agreement if you are not responsive enough, potentially triggering forfeiture or clawback provisions elsewhere in the contract.', 'For a period of thirty (30) days following the Employee''s last day of employment, the Employee agrees to respond to reasonable written questions regarding the transition of the Employee''s duties, limited to no more than five (5) hours total. The Company shall compensate the Employee at a rate of 150% of the Employee''s final hourly equivalent base salary for all transition assistance time. Any transition assistance beyond the 30-day period shall require a separate written consulting agreement.', 'Under FLSA, requiring work without compensation may violate minimum wage and overtime provisions. UK Employment Rights Act 1996 and the National Minimum Wage Act 1998 require compensation for all work performed. EU Working Time Directive 2003/88/EC regulates working hours and requires compensation. Restatement (Second) of Contracts section 79 requires consideration for contractual obligations; post-termination work without pay lacks adequate consideration.', '[0.03794625,-0.014111329,-0.030607872,-0.015084679,-0.03991811,0.02636416,-0.006369313,0.012387897,-0.04458794,-0.021362737,-0.03774132,-0.002461576,-0.04815684,-0.074774906,-0.008313303,-0.027333789,0.001913727,0.01302154,0.004490775,-0.000555869,-0.01565394,0.011519133,0.025417328,0.009182625,-0.011460009,-0.0702838,-0.049800973,0.047106877,0.022956353,-0.000686361,0.033777315,-0.03714623,-0.05703389,-0.055104807,-0.02843945,0.020960169,0.04175082,0.00233774,0.02100519,0.019817293,0.012896083,0.05163902,0.034230087,-0.012846912,-0.024293922,0.047545668,0.003950506,-0.004534737,0.003880893,0.03425555,0.015352253,-0.03351044,-0.059413843,0.003670626,-0.029468553,-0.022569574,0.054043744,0.03948178,-0.00622914,0.010118745,0.04248077,0.028414756,-0.008624947,0.03857406,-0.007558603,0.016363163,0.020625569,-0.015577014,-0.025514353,-0.013304926,8.8591e-05,0.050470762,-0.008116055,0.031538107,0.024247635,0.021569198,-0.005183974,0.060302194,0.008195198,-0.015643153,0.011601028,-0.014244931,0.000460971,0.048078217,-0.038659904,-0.028963946,-0.002292403,-0.056520805,0.020510416,0.011790088,0.012138358,-0.015365709,0.01993439,-0.03153318,0.021931393,0.05849652,0.019119257,-0.03864561,-0.019041397,0.023558283,-0.052405678,-0.000557498,0.043805316,-0.001234825,0.04098223,-0.004924386,-0.038294114,-0.04837977,0.048143223,0.00698545,0.03669514,-0.021792458,-0.00209461,0.009751415,0.051577114,0.0513043,-0.021062639,-0.039693367,0.028183928,0.09228146,-0.008088404,0.019921716,-0.03672991,-0.021270033,0.007192908,0.06809126,-0.028412456,0.010178426,0.010280083,0.013188059,-0.001008642,0.012380929,0.014379696,-0.016999934,-0.035706256,0.028897764,-0.014489544,0.022849772,-0.005049547,-0.036206726,0.03986423,0.010115873,-0.018778896,0.001694051,-0.06703775,0.00466847,-0.000405651,-0.025341537,-0.03260591,-0.024966061,0.03078687,-0.0110658