,0.05136181,0.09932538,0.05851564,-0.005802991,-0.037255958,-0.026171494,0.014459056,0.019686606,-0.0637565,-0.025902608,-0.0984278,-0.01801651,-0.014762664,-0.017636001,-0.037309792,0.002896487,-0.031745024,-0.005375237,-0.020528367,-0.019752346,-0.015353486,-0.011243236,0.059540767,-0.001634626,-0.016039403,0.006235979,0.028580585,0.005365049,0.036326464,0.034717318,-0.029203726,-0.018583043,0.017789703,-0.04746812,-0.019591859,-0.058786336,-0.010812247,0.046717357,-0.005167548,0.02684459,-0.009224883,0.027024055,0.010784904,-0.009331234,-0.034922794,-0.008941947,-0.010922674,0.01991629,0.085541174,-0.081539005,-0.016502414,0.025758017,0.034728225,0.089850284,0.006353196,-0.00448317]'::vector, '2026-03-14T19:51:47.730Z');
INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4c5d6e7-8f9a-4b0c-ad3e-4f5a6b7c8d9e', 'During the Restricted Period and for a period of twelve (12) months following the termination of employment for any reason, the Employee shall not directly or indirectly solicit, entice, or persuade, or attempt to solicit, entice, or persuade, any person who is, or was during the preceding twenty-four (24) months, a supplier, contractor, referral source, or business partner of the Company to reduce or cease doing business with the Company.', 'restrictive_covenants', '["employment"]'::jsonb, 'yellow', 'This ''non-dealing'' clause prevents you from interacting with a huge range of the company''s business relationships for a year after leaving -- not just clients, but suppliers, contractors, and anyone who referred business. The 24-month lookback period means it covers relationships that may have already ended. If you start your own business or join a competitor, you could inadvertently violate this by working with a supplier who also works with your former employer.', 'For a period of six (6) months following termination, the Employee shall not directly solicit any supplier or business partner of the Company with whom the Employee had direct and substantial dealings during the final twelve (12) months of employment for the specific purpose of diverting that business relationship away from the Company. General business dealings, competitive bidding, and responding to inbound inquiries from such parties shall not constitute a breach of this clause.', 'UK courts in Townsend v Malmros (2020) upheld non-dealing clauses only where limited in scope and connected to the employee''s actual role. Restatement (Second) of Contracts section 188 requires post-employment restraints be narrowly tailored to protect legitimate business interests. US courts generally require non-solicitation clauses to be limited to relationships the employee actually influenced (Boulanger v Dunkin'' Donuts Inc., 442 Mass. 635 (2004)).', '[0.03779225,0.02796514,0.004550457,0.037387516,-0.060973134,0.012852225,-0.016953984,0.02502799,-0.038656354,0.029524539,-0.043956183,0.016921174,-0.004591587,0.011599991,0.006649572,-0.013411998,0.006236728,0.033215847,0.00082628,0.012447448,-0.035856128,0.001600622,-0.030251976,0.051008377,-0.020238213,-0.04197208,0.020486968,0.04439107,-0.02825609,-0.035105508,0.06899589,-0.012137732,0.000417319,-0.01281181,0.0181316,-0.017740168,0.03167957,-0.021031234,-0.01393657,-0.008198565,0.04081206,0.036895823,0.04529751,-0.008916542,-0.013570381,-0.001626947,-0.023503197,-0.004244865,0.002749526,0.025363276,0.015559405,0.001900267,-0.09539876,0.05031912,0.001756515,0.045429815,0.03686775,0.07029582,0.011722721,0.001764124,0.06716961,-0.032773215,-0.020417122,0.061135545,0.014405909,-0.012861548,0.046508286,0.007810378,-0.021559075,0.02592932,0.055711713,0.028512534,0.0084558,0.05718807,0.01584937,0.008600267,-0.011207623,0.05267529,0.002428663,-0.002434897,-0.06491337,-0.009875401,0.000495115,0.046712026,-0.047807902,-0.010282982,0.003195765,-0.041222896,0.00954907,0.06022409,-0.005758837,-0.04985143,0.09847093,-0.035192516,-0.007554618,0.014865877,-0.011225165,0.020722512,-0.009623518,0.029577225,-0.043543313,-0.018932924,0.024616104,-0.040582176,0.055339657,0.002296215,-0.011074614,-0.07555731,0.054955598,-0.034805786,0.019681191,-0.047861185,0.010481232,0.026600217,0.031361856,0.013389381,-0.014638692,0.005018781,0.008442247,0.021190034,0.011478322,0.038857203,-0.007349685,0.014787093,-0.048283406,0.0380263,0.007692368,-0.02408866,0.032610986,0.039373986,0.045614377,0.007988382,-0.030148199,0.056896325,-0.02955187,0.06822371,0.02970409,-0.012827599,0.000114941,0.011343662,-0.001991987,0.014111302,0.017968312,-0.001743874,0.007789442,-0.007370846,-0.05780985,-0.023536233,-0.048405897,-0.0242073,0.007099119,-0.030242257,0.01461