INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3c1d2e3-f4a5-4b6c-ad8e-0f1a2b3c4d5e', 'The Receiving Party shall not retain any copies of Confidential Information in any form, including electronic back-ups, archived emails, or records stored on cloud-based systems, and shall take all steps necessary to purge Confidential Information from all systems, including those maintained by third-party service providers, within seventy-two (72) hours of the Disclosing Party''s request.', 'return_of_materials', '["nda"]'::jsonb, 'red', 'Purging all traces of information from every system — including third-party cloud providers, email archives, and backup tapes — within 72 hours is technically impossible for most organizations. Enterprise backup systems, email servers, and cloud platforms retain data in ways that cannot be selectively deleted on a short timeline. Promising something impossible to perform makes this clause a trap: you''ll inevitably be in breach because full compliance is not achievable.', 'Upon the Disclosing Party''s written request, the Receiving Party shall use commercially reasonable efforts to delete or destroy Confidential Information from its active systems within thirty (30) days. The Receiving Party shall not be required to purge Confidential Information from (a) automatic backup or archival systems where deletion is not commercially practicable, provided that such copies are not actively accessed and remain subject to the confidentiality obligations herein, or (b) records required to be maintained under applicable law or regulation.', 'US: Courts apply a reasonableness standard to return/destruction obligations. Requiring the technically impossible may render the clause void for impossibility under Restatement (Second) of Contracts Section 261. EU: GDPR Article 17(3) — exceptions to erasure obligations where retention is required 