INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3b0c1d2-e3f4-4a5b-9c7d-9e0f1a2b3c4d', 'Upon the termination or expiration of this Agreement, or upon the Disclosing Party''s written request at any time, the Receiving Party shall immediately return or destroy all Confidential Information, including all copies, notes, summaries, analyses, compilations, studies, interpretations, memoranda, and other materials prepared by the Receiving Party that contain, reflect, or are derived from Confidential Information (collectively, "Derivative Materials"), and shall certify such return or destruction in writing within five (5) business days.', 'return_of_materials', '["nda"]'::jsonb, 'yellow', 'This requires you to destroy all your own work product — notes, analyses, summaries, and anything ''derived from'' confidential information. That could include your internal meeting minutes, strategy documents, evaluation reports, and more. It also ignores that you may have legal or regulatory obligations to retain certain records (tax records, compliance files, litigation holds). The five-day deadline is extremely tight for organizations with complex data systems.', 'Upon the termination or expiration of this Agreement, or upon the Disclosing Party''s written request, the Receiving Party shall promptly return or destroy the Disclosing Party''s Confidential Information in its possession, and shall confirm such return or destruction in writing within thirty (30) days. Notwithstanding the foregoing, the Receiving Party may retain (a) one archival copy of Confidential Information solely for legal compliance and dispute resolution purposes, and (b) Confidential Information contained in automatic computer back-up or archival systems, provided such retained copies remain subject to the confidentiality obligations of this Agreement.', 'US: Legal hold obligations under Federal Rules of Civil Procedure may require retention of documents relevant to anticipated or pending litigation — destruction could constitute spoliation. Sarbanes-Oxley Act Section 802 imposes record retention requirements. EU: GDPR Article 17 and recital 65 — right to erasure must be balanced against legal obligation to retain. UK: Limitation Act 1980 — documents may need to be retained for potential claims within limitation periods.', '[0.006301776,0.010198913,-0.05625884,0.04652507,-0.050426707,0.036053687,-0.007762576,0.013214416,-0.012402298,0.011472209,-0.024409158,-0.022532213,-0.03301253,-0.060570482,-0.03715981,-0.007769152,0.002137034,0.009310471,0.032088686,0.022487748,-0.010031287,0.031447645,-0.015493791,0.031046955,-0.040350858,-0.023090113,-0.050982155,0.061290573,-0.04275456,-0.029439691,-0.002095454,0.04294766,-0.009889705,0.029824577,-0.032535754,0.010807253,-0.042543333,-0.06843014,0.049399238,-0.010019587,0.014245798,-0.029102478,-0.015151075,-0.006443213,0.056944102,-0.03357167,-0.015022903,0.029805133,0.020171016,-0.001875858,-0.024883078,0.031124443,0.062384743,0.001327133,0.023442343,-0.006182008,0.056700666,0.00765611,0.022411969,0.030379428,-0.02229357,-0.030578017,-0.026809039,0.007480301,-0.00052412,0.07515922,0.005665209,0.015028273,0.06832291,-0.022867056,-0.006747197,0.05733334,0.001244422,0.047210816,0.049551025,-0.012715249,0.029979002,0.06673728,-0.012184774,-0.019187182,-0.040752668,-0.058562115,0.006600739,-0.012143816,0.010169989,0.016575955,0.02252212,0.000793886,0.055058826,-0.006644551,-0.027433516,-0.04461104,0.0494634,-0.005989707,-0.012447193,0.00502904,0.023553686,-0.013961471,-0.002496852,0.033575878,-0.09664145,0.025944177,0.04847114,0.006128332,0.039510727,-0.008678931,-0.02587498,0.021026919,0.016510814,-0.020990988,-0.08049288,0.10310106,-0.01812433,-0.010566561,0.055386804,-0.047612134,-0.002547401,0.018885355,-0.01380872,-0.064175986,0.03206329,-0.01895998,-0.04914789,-0.029024005,-0.004885699,0.02906735,-0.005111681,-