INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-1005-4a00-8000-000000000005', 'In the event Landlord installs or activates security cameras, smart locks, or other monitoring devices in or around the Premises, Tenant agrees not to disable, obstruct, or interfere with such devices and consents to any recordings made thereby.', 'right_of_entry', '["lease"]'::jsonb, 'red', 'This gives your landlord the right to install cameras and monitoring equipment in your home and record you without limits. Even if cameras are in common areas, smart locks track every time you enter and leave. This is a serious invasion of privacy. In many places, recording someone in their home without clear, specific consent violates wiretapping and privacy laws.', 'Landlord may install security cameras only in shared common areas (lobbies, parking garages, building entrances) with clear signage disclosing their presence. No recording or monitoring devices shall be installed inside the Premises or in areas where Tenant has a reasonable expectation of privacy. Tenant shall have full control over any smart lock systems installed on the Premises'' entry door.', 'UK Data Protection Act 2018 and UK GDPR regulate surveillance in residential settings. EU General Data Protection Regulation Articles 6-7 require specific, informed consent for data processing. California Invasion of Privacy Act (Penal Code Section 632) prohibits recording confidential communications. New York Penal Law Section 250.00 makes unlawful surveillance a crime.', '[-0.04646091,0.041761734,-0.012367252,-0.013561601,-0.035641123,0.03466266,-0.046587393,0.04230057,0.02538952,0.013703029,0.00507922,0.000182886,-0.053762656,-0.04320497,0.04020043,-0.013284947,0.011487394,-0.015205121,0.000332609,0.024207607,-0.000990533,-0.03044785,-0.001242354,0.008485915,0.03186322,0.029462684,-0.02109872,0.011926982,-0.037