INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-1001-4a00-b000-000000000001', 'Landlord or Landlord''s agents shall have the right to enter the Premises at any time, with or without notice, for any purpose deemed necessary by Landlord, including but not limited to inspection, repairs, or showing the Premises to prospective tenants or buyers.', 'right_of_entry', '["lease"]'::jsonb, 'red', 'This gives the landlord unlimited, unannounced access to your home. In most jurisdictions, landlords must give at least 24-48 hours written notice before entering, except in genuine emergencies (like a burst pipe). Unrestricted entry effectively eliminates your right to privacy in your own home and is illegal in most US states, contrary to UK common law implied terms, and unfair under EU Directive 93/13/EEC.', 'Landlord may enter the Premises upon providing Tenant with no less than 24 hours'' prior written notice, stating the date, approximate time, and purpose of entry. Entry without notice is permitted only in the event of a genuine emergency posing an immediate risk to life, health, or property. The Tenant''s right to quiet enjoyment shall not be unreasonably disturbed.', 'California Civil Code Section 1954 requires 24 hours'' reasonable notice except in emergencies. New York has no specific statute but courts imply a covenant of quiet enjoyment requiring reasonable notice. UK common law implies a covenant of quiet enjoyment (Southwark LBC v Mills [2001] 1 AC 1). EU Directive 93/13/EEC Annex paragraph (b) prohibits terms inappropriately restricting the consumer''s legal rights.', '[-0.053655248,0.07008136,0.011525512,-0.052628137,-0.06366285,-0.04123702,-0.060138058,-0.008721909,0.02553984,-0.011401805,0.028039299,-0.03746817,-0.029810738,0.005682646,-0.026226474,0.06296963,0.03169086,-0.026103135,-0.016426632,0.058081236,0.013322588,-0.015265056,-0