INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-1002-4a00-b000-000000000002', 'Tenant acknowledges and agrees that Landlord shall retain a master key to the Premises at all times and may use said key to access the Premises without prior consent or notification to Tenant.', 'right_of_entry', '["lease"]'::jsonb, 'red', 'While landlords typically retain a key for emergencies, this clause removes your right to be told when they enter. Combining key retention with no-notice access essentially means someone can walk into your home at any time without telling you. This violates the implied covenant of quiet enjoyment -- a legal principle that says tenants have the right to use their home without unreasonable interference from the landlord.', 'Landlord shall retain a master key to the Premises solely for use in emergencies. Except in emergencies, Landlord shall not use the master key to enter the Premises without providing Tenant no less than 24 hours'' prior written notice and obtaining Tenant''s consent, which shall not be unreasonably withheld.', 'California Civil Code Section 1954(d)(1) requires reasonable notice even when landlord possesses a key. UK Renters (Reform) Act proposals reinforce tenant right to control access. EU Directive 93/13/EEC Annex paragraph (b) flags terms that inappropriately exclude or limit consumer rights.', '[-0.060848884,0.0271581,-0.035659563,-0.0487391,-0.077275194,-0.033978928,-0.04014223,0.058285337,0.026715856,0.011103094,0.015684374,-0.009176478,-0.07173336,-0.026358094,-0.019383067,0.059671752,0.026120415,-0.013573596,-0.020139815,0.03152518,0.016445663,0.009007834,-0.044496525,0.02456844,0.05171876,-0.011232699,-0.067767754,0.05907329,-0.03155232,-0.00407452,0.004464067,0.003621573,-0.04381965,0.01675879,-0.03153195,-0.036022753,0.028865123,0.016872033,-0.033503428,-0.002043968,-0.045444675,0.016645199,-0.