INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-1004-4a00-a000-000000000004', 'Landlord and Landlord''s employees, agents, and contractors may enter the Premises without notice to perform routine inspections on a schedule determined solely by Landlord, including but not limited to monthly inspections of all rooms, appliances, and fixtures.', 'right_of_entry', '["lease"]'::jsonb, 'red', 'Mandatory monthly inspections of your entire home with no notice requirement is excessive surveillance, not reasonable property management. This treats your home like a commercial property subject to audit. It creates a power dynamic where you feel constantly monitored, which courts have recognized as a violation of your right to quiet enjoyment and peaceful possession of the property.', 'Landlord may conduct a routine inspection of the Premises no more than once every six months, upon providing Tenant with at least 48 hours'' prior written notice. Inspections shall be limited to verifying compliance with the lease terms and assessing the general condition of the Premises. Tenant shall have the right to be present during any inspection.', 'Javins v. First National Realty Corp., 428 F.2d 1071 (D.C. Cir. 1970) established that residential leases carry implied habitability and quiet enjoyment rights. California Civil Code Section 1954 limits entry to specified purposes with 24 hours'' notice. UK Consumer Rights Act 2015 Schedule 2 paragraph 4 targets terms giving the trader the right to determine whether goods/services are in conformity unilaterally.', '[-0.054937765,0.05617208,0.030828051,-0.05364367,-0.07008868,-0.010797462,-0.10207123,-0.03865816,0.027638052,-0.008446693,0.032370422,-0.024157435,-0.010180185,-0.008385177,0.010128126,0.03712871,0.009250349,-0.037538618,0.009575794,0.007305468,0.01092812,-0.009220286,-0.03974948,0.008979611,0.000340245,-0.