INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-1003-4a00-9a00-000000000003', 'Landlord reserves the right to show the Premises to prospective tenants, buyers, lenders, or contractors at any reasonable time without prior notice to Tenant.', 'right_of_entry', '["lease"]'::jsonb, 'yellow', 'While landlords have a legitimate need to show property to prospective tenants or buyers, doing so without notice disrupts your daily life and privacy. The vague phrase ''any reasonable time'' is subjective and could mean daily interruptions. Most state laws require advance notice even for showings.', 'Landlord may show the Premises to prospective tenants during the final 60 days of the lease term, and to prospective buyers at any time during the lease term, provided Landlord gives Tenant at least 24 hours'' written notice specifying the date and a two-hour time window. Showings shall not exceed three per week without Tenant''s written consent.', 'California Civil Code Section 1954(d)(2) requires 24 hours'' notice for showings. Illinois 765 ILCS 735/1 requires two days'' notice. UK Housing Act 1988 Section 11 does not override implied quiet enjoyment rights. EU Directive 93/13/EEC Article 3(1) requires assessment of significant imbalance in parties'' rights.', '[-0.044467393,0.07137079,-0.008750646,-0.046946492,-0.033166587,-0.012317793,-0.044183258,0.016501663,0.024896752,0.03364458,0.024178095,-0.056048118,-0.06376922,-0.024106577,-0.01865688,0.06815143,0.027348615,-0.024701253,-0.002904917,0.008332055,-0.018216578,-0.009050156,-0.054590527,0.01523908,0.021519065,0.019645574,-0.041142255,0.029542875,-0.043840606,-0.01915987,0.038983036,0.015717788,-0.02989637,-0.017763678,-0.009677914,-0.032172114,-0.019856578,-0.026386105,-0.011198568,0.011851024,-0.035015132,0.007354014,-0.000435542,-0.020009216,0.045334376,-0.035551038,0.024379011,-0.014178774,-0.