INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3a1b2c3-d4e5-4f6a-8b9c-0d1e2f3a4b5c', '"Confidential Information" shall mean any and all information, whether written, oral, electronic, or otherwise, disclosed by or on behalf of the Disclosing Party to the Receiving Party, including but not limited to all business plans, financial data, customer lists, technical data, trade secrets, know-how, inventions, processes, techniques, algorithms, software, designs, drawings, engineering, marketing plans, and any other information relating to the Disclosing Party''s business, regardless of whether such information is marked or designated as "confidential."', 'scope_breadth', '["nda"]'::jsonb, 'red', 'This definition covers literally everything the disclosing party ever shares with you, even casual conversations or publicly known facts. Because nothing needs to be marked "confidential," you could accidentally breach the NDA by discussing something you learned from a Google search. Courts have struck down definitions this broad as unenforceable because they fail to give the receiving party fair notice of what they must protect.', '"Confidential Information" shall mean information disclosed by the Disclosing Party to the Receiving Party that is (a) in written or electronic form and clearly marked "Confidential" at the time of disclosure, or (b) disclosed orally and identified as confidential at the time of disclosure and confirmed in writing within thirty (30) days thereafter.', 'US: Overbroad definitions may fail under UTSA''s requirement that trade secrets derive value from not being generally known. See nClosures Inc. v. Block and Veatch, Inc. (overbroad NDAs found unenforceable). Restatement (Second) of Contracts Section 208 (unconscionability). EU: Directive 2016/943 Article 2(1) requires information to be secret and have commercial value due to secrecy. UK: Trade Secrets Regulations 2018 mirror EU requirements.', '[-0.000637565,0.015832372,-0.023744969,0.01755465,-0.053290185,0.025761109,-0.025012562,0.058513317,-0.047446452,0.029791217,-0.06081304,-0.04590704,-0.027399354,-0.009663298,-0.009578979,-0.01667734,-0.023668127,0.019684741,0.014425031,0.023079112,-0.019486863,0.057822123,0.006792816,0.023803255,-0.04275193,-0.02128497,-0.013358086,0.026317813,-0.001157154,-0.007886435,-0.008193981,0.03876026,-0.020066964,0.040292613,0.00990339,0.015515976,0.012498162,-0.046960976,0.050039753,0.044079833,0.08650168,-0.000866825,0.004689517,7.3756e-05,0.024672052,-0.0447536,-0.052617233,0.043225396,0.005961073,-0.027167065,-0.005671916,-0.005811745,-0.017736828,0.004416416,0.034049645,-0.032661613,0.05527705,0.007203987,-0.009539571,-0.02480858,-0.011560291,-0.06593063,-0.010647275,0.018603187,0.003256618,0.017472118,0.03743684,0.057399545,0.06310251,-0.02314587,0.040500496,0.07485403,0.04073312,0.025298232,0.022222616,-0.003074646,-0.03573968,0.059155904,-0.05421589,-0.03204759,-0.002311802,-0.028111821,-0.044678945,0.030785901,-0.017739126,0.036797676,-0.016626844,0.03794353,0.021377442,-0.03767791,-0.021455325,-0.07617079,0.029991783,-0.061191365,-0.025354527,-0.017804053,-0.004847618,-0.016315904,-0.03113278,0.027358387,-0.07528257,-0.008202574,0.03611838,0.032106206,0.061414223,0.001992525,-0.014315132,-0.017530387,0.058795013,0.027165886,-0.054016143,0.04801017,0.013718441,0.001307219,0.023467345,-0.026660787,-0.01334603,0.03694819,-0.029118096,-0.019829987,-0.021590691,-0.015254676,-0.024000999,0.014067984,0.023433924,0.013171578,-0.015306355,0.000715587,0.017324802,0.05044326,0.014537144,-0.0488619,-0.004434673,0.005965458,-0.015684055,0.027030949,0.027919397,0.054943632,0.007422247,-0.007522649,0.00673755,-0.01612083,0.022401225,-0.001151685,0.078646384,0.014560982,-0.02600763,0.006562525,-0.003245597,-0.027846146,-0.003548389,0.005165433,0.044662137,-0.048902813,0.003407706,-0.043532297,-0.05521392,-0.0133486