INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3c3d4e5-f6a7-4b8c-9d0e-2f3a4b5c6d7e', 'The definition of Confidential Information hereunder shall encompass all information relating to the Disclosing Party''s business operations, regardless of whether such information is publicly available, generally known in the industry, or ascertainable through publicly accessible sources.', 'scope_breadth', '["nda"]'::jsonb, 'red', 'This clause claims that even publicly available information — things anyone can find on Google, in news articles, or in public filings — must be treated as confidential. That''s absurd on its face: you can''t be bound to secrecy about facts the whole world already knows. Courts consistently reject this because the entire point of a trade secret is that it''s NOT publicly known.', 'Confidential Information shall not include information that: (a) is or becomes publicly available through no fault or action of the Receiving Party; (b) is generally known within the relevant industry or trade; or (c) is contained in publicly accessible filings, publications, or databases.', 'US: UTSA Section 1(4)(i) explicitly requires trade secrets to ''derive independent economic value from not being generally known.'' DTSA 18 U.S.C. Section 1839(3) mirrors this requirement. EU: Trade Secrets Directive 2016/943 Article 2(1)(a) — information must be ''not generally known among or readily accessible to persons within the circles that normally deal with the kind of information in question.'' UK: Trade Secrets Regulations 2018 adopt the same test.', '[0.025845055,0.008969819,-0.00150339,0.03950905,-0.02344702,0.03205479,-0.021235885,0.043834444,-0.03870163,0.013623131,-0.07284567,-0.054148324,-0.038786877,-0.005696906,-0.006948871,-0.025517583,-0.007150184,-0.01707054,-0.001923929,-0.025762709,-0.012437951,0.040426005,-0.012973301,0.022752155,-0.03353024