INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3b2c3d4-e5f6-4a7b-8c9d-1e2f3a4b5c6d', 'Confidential Information shall include, without limitation, all information that the Receiving Party knew or should have known would be regarded as confidential by the Disclosing Party, including information that the Receiving Party may have independently developed or lawfully obtained from third-party sources prior to execution of this Agreement.', 'scope_breadth', '["nda"]'::jsonb, 'red', 'This clause tries to lock away information you already had before signing the NDA, including things you figured out on your own or got from someone else entirely. That means your own pre-existing work could suddenly be treated as the other party''s secret. This is fundamentally unfair and generally unenforceable because you can''t agree to keep secret something that was never actually secret to you.', 'Confidential Information shall not include information that: (a) was already known to the Receiving Party at the time of disclosure, as demonstrated by written records predating such disclosure; (b) was independently developed by the Receiving Party without use of or reference to the Disclosing Party''s Confidential Information; or (c) was lawfully obtained by the Receiving Party from a third party without restriction on disclosure.', 'US: UTSA Section 1(4) defines trade secrets as information not generally known — information already possessed cannot be a trade secret. Restatement (Second) of Contracts Section 208. EU: Trade Secrets Directive 2016/943 Article 3(1)(b) recognizes independent discovery as lawful acquisition. UK: Trade Secrets Regulations 2018 reg. 3(1)(b) — independent discovery is a lawful means of acquisition.', '[0.001127883,-0.02369224,-0.023564788,0.0303476,-0.030868765,0.017064681,-0.04217368,0.07748382,-0.017949346,0.03752528,-0.044423304,-0.042292397,