INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3d4e5f6-a7b8-4c9d-8e1f-3a4b5c6d7e8f', 'For purposes of this Agreement, Confidential Information shall include the existence of this Agreement, the identity of the parties hereto, the fact that discussions or negotiations are taking place, and any terms, conditions, or other facts with respect to any such discussions or negotiations, including the status thereof.', 'scope_breadth', '["nda"]'::jsonb, 'yellow', 'This clause prevents you from telling anyone — including your own lawyer, accountant, or business advisor — that the NDA even exists or that you''re in discussions with this company. While keeping negotiation details private can be reasonable, making the very existence of the agreement secret can prevent you from getting proper legal or financial advice about the deal itself.', 'The existence of this Agreement and the fact that discussions are taking place between the parties shall be treated as Confidential Information, provided that either party may disclose such facts to its legal counsel, accountants, financial advisors, and officers or directors with a need to know, each of whom shall be bound by obligations of confidentiality no less restrictive than those set forth herein.', 'US: Generally enforceable but subject to unconscionability limits under Restatement (Second) of Contracts Section 208. May conflict with SEC disclosure requirements for public companies. EU: Unfair Contract Terms Directive 93/13/EEC Article 3(1) — a term causing significant imbalance may be unfair. UK: CRA 2015 Schedule 2 para. 12 — terms restricting the right to take legal action or exercise legal remedy may be unfair.', '[-0.03273049,-0.025736125,-0.020778455,-0.020515013,-0.01911835,-0.012904439,-0.027815118,0.07679588,-0.024294114,0.020003712,-0.030632148,-0.07164621,-0.07684833,-0.028015114,-0.035929333,-0.01