INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2323334-3536-4738-893a-3b3c3d3e3f40', 'Contractor shall make unlimited revisions to any deliverable until Client is fully satisfied, at no additional cost to Client. Client''s request for revisions shall not be subject to any time limit, and Contractor shall commence each round of revisions within two (2) business days of receiving Client''s feedback.', 'scope_creep', '["freelance"]'::jsonb, 'red', 'Unlimited free revisions with no time limit means the client can keep requesting changes forever. ''Fully satisfied'' is completely subjective -- if the client keeps changing their mind, you''re trapped in an endless loop of unpaid work. Two business days to start each round means you can''t even schedule other work reliably.', 'The agreed fee includes up to two (2) rounds of revisions per deliverable, with each round consisting of consolidated written feedback from Client. Additional revisions beyond two rounds shall be billed at Contractor''s standard hourly rate. Client shall submit all revision requests within ten (10) business days of deliverable submission.', 'Unlimited revisions without additional compensation may violate the implied duty of good faith under Restatement (Second) of Contracts Section 205. UK Supply of Goods and Services Act 1982 Section 15 implies a duty to pay a reasonable price for reasonable services. EU Directive 93/13/EEC Annex paragraph 1(c) flags terms allowing retention of sums for services not provided by the consumer.', '[-0.008289316,0.014912399,-0.06295026,-0.030204374,-0.06802566,0.01549062,0.04145026,-0.006478918,-0.011120054,0.007136536,-0.026925074,-0.004420583,-0.05422087,-0.060110774,0.05773809,0.057923403,-0.003481483,-0.00442787,0.007574209,0.025406443,-0.003663283,0.009051139,0.008601058,-0.012480158,-0.038728934,-0.056962486,0.004181955,0.06516173,0.02143653