INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2424344-4546-4748-894a-4b4c4d4e4f50', 'The scope of Services shall include, but not be limited to, the deliverables described in the Statement of Work, and shall encompass all tasks reasonably necessary to achieve Client''s business objectives as determined by Client from time to time during the engagement.', 'scope_creep', '["freelance"]'::jsonb, 'red', 'The phrase ''but not limited to'' combined with ''all tasks reasonably necessary to achieve Client''s business objectives'' is a blank check. The client can add work by simply redefining their ''business objectives,'' and you''re expected to do it within the original price. This is the classic scope creep clause -- it makes the Statement of Work meaningless.', 'The scope of Services is limited exclusively to the deliverables described in the Statement of Work. Any work requested by Client that is not described in the Statement of Work shall be subject to a separate written change order specifying scope, timeline, and additional fees, signed by both parties before work begins.', 'Open-ended scope terms undermine the certainty required for a valid contract under Restatement (Second) of Contracts Section 33 (certainty of terms). EU Directive 93/13/EEC Annex paragraph 1(j) flags terms enabling the supplier to unilaterally alter contract terms. UK Unfair Contract Terms Act 1977 Section 3 restricts claims to render performance substantially different from what was reasonably expected.', '[-0.018547349,-0.005694969,-0.072368294,-0.00335002,-0.07951996,0.018594848,0.039349712,-0.024191186,-0.03468615,-0.026431847,0.034886744,-0.02684438,-0.044737738,-0.055203646,0.04778009,-0.054149967,-0.070424,0.000574127,0.011395118,0.06744842,-0.043858286,0.02541089,-0.034099355,-0.008632653,-0.002463163,-0.041048214,0.012483274,0.022573914,-0.010415987,0.03321032,0.