INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2626364-6566-4768-896a-6b6c6d6e6f70', 'In the event that any deliverable requires additional work beyond the original estimate, Contractor shall complete such additional work at no extra charge, provided the additional work arises from Client''s clarification of the original requirements or change in Client''s business priorities.', 'scope_creep', '["freelance"]'::jsonb, 'yellow', 'This forces you to absorb the cost of scope changes as long as the client frames them as ''clarifications'' or ''priority changes.'' In practice, most scope creep is presented exactly this way -- ''Oh, I thought this was included'' or ''Our priorities have shifted slightly.'' The line between a clarification and a new requirement is endlessly arguable, and the client controls the framing.', 'Work beyond the scope described in the Statement of Work, including changes arising from revised requirements, clarifications that materially alter deliverables, or shifts in business priorities, shall be documented in a written change order specifying the additional scope, timeline impact, and fees before work begins.', 'Restatement (Second) of Contracts Section 89 provides that a modification is binding only if fair and equitable in view of circumstances not anticipated. EU Directive 93/13/EEC Annex paragraph 1(j) flags terms allowing unilateral alteration of contract terms. UK Unfair Contract Terms Act 1977 Section 3(2)(b) restricts claims to render substantially different performance.', '[-0.003785648,0.018172909,-0.057943083,-0.022983065,-0.05119704,0.02457988,-0.014992319,-0.005520374,-0.01632539,0.007076186,-0.005377688,-0.043121807,-0.019847553,-0.067614734,0.0979488,-0.00030843,-0.069605015,-0.03452762,0.029011434,-0.007260107,-0.011326404,0.004281505,0.040596664,-0.042715732,-0.029093977,-0.017817019,0.015358137,0.05048678