INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2525354-5556-4758-895a-5b5c5d5e5f60', 'Contractor shall be available to Client during normal business hours and shall respond to all communications within four (4) hours. Contractor shall also perform such other duties as may be reasonably assigned by Client from time to time, consistent with Contractor''s skills and expertise.', 'scope_creep', '["freelance"]'::jsonb, 'yellow', 'The ''other duties as assigned'' language is an employment clause that has no place in a freelance contract. Combined with the 4-hour response requirement and business-hours availability, this looks like an employer-employee relationship, not an independent contractor engagement. It also allows unlimited scope expansion via ''reasonable'' assignments.', 'Contractor shall perform the Services described in the Statement of Work and shall respond to Client communications within one (1) business day during the engagement period. Contractor maintains discretion over work hours and methods consistent with Contractor''s independent contractor status.', 'Requiring set hours and ''other duties as assigned'' are strong indicators of employment status under the IRS 20-factor test and the ABC test used in California (AB5, Dynamex Operations West v Superior Court). UK IR35 off-payroll working rules (Chapter 10 of ITEPA 2003) look at control, substitution, and mutuality of obligation. HMRC''s CEST tool would likely flag these requirements as indicators of disguised employment.', '[-0.03391613,-0.004906791,-0.039778635,-0.018894056,-0.07014828,-0.019374372,0.009092473,0.001616937,0.03204744,0.002873884,-0.021629982,-0.008625045,-0.027733194,-0.055621337,0.035533078,-0.050862286,-0.02137901,0.005900604,-0.009099788,-0.058356125,-0.034733005,0.004361176,-0.06109439,0.02049091,-0.019918306,-0.01987886,-0.019182215,0.055371307,-0.020644171,-