INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-2001-4a00-b000-000000000006', 'The security deposit paid by Tenant upon execution of this Lease is non-refundable and shall be retained by Landlord in its entirety upon termination of the Lease, regardless of the condition of the Premises.', 'security_deposit', '["lease"]'::jsonb, 'red', 'A completely non-refundable security deposit is illegal in most jurisdictions. The whole point of a deposit is that it secures the landlord against actual damage -- it is your money that the landlord holds temporarily, not a fee you pay. If you leave the property in good condition, you are entitled to get your deposit back. Calling it ''non-refundable'' is an attempt to convert your deposit into a hidden fee.', 'The security deposit shall be held by Landlord in a separate interest-bearing account. Within 30 days of Tenant vacating the Premises, Landlord shall return the full deposit to Tenant, less any amounts deducted for actual damages beyond normal wear and tear, accompanied by an itemized statement of deductions with receipts.', 'California Civil Code Section 1950.5 prohibits non-refundable deposits and requires itemized return within 21 days. New York GOL Section 7-108 requires deposits held in interest-bearing accounts and return within 14 days. UK Tenant Fees Act 2019 caps deposits at 5 weeks'' rent and requires government-approved deposit protection schemes. EU Directive 93/13/EEC Annex paragraph (d) prohibits terms allowing the trader to retain sums paid where the trader terminates.', '[-0.030934332,0.055333704,-0.020228773,0.005587439,-0.032553922,-0.041904952,-0.007543191,0.056696255,-0.001221008,-0.002915761,-0.008835698,-0.06593517,-0.037896093,-0.068396054,0.026425172,0.030371666,0.007790159,0.047562134,0.04221401,0.01627171,0.010653649,-0.003466426,-0.019268056,-0.003641916,-0.009174729,-0.