INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-2003-4a00-a000-000000000008', 'Landlord shall not be required to provide Tenant with any accounting, itemization, or documentation of deductions from the security deposit. Tenant waives any right to dispute the amount returned or retained.', 'security_deposit', '["lease"]'::jsonb, 'red', 'This tries to strip away your legal right to know what your deposit was spent on and to challenge unfair deductions. In virtually every jurisdiction, landlords are legally required to give you an itemized list of exactly what they deducted and why. Waiving your right to dispute deductions means the landlord can pocket your entire deposit and you would have no recourse.', 'Within 21 days of Tenant vacating the Premises, Landlord shall provide Tenant with an itemized written statement listing each deduction from the security deposit, the amount of each deduction, and the reason for each deduction, together with copies of receipts or estimates. Any remaining balance shall be returned concurrently. Tenant retains the right to dispute any deduction.', 'California Civil Code Section 1950.5(g) requires itemized statement within 21 days; non-compliance entitles tenant to full refund. Massachusetts GL c. 186 Section 15B requires 30-day itemized return with treble damages for non-compliance. UK Housing Act 2004 Sections 213-215 require deposit protection and prescribed information. EU Directive 93/13/EEC Annex paragraph (q) prohibits terms excluding or restricting the consumer''s right to take legal action.', '[0.007174447,0.040716656,0.0140943,-0.000727973,-0.038352557,-0.007163532,-0.02415165,0.016306415,0.011203703,-0.003255715,-0.00905949,-0.05710103,-0.028667847,-0.03683888,-0.022309054,-0.013162033,-0.031545404,0.004924071,0.027937971,-0.004181416,0.035206325,-0.0323996,-0.024659187,-0.010102798,-0.021884775,