INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-2004-4a00-8000-000000000009', 'Tenant shall pay a security deposit equal to three months'' rent upon execution of this Lease. An additional deposit of one month''s rent shall be required for each pet, and a further supplemental deposit may be required at Landlord''s discretion during the term.', 'security_deposit', '["lease"]'::jsonb, 'red', 'An upfront deposit of three months'' rent plus open-ended additional deposits is excessive and creates a major financial barrier. Many jurisdictions cap security deposits at one to two months'' rent precisely to prevent landlords from demanding unreasonable amounts. The clause also allows the landlord to demand more money during the lease at their discretion, which is a one-sided power that could be used coercively.', 'Tenant shall pay a security deposit equal to one month''s rent upon execution of this Lease. If Tenant keeps a pet on the Premises with Landlord''s written consent, an additional pet deposit not exceeding one-half month''s rent may be required. No additional deposits shall be required during the lease term.', 'California Civil Code Section 1950.5(c) limits deposits to two months'' rent (unfurnished) or three months'' (furnished). New York RPL Section 7-108(1-a)(a) limits deposits to one month''s rent. UK Tenant Fees Act 2019 caps deposits at five weeks'' rent (annual rent under 50,000 GBP) or six weeks'' rent. EU Directive 93/13/EEC Article 3(1) targets terms causing significant imbalance.', '[-0.028841572,0.045053903,-0.033375803,0.004412938,-0.05035325,-0.045381244,-0.020646013,0.014375502,0.04732463,0.02532354,-0.019848777,-0.023265358,-0.01646773,-0.04315771,0.041665692,0.029229602,-0.02076155,-0.020578137,0.03538691,-0.00444324,-0.008991869,-0.015578253,0.048004955,-0.021253409,0.01083717,-0.05468841,-0.031859346,0.023022648,-0.013