,0.0620244,-0.02369207,-0.001358785,0.014407518,-0.031540617,-0.03948871,0.019056154,-0.05894463,-0.027176496,-0.000599242,0.023141151,-0.028156614,-0.014849146,-0.031388436]'::vector, '2026-03-14T19:51:52.380Z');
INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-2006-4a00-b000-000000000011', 'In the event of early termination by Tenant for any reason, the entire security deposit shall be forfeited to Landlord as liquidated damages, in addition to any remaining rent owed for the balance of the lease term.', 'security_deposit', '["lease"]'::jsonb, 'red', 'This is a double penalty: you lose your entire deposit AND still owe rent for the rest of the lease. Liquidated damages clauses (pre-set penalties) are only enforceable when they reasonably estimate actual harm. Forfeiting the full deposit on top of remaining rent obligations is punitive, not compensatory, and courts routinely strike down penalty clauses that exceed actual losses. The landlord also has a legal duty to mitigate -- meaning they must try to re-rent the unit, not just collect rent from you on an empty apartment.', 'In the event of early termination by Tenant, Tenant shall provide 60 days'' written notice. Tenant shall be responsible for rent until the earlier of (a) the end of the notice period, or (b) the date a replacement tenant begins a new lease. Landlord shall make reasonable efforts to re-let the Premises. The security deposit shall be returned in accordance with standard deposit return procedures, less any legitimate deductions.', 'Restatement (Second) of Contracts Section 356 renders penalty clauses unenforceable where they are disproportionate to actual loss. California Civil Code Section 1951.2 requires landlord to mitigate damages. UK Consumer Rights Act 2015 Schedule 2 paragraph 6 targets terms requiring disproportionately high compensation. EU Directive 93/13/EEC Annex paragraph (e) prohibits terms requiring disproportionately high compensation from the consumer.', '[-0.016355272,0.09111043,-0.014512767,0.00096539,-0.028232241,-0.01976589,-0.04145451,0.029264638,-0.020740