INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-2002-4a00-9000-000000000007', 'Landlord may deduct from the security deposit any amounts deemed necessary for cleaning, repairs, repainting, carpet replacement, or other work required to restore the Premises to their original condition, at Landlord''s sole discretion.', 'security_deposit', '["lease"]'::jsonb, 'red', 'The phrase ''at Landlord''s sole discretion'' means the landlord alone decides how much to deduct, with no accountability. Combined with ''restore to original condition,'' this ignores the legal concept of ''normal wear and tear'' -- the gradual deterioration that happens through everyday living (faded paint, minor scuffs, worn carpet). You cannot be charged for normal aging of the property. This clause tries to make you pay for things that are the landlord''s responsibility.', 'Landlord may deduct from the security deposit only the actual, documented cost of repairing damage caused by Tenant beyond normal wear and tear. Normal wear and tear includes minor scuffs, nail holes, faded paint, and gradual carpet wear from ordinary use. Within 21 days of lease termination, Landlord shall provide Tenant with an itemized list of deductions, accompanied by copies of receipts or invoices for all work performed.', 'California Civil Code Section 1950.5(b) limits deductions to actual damages beyond normal wear and tear, with itemized statement required. New York GOL Section 7-108(1-a) requires reasonable, itemized deductions. UK Tenant Fees Act 2019 restricts deposit deductions to actual loss suffered. Restatement (Second) of Contracts Section 208 renders unconscionable terms unenforceable.', '[-0.03499673,0.033971746,-0.0005066,-0.002692139,-0.021848558,-0.042191606,-0.011998129,0.023370855,-0.012683583,-0.0597185,-0.057037033,-0.059765734,-0.045847,-0.06856681,0.027798383,0.010154042,0.0