INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-2005-4a00-9a00-000000000010', 'Landlord shall hold the security deposit without obligation to pay interest thereon. The deposit may be commingled with Landlord''s personal or business funds at Landlord''s discretion.', 'security_deposit', '["lease"]'::jsonb, 'yellow', 'When a landlord mixes your deposit with their own money (called ''commingling''), your deposit is no longer protected if the landlord goes bankrupt or has financial problems -- creditors could seize it. Many jurisdictions require landlords to keep deposits in separate accounts specifically to prevent this. Not paying interest may also violate local laws, though this varies widely.', 'Landlord shall hold the security deposit in a separate, federally insured interest-bearing account at a banking institution located in the state where the Premises are situated. Landlord shall not commingle the deposit with personal or business funds. Interest earned shall belong to Tenant and shall be paid or credited annually.', 'New York GOL Section 7-103 requires deposits held in trust, separate from landlord''s assets, in interest-bearing accounts. Massachusetts GL c. 186 Section 15B(3) requires separate interest-bearing account with annual interest payment to tenant. UK Housing Act 2004 Sections 213-214 require deposit protection in government-approved schemes within 30 days.', '[0.004024083,0.023247616,0.027997762,0.020401174,-0.018073473,-0.009912186,-0.035805665,0.04930137,-0.02402637,-0.003186765,0.007710306,-0.099945106,-0.025383312,-0.020224612,0.031016445,-0.00054471,-0.005170358,-0.006118085,-0.002991917,-0.028878795,-0.005160091,0.03355571,-0.003617775,0.019617222,0.012730548,-0.077567734,-0.090328045,0.010496955,0.000978367,-0.038363345,-0.035805665,0.028602434,-0.010700155,0.039603826,0.003017025,0.002197904,0.003343061,-0.01756