INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-8001-4a00-9a00-000000000035', 'Subletting, assignment, or transfer of this Lease, or permitting any person other than Tenant and persons listed on this Lease to occupy the Premises for any duration, is strictly prohibited under all circumstances. Any violation shall be grounds for immediate termination.', 'subletting', '["lease"]'::jsonb, 'yellow', 'An absolute ban on subletting with no exceptions locks you into the lease with no flexibility. If you need to relocate for a job, family emergency, or military service, you cannot find someone to take over your lease -- you either stay and pay or leave and pay. Many jurisdictions require landlords to allow reasonable subletting and not unreasonably withhold consent. The ''any person... any duration'' language could even penalize you for having an overnight guest.', 'Tenant shall not sublet the Premises or assign this Lease without Landlord''s prior written consent, which shall not be unreasonably withheld, conditioned, or delayed. Landlord shall respond to any subletting request within 14 days. If Landlord rejects a proposed subtenant, Landlord shall provide specific, reasonable grounds for rejection in writing. Short-term guests (stays under 14 consecutive days) do not require Landlord''s approval.', 'New York Real Property Law Section 226-b requires landlords to not unreasonably withhold consent to sublet. California Civil Code Section 1995.310 codifies the rule against unreasonable withholding. San Francisco Rent Ordinance Section 6.15 permits roommate replacement in rent-controlled units. UK Landlord and Tenant Act 1927 Section 19 implies reasonableness into consent-to-assign clauses.', '[-0.035284385,0.063576736,-0.056980543,0.009473965,-0.051550377,-0.050565246,-0.012335599,0.044869903,0.024316536,0.011969195,0.009330541,-0.031130958,-0.0