INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-4005-4a00-9000-000000000022', 'This Lease may be terminated by Landlord upon sale or transfer of the Property to a new owner. Upon such sale, Tenant shall vacate the Premises within 30 days of written notice, and Landlord shall have no further obligations to Tenant, including return of the security deposit.', 'termination', '["lease"]'::jsonb, 'red', 'In most jurisdictions, a sale does not terminate an existing lease -- the new owner inherits the lease and must honor it. This clause tries to circumvent that rule and also eliminates your right to get your deposit back. The landlord is essentially saying they can sell the building and leave you homeless with no deposit, which is illegal in most places under the doctrine that leases ''run with the land.''', 'In the event of sale or transfer of the Property, this Lease shall remain in full force and effect, and the new owner shall assume all of Landlord''s obligations hereunder, including responsibility for the security deposit. Landlord shall transfer the security deposit to the new owner and provide Tenant with written notice of the transfer, including the new owner''s contact information.', 'California Civil Code Section 1950.5(h) requires transfer of deposit to new owner on sale. New York GOL Section 7-105 requires lease obligations to transfer with the property. UK Landlord and Tenant Act 1985 Section 3 transfers landlord covenants to the assignee. Common law doctrine of privity of estate means leases run with the land.', '[0.012130652,0.062509954,-0.034512136,-0.007293913,-0.00360366,0.004606578,-0.034112938,0.007817451,0.02453226,0.001664574,-0.0126816,-0.045814615,-0.035942063,-0.032629624,0.011777597,0.06244038,-0.006777682,-0.011590272,0.06541615,0.05999758,-0.058171473,-0.020222152,-0.034420747,0.010000319,0.010032988,-0.031156065,-