INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-4001-4a00-a000-000000000018', 'Landlord may terminate this Lease at any time, for any reason or for no reason, upon providing Tenant with 14 days'' written notice to vacate. Tenant shall have no right to contest such termination.', 'termination', '["lease"]'::jsonb, 'red', 'A lease is supposed to guarantee you housing for a fixed period. This clause lets the landlord kick you out with only two weeks'' notice for no reason at all, which defeats the entire purpose of a lease. In many jurisdictions, landlords can only terminate mid-lease for specific causes (like non-payment of rent or serious lease violations). No-cause termination with 14 days'' notice is illegal in many places, especially during a fixed term.', 'This Lease may be terminated by Landlord during the fixed term only for material breach by Tenant, including non-payment of rent, substantial damage to the Premises, or illegal activity on the Premises. Landlord shall provide Tenant with written notice specifying the breach and allowing a 30-day cure period before commencing any termination proceedings. Tenant shall have the right to contest termination through applicable legal channels.', 'California Civil Code Section 1946.2 (AB 1482) requires just cause for eviction. Oregon ORS 90.427 requires 90 days'' notice for no-cause termination in the first year, and just cause after. New York Real Property Law Section 226-c requires 30-90 days'' notice depending on tenancy length. UK Housing Act 1988 Section 21 (being reformed) requires minimum 2 months'' notice. EU Directive 93/13/EEC Annex paragraph (f) prohibits terms authorizing the supplier to dissolve the contract on a discretionary basis.', '[-0.04660848,0.09327929,-0.016864767,-0.049206864,-0.054784495,-0.004004246,-0.03780272,-0.028529868,0.040694926,0.038421363,0.01200528,-0.01