INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5a7b8c9-d0e1-4f2a-b3c4-d5e6f7a8b9c0', 'We may terminate or suspend your access to the Services immediately, without prior notice or liability, for any reason whatsoever, including without limitation if you breach the Terms. Upon termination, your right to use the Services will immediately cease. All provisions of the Terms which by their nature should survive termination shall survive termination, including, without limitation, ownership provisions, warranty disclaimers, indemnity provisions, and limitations of liability. Any data associated with your account may be deleted within thirty (30) days of termination, and we shall have no obligation to provide you with access to, or copies of, your data.', 'termination', '["tos"]'::jsonb, 'red', 'The company can lock you out instantly, for any reason, with no warning and no way to appeal. You lose access to all your data within 30 days and they have no obligation to let you export it first. Meanwhile, all the clauses that benefit the company (like owning your content and not being liable) survive forever after termination.', 'We may terminate your account for material breach of these Terms after providing you with 14 days'' written notice and an opportunity to cure the breach. Upon termination for any reason, we will provide you with a 30-day period to export your data. You may request a machine-readable copy of all data associated with your account. Prepaid fees will be refunded on a pro-rated basis for the unused portion of service.', 'GDPR Article 20 guarantees data portability rights that cannot be contractually waived. EU Unfair Contract Terms Directive Annex 1(f) flags terms permitting the seller to dissolve the contract on a discretionary basis without giving the same right to the consumer. UK CRA 2015 Schedule 2 para 7 grey-lists terms allowing disproportionate termination. EU Digital Services Act Article 17(3) requires platforms to provide a statement of reasons for account restrictions.', '[-0.024640016,0.026295593,-0.005332872,0.012190119,-0.011400114,0.018208187,-0.02063179,-0.00473047,0.03130039,0.022202551,-0.030465929,-0.030391797,-0.06817332,-0.04871585,-0.032807853,0.06873454,-0.013058688,-0.002899626,0.011776936,0.048371416,0.001643646,0.000910197,-0.054171856,-0.001190622,-0.018136451,-0.009594318,0.003840822,0.051566023,-0.018687837,0.021684634,0.013972656,0.011341584,-0.017517446,0.013774031,0.030212082,0.009980052,0.043920428,-0.0690861,0.002576559,0.007074457,0.047880985,0.007018924,-0.013153499,0.017161367,0.023241755,-0.04563614,-0.035158042,0.03726192,-0.021456042,-0.012746151,-0.045001365,-0.02230897,0.008800493,0.063093,-0.005438986,0.00677281,0.08091201,0.07714054,-0.00582717,0.03071972,-0.006566948,-0.013379117,0.006155591,0.037010547,0.010113235,0.005692732,0.013996037,-0.01846858,0.017642112,-0.01031155,0.06074508,0.044902142,0.009059978,0.031993065,0.00383688,0.017938057,-0.000682456,0.059238307,0.009090337,0.030099077,-0.020689515,0.035895802,-0.02078162,0.015714906,-0.044578295,-0.05459879,0.06461729,0.02376502,0.021367636,0.011039346,-0.003393646,-0.024640823,0.048538048,-0.053976208,-0.021694418,0.05180736,0.003837354,-0.044278637,0.026838876,0.022123463,0.020992473,-0.042596295,0.003871554,0.027502535,0.010417392,-0.001518565,-0.00408816,-0.054144334,-0.061084032,0.05271678,-0.064925864,-0.030029008,0.00335567,-0.009743364,0.073846065,0.023849025,-0.006885038,-0.008922304,0.001210552,-0.048685998,-0.03660056,-0.006813277,0.035728946,-0.02065123,0.007150277,0.028148806,-0.000813584,0.012758804,0.043789323,0.025479587,0.0850438,-0.058483988,0.019491686,0.03566145,-0.003741287,0.04316818,-0.01359074,0.002820517,-0.00800449,0.01652604,-0.021144917,0.02692184,0.03071366,0.029072883,0.0644358,0.049954034,-0.017978663,0.03945106,-0.038380668,-0.043447968,0.006733245,-0.041948937,0.0