INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4e1f2a3-4b5c-4d6e-8f9a-0b1c2d3e4f5a', 'The Company may terminate the Employee''s employment at any time, with or without cause and with or without notice. Upon any termination of employment by the Company, any unvested equity awards, accrued but unused paid time off, earned but unpaid bonuses, and deferred compensation shall be immediately and irrevocably forfeited, regardless of the reason for termination.', 'termination', '["employment"]'::jsonb, 'red', 'While at-will employment (where either side can end the job at any time) is legal in most US states, coupling it with forfeiture of earned compensation is a different matter entirely. This clause means the company can fire you the day before your bonus is paid or your equity vests, and you lose everything you have already earned. Accrued paid time off is considered earned wages in many states, so requiring its forfeiture on termination may violate wage payment laws.', 'Either party may terminate this employment relationship upon thirty (30) days'' written notice, or immediately for Cause as defined in Section X. Upon termination for any reason, the Employee shall receive (a) all accrued but unused paid time off, paid out at the Employee''s then-current base rate, (b) any bonus earned for a completed performance period, payable on the normal bonus payment date, and (c) pro-rata vesting of equity awards through the termination date.', 'California Labor Code section 227.3 requires payout of accrued vacation upon termination. Illinois Wage Payment and Collection Act (820 ILCS 115) requires payment of all earned compensation upon separation. UK Employment Rights Act 1996 sections 86-91 require statutory minimum notice periods (1 week per year of service, up to 12 weeks). EU Directive 2019/1152 Article 8 requires reasonable notice periods. Forfeiture of earned wages may violate state wage theft laws in New York, Massachusetts, Colorado, and others.', '[-0.029078567,0.030455029,0.039761834,0.013145569,-0.061171964,0.03434293,-0.016687408,-0.060501866,-0.039882276,0.028048288,-0.04274827,-0.01017121,-0.0313227,-0.011342055,-0.007514558,0.0209436,-0.044939417,0.019066947,-0.02022712,0.040944718,-0.014599269,0.029488888,-0.017566176,0.019612985,0.028199637,0.008220918,-0.025215825,0.03668198,0.020097485,0.015204466,0.03123097,0.035789784,-0.047517873,-0.001702425,-0.03126455,0.014102486,0.05119863,-0.0371766,0.006493457,-0.01927853,0.017680068,0.005427479,0.049387906,0.015199863,0.011830219,-0.047443375,-0.04164448,0.009912739,0.010997435,-0.004775812,0.03342475,-0.002812256,-0.016913237,0.014726532,-0.032084763,-0.000635317,0.010039607,0.08039465,0.021286987,-0.04082959,0.050256085,-0.003013009,0.021663705,0.041216087,-0.036583878,-0.055386733,-0.012678273,-0.018679937,-0.008113294,-0.03601529,0.018091565,0.051815245,0.007109259,0.017945735,0.008844438,-0.002056305,0.007402845,0.039314315,-0.03200151,0.028216416,-0.06200247,0.005204065,0.04769233,0.05322192,-0.042639725,-0.031042855,0.014680243,-0.006700419,0.012553777,0.08388686,0.012901473,-0.06345719,0.04627324,-0.016209746,-0.027361954,0.04101553,-0.008696409,0.019943235,0.028992873,-0.004056153,-0.005493619,0.000185294,0.017216025,0.026325896,-0.013647188,-0.01778517,0.022220396,-0.06059493,-0.005937192,0.050096598,-0.03276984,-0.04629674,0.030845148,-0.009705681,0.05918973,0.027894635,-0.012769903,-0.067916445,0.007094977,-0.00973812,0.00182374,-0.017197529,-0.026200745,0.000339073,-0.03951849,0.025089609,0.004978578,-0.004830036,0.010399496,0.02883652,0.0163545,-0.014424096,-0.026648752,0.017223572,-0.0378347,0.07976727,-0.034964122,-0.008355027,0.011596844,-0.018778857,-0.040343568,-0.043860003,-0.015559025,0.06921224,0.028931187,-0.011205663,-0.026378177,0.015920753,-0.04262572,-0.03266759,-0.022551153,-0.050359108,-0.034087013,0.04530049,-0.030177917,-0.0