INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2d1d2d3-d4d5-46d7-88d9-dadb0c0d0e0f', 'Contractor may not terminate this Agreement without Client''s prior written consent. In the event Contractor terminates without such consent, Contractor shall be liable to Client for all direct and consequential damages, including the cost of finding and engaging a replacement contractor, project delays, and lost business opportunities.', 'termination', '["freelance"]'::jsonb, 'red', 'You can''t quit without the client''s permission, and if you do, you''re liable for potentially enormous damages including their ''lost business opportunities'' -- an open-ended sum that could dwarf the contract value. This is effectively indentured servitude: the client can terminate freely, but you''re locked in and financially punished for leaving.', 'Either party may terminate this Agreement upon thirty (30) days written notice. Upon termination by Contractor, Contractor shall use reasonable efforts to complete work in progress or transition it to Client''s designated replacement. Neither party shall be liable for consequential damages arising from a good-faith termination with proper notice.', 'One-sided termination rights create an imbalance that may be unconscionable under Restatement (Second) of Contracts Section 208. EU Directive 93/13/EEC Annex paragraph 1(f) flags terms enabling the supplier to dissolve the contract while denying the same right to the consumer. UK Consumer Rights Act 2015 Schedule 2 paragraph 7 addresses asymmetric termination rights. Consequential damages for quitting with notice are rarely awarded by US or UK courts.', '[-0.012830888,-0.017742813,-0.04021922,-0.019003907,-0.02863259,0.029781597,0.012480618,0.003821669,-0.029028684,0.07374382,-0.001463101,-0.0480203,-0.024497135,-0.07693525,-0.013069515,0.03301,-0.016796088,-0.02272737,0.036888566,-0