INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2c1c2c3-c4c5-46c7-88c9-cacb0c0d0e0f', 'In the event of termination by either party for any reason, all intellectual property rights in the Work Product, including incomplete work, concepts, drafts, and preparatory materials, shall immediately and automatically revert to or vest in Client, regardless of whether payment for such work has been made.', 'termination', '["freelance"]'::jsonb, 'red', 'If the contract ends -- even if the CLIENT breaks the terms -- they automatically get all your work, including unfinished drafts and concepts, without having to pay for any of it. This removes any leverage you have to get paid for completed work. The client could intentionally terminate to get free deliverables.', 'Upon termination, intellectual property rights in completed Work Product shall transfer to Client only upon receipt of full payment for all Services rendered through the termination date. Until such payment is received, Contractor retains all rights in the Work Product. Incomplete drafts and concepts remain the property of Contractor.', 'Conditional IP transfer upon payment is a recognized and enforceable structure. UK Sale of Goods Act 1979 Section 19 allows retention of title until payment (Romalpa clause). Restatement (Third) of Restitution Section 39 allows restitution when the other party fails to perform. EU Directive 93/13/EEC Annex paragraph 1(o) flags terms binding the consumer where the supplier has not performed their obligation.', '[-0.009916496,0.012293472,-0.012309294,0.019506043,-0.047473505,0.005599175,0.00931556,-0.007844284,-0.043326735,0.033108935,0.00175021,-0.016154632,-0.05708249,-0.059566814,0.024562282,-6.828e-06,-0.071698755,-0.021851743,0.031112054,0.019519852,0.010173411,0.038492154,-0.012671485,-0.021019487,-0.01708405,-0.036529765,-0.036096156,0.049324643,-0.017322503