INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2b1b2b3-b4b5-46b7-88b9-babb0c0d0e0f', 'Client may terminate this Agreement immediately upon written notice for any reason or no reason. Upon such termination, Contractor shall immediately cease all work and deliver all Work Product in its current state. Contractor shall have no claim for damages, lost profits, or any other compensation arising from such termination.', 'termination', '["freelance"]'::jsonb, 'red', 'The client can fire you instantly with zero notice, zero compensation for work done, and zero kill fee -- while keeping everything you''ve built. You could quit other projects to take this one, block out your calendar, and get cancelled on day one with nothing to show for it. There''s no symmetry -- the client takes zero risk.', 'Either party may terminate this Agreement for convenience upon fourteen (14) days written notice. Upon termination, Client shall pay for all Services rendered through the effective date of termination plus any pre-approved expenses. If Client terminates without cause, Client shall additionally pay a termination fee equal to two (2) weeks of the agreed rate.', 'UK Supply of Goods and Services Act 1982 Section 15 implies an obligation to pay a reasonable charge for services performed. Restatement (Third) of Restitution Section 1 prevents unjust enrichment where work has been performed. EU Directive 93/13/EEC Annex paragraph 1(f) flags terms permitting the supplier to dissolve the contract on a discretionary basis where the consumer receives no compensation. NYC Freelance Isn''t Free Act requires payment for all services performed.', '[-0.027021663,0.023993516,-0.030123224,0.001002956,-0.044027798,0.008965958,0.01786605,-0.028694373,-0.026427312,0.03153485,0.002929725,0.006105324,-0.017957475,-0.048025474,0.004523973,0.041264452,-0.07023629,-0.025756184,0.02631366,