INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-4003-4a00-9a00-000000000020', 'Tenant agrees that any termination by Tenant prior to the natural expiration of the Lease term shall constitute a default, and Tenant shall be liable for the total remaining rent due through the end of the Lease term, accelerated and payable immediately upon vacating.', 'termination', '["lease"]'::jsonb, 'red', 'Rent acceleration means if you leave early, you owe ALL remaining rent at once -- not just month by month. If you have 8 months left on a $2,000/month lease, you would owe $16,000 immediately. This ignores the landlord''s legal duty to mitigate damages by trying to find a new tenant. If a new tenant moves in the next month, the landlord would collect double rent -- yours and the new tenant''s. Courts routinely strike down acceleration clauses in residential leases as unconscionable penalties.', 'If Tenant terminates prior to the Lease expiration, Tenant shall provide at least 60 days'' written notice and shall pay an early termination fee equal to two months'' rent. Landlord shall make commercially reasonable efforts to re-let the Premises. Tenant''s liability for remaining rent shall be reduced by any rent received from a replacement tenant. No rent acceleration shall apply.', 'Restatement (Second) of Contracts Section 356 renders penalty clauses unenforceable. California Civil Code Section 1951.2 requires landlord mitigation of damages. Austin Apartments v. Keough (Tex. App. 2004) held acceleration clauses in residential leases unenforceable. EU Directive 93/13/EEC Annex paragraph (e) prohibits disproportionate compensation clauses.', '[-0.018189419,0.052536923,-0.03295065,0.002272866,-0.07495645,-0.026130822,-0.006823756,0.023587206,0.05531347,0.032472115,0.0125624,-0.01637286,-0.02691776,-0.10437395,0.014772698,0.040114935,0.0061209,0.013757735,0.