INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-4004-4a00-b000-000000000021', 'Landlord may terminate this Lease immediately and without notice if Landlord determines, in Landlord''s sole judgment, that Tenant has violated any term or condition of this Lease, any house rules, or any instructions provided by Landlord or Landlord''s agents.', 'termination', '["lease"]'::jsonb, 'red', 'This lets the landlord evict you instantly for any alleged violation, no matter how minor, with no notice and no chance to fix the problem. ''Sole judgment'' means the landlord is both accuser and judge. Minor issues like leaving a bike in the hallway or having a guest stay overnight could technically trigger immediate eviction. Every jurisdiction requires formal eviction procedures with notice, right to cure, and judicial oversight -- you cannot be thrown out by one person''s unilateral decision.', 'In the event of a lease violation, Landlord shall provide Tenant with written notice specifying the nature of the violation and a reasonable cure period of no less than 14 days (or 3 days for non-payment of rent). If Tenant fails to cure within the notice period, Landlord may initiate termination proceedings in accordance with applicable law. Tenant shall have the right to contest any termination.', 'US Uniform Residential Landlord and Tenant Act Section 4.201 requires written notice and cure period before termination. California CCP Section 1161 requires 3-day notice for non-payment and 3-day notice to cure or quit for other violations. UK Housing Act 1988 Section 8 requires notice periods of 2 weeks to 2 months depending on grounds. EU Directive 93/13/EEC Annex paragraph (f) targets unilateral dissolution rights.', '[-0.03293848,0.084829114,0.03936749,0.004456117,-0.028439458,0.013509118,-0.0511396,-0.00928423,0.048751205,0.02912429,-0.015178302,-0.04833836,-0