INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4b4c5d6-7e8f-4a9b-9c2d-3e4f5a6b7c8d', 'In the event of termination by the Company for Cause, the Employee shall not be entitled to any severance payment, accrued bonus, or unvested equity. For purposes of this Agreement, ''Cause'' shall include, without limitation, any act or omission that the Company, in its sole discretion, determines to be detrimental to the Company''s interests, reputation, or business relationships.', 'termination', '["employment"]'::jsonb, 'red', 'The definition of ''Cause'' here is so broad that virtually any action or inaction could qualify. The phrase ''without limitation'' means the listed reasons are just examples -- the company can add any reason it wants. Worse, the company is the sole judge of what is ''detrimental to its interests.'' This means the company can label almost any termination as ''for Cause'' to avoid paying severance and benefits you have earned, turning the for-cause definition into an empty formality.', 'For purposes of this Agreement, ''Cause'' shall mean: (a) a material breach of this Agreement that remains uncured for thirty (30) days after written notice specifying the breach; (b) conviction of, or plea of guilty or nolo contendere to, a felony; (c) willful misconduct or gross negligence in the performance of duties that results in material harm to the Company; or (d) fraud or embezzlement involving Company assets. The determination of Cause shall require approval by the Board of Directors and the Employee shall have the opportunity to be heard before such determination is final.', 'UK Employment Rights Act 1996 section 98 requires that dismissal be for a fair reason and follow a fair procedure; an unlimited ''sole discretion'' standard would not satisfy this test. US courts in Russ v. TeleCom Semiconductor Inc. (1999) and similar cases have found vague for-cause definitions unconscionable when they give one party unfettered discretion. Restatement (Second) of Contracts section 205 imposes a duty of good faith that constrains discretionary termination provisions.', '[-0.051750395,0.035583347,0.02045639,0.015685491,-0.06422584,0.02804307,-0.006505192,0.00570386,-0.044154737,0.020842971,-0.02581152,-0.033635315,-0.010532597,-0.05865779,0.008885527,0.037065238,-0.034863707,0.009882663,-0.025720373,0.009711384,-0.027531682,0.03858663,-0.016895596,0.021972626,-0.009956549,-0.00127818,0.011313578,0.014150669,0.00730166,-0.039189488,0.00514893,0.000241489,-0.003681846,-0.013250092,0.01148425,-0.006527622,0.028559694,-0.03126597,0.012567929,-0.019205863,0.06353759,-0.007939042,0.055687826,-0.004467675,0.01670814,-0.048429873,-0.04541852,0.012936573,-0.008484721,-0.004522439,0.012634247,-0.00660578,0.001068573,-0.040761158,0.016488822,0.009512669,0.050122175,0.05880957,-0.013452407,-0.02141902,0.02858894,-0.01817423,0.018669387,0.035481464,0.000791584,-0.059700284,-0.037093706,-0.022644995,0.041593593,0.017519334,0.05045665,0.04096117,-0.028225608,-0.011520077,-0.006898591,0.018662952,-0.022892455,0.028037796,-0.021469694,0.045323335,-0.04975328,-0.011882065,0.037861038,0.04385022,-0.026859157,-0.011487412,-0.009477082,-0.000365503,-0.019631399,0.08939498,0.030653624,-0.08654952,0.044143636,0.008684657,0.016224237,0.07347277,-0.019328907,0.002188136,-0.030131863,-0.017497627,0.012418821,-0.001688877,0.03308315,0.049706753,0.038634147,0.006971422,0.010827487,-2.8984e-05,0.03041733,0.02074327,-0.014101549,-0.05549513,0.000529604,0.01325076,0.06545119,0.03519386,0.000345976,-0.046432693,0.009784664,-0.011626796,-0.003061208,-0.001942381,-0.004848195,-0.00071703,-0.05048096,0.03816135,0.008057154,-0.008194095,-0.004484253,0.03576203,-0.01391863,0.003821637,0.014616805,0.0679938,-0.014895512,0.071209945,0.000523915,0.024086095,-0.009052097,0.011594125,-0.018150654,0.014428544,-0.052508324,0.027114866,0.046083264,0.021309