INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('d4f2a3b4-5c6d-4e7f-9a0b-1c2d3e4f5a6b', 'In the event the Employee voluntarily resigns within twenty-four (24) months of the Employee''s start date, the Employee shall repay the Company the full gross amount of any sign-on bonus, relocation assistance, and any other special payments made in connection with the commencement of employment, without proration, within thirty (30) days of the Employee''s last day of employment.', 'termination', '["employment"]'::jsonb, 'yellow', 'This requires full repayment of all sign-on money if you leave within two years, with no reduction based on how long you actually stayed. If you received a $20,000 sign-on bonus and quit after 23 months, you owe back the full $20,000. This can trap you in a bad job because you cannot afford to leave. Increasingly, regulators are scrutinizing these ''stay-or-pay'' provisions. Note that repayment is based on the gross (pre-tax) amount, meaning you may owe more than you actually received after taxes.', 'In the event the Employee voluntarily resigns within twelve (12) months of the Employee''s start date, the Employee shall repay the Company a pro-rated portion of the net (after-tax) sign-on bonus, calculated as the remaining months of the twelve-month period divided by twelve. No repayment shall be required if the Employee resigns due to a material breach by the Company, a reduction in base salary, a relocation of more than thirty (30) miles, or a material diminution of duties. Relocation assistance shall not be subject to clawback.', 'The CFPB and FTC have signaled increased scrutiny of ''stay-or-pay'' provisions, including training repayment agreement provisions (TRAPs). California courts in In re Acknowledgment Cases (2015) limited enforceability of repayment clauses that function as penalties rather than reasonable liquidated damages. UK law treats such clauses as restraint of trade if the repayment amount is disproportionate to the employer''s actual loss. Restatement (Second) of Contracts section 356 distinguishes enforceable liquidated damages from unenforceable penalties.', '[-0.006151421,0.008554726,-0.07475448,0.0164061,-0.03614206,0.031045768,-0.016841905,0.04261155,0.006620116,0.005799619,-0.052628335,0.01686416,-0.009321859,-0.000606702,0.048429217,0.012049415,0.000364854,0.050695147,-0.006907492,0.05340515,-0.024278723,0.037569962,0.02498562,0.013800221,-0.021414544,-0.01585859,-0.007468123,0.018912895,-0.030441081,-0.010931325,0.059055336,0.019228421,-0.025277097,0.013864103,0.009865066,-0.020559825,0.06734368,-0.078578405,0.023549115,-0.000405442,-0.006249146,0.020654293,0.042961903,-0.000510832,0.014639357,-0.014888432,-0.006983152,-0.010642589,0.017986706,0.012300782,-0.025213456,-0.023468856,-0.051741764,0.003378374,0.03886714,0.037412785,-0.038638525,0.01794108,0.026399469,0.015763206,0.023432666,0.008990563,0.067889325,0.046252754,-0.012339252,0.028017612,0.041067246,-0.036096755,-0.029989392,-0.026740411,0.008172483,0.035854213,0.019102026,0.029058114,0.026785035,0.012900508,0.019814057,-0.003064628,0.027821252,-0.002652665,-0.000984526,-0.012022479,-0.005182987,0.029693622,-0.06323127,-0.016167898,-0.000889602,-0.07792007,0.014223914,0.024718467,-0.03304496,0.028287461,0.048384268,-0.02340518,-0.025067518,0.018820506,0.036182728,-0.016428847,0.002069206,0.036405228,-0.022612263,-0.009634034,-0.002507209,-0.007363841,-0.007825197,-0.011383704,-0.004617692,-0.024616448,0.034471884,0.001575737,0.03477734,0.016946713,0.023846393,-0.03456507,0.026218131,-0.040425703,0.009342013,-0.07232826,0.017483303,-0.000581971,-0.003779691,0.004327443,-0.034555055,0.03264037,-0.009233863,0.01595537,0.007183658,0.015117775,-0.005129655,-0.048812337,-0.01706894,0.046044398,0.03091612,0.02812274,-0.021979865,0.048650187,0.05020974,0.055607274,-0.000792372,-0.048499838,-0.014393082,0.00152163