INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2e1e2e3-e4e5-46e7-88e9-eaeb0c0d0e0f', 'Upon termination, Contractor shall provide a minimum of sixty (60) days of transition assistance at no additional cost to Client, including knowledge transfer, documentation, and training of Client''s replacement personnel.', 'termination', '["freelance"]'::jsonb, 'yellow', 'After the contract ends, you must work for free for two months helping the client transition. This is unpaid labor disguised as a ''transition'' obligation. If you''ve already started other projects, you''d need to juggle this free work alongside paid engagements.', 'Upon termination, Contractor shall provide up to ten (10) business days of transition assistance at Contractor''s standard hourly rate, including reasonable knowledge transfer and documentation of the Work Product.', 'Requiring extended unpaid services post-termination may violate UK National Minimum Wage Act 1998 if the relationship is deemed one of worker status. Under the IRS 20-factor test for independent contractor status, requiring unpaid transition work is an indicator of employment rather than independent contractor status, potentially triggering misclassification liability. EU Directive 93/13/EEC Annex paragraph 1(d) flags terms permitting retention of sums for services not yet supplied.', '[0.005898688,-0.023189416,-0.047495157,-0.01942128,-0.0395086,0.031656187,-0.02172741,0.007948016,-0.038231667,-0.021816455,-0.002130712,-0.040061105,-0.040385492,-0.044568736,0.04320133,-0.024691638,-0.04216242,-0.01749426,0.023100741,0.021059236,-0.05499215,-0.025737118,-0.005552663,0.002979544,-0.017591652,-0.06757172,0.007150644,0.082987495,-0.003233165,-0.013179461,0.019556979,-0.012388097,-0.05741546,-0.08701518,0.006356199,0.051825415,0.03562524,-0.018616052,0.016511263,0.020389272,0.002630834,0.07862477,-0.007744872,0.0002