INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5e7f8a9-b0c1-4d2e-b3a4-b5c6d7e8f9a0', 'The Company retains the right to remove, disable, or restrict access to any content that it determines, in its sole discretion, violates these Terms, is objectionable, or is otherwise harmful to the Services or other users. The Company may take such action without prior notice and without liability. The Company is not obligated to provide any explanation for such decisions and may, in its sole discretion, refuse to restore removed content or reinstate suspended accounts.', 'termination', '["tos"]'::jsonb, 'yellow', 'This gives the company unlimited power to delete your content or suspend your account based on vague criteria like ''objectionable,'' with no warning, no explanation, and no appeals process. For users who depend on the service for business or store important content, this is extremely risky. The lack of any due process means decisions can be arbitrary.', 'We may remove content that materially violates these Terms or applicable law. Before removing content or restricting your account, we will provide notice and a clear explanation of the reason, except where immediate removal is required to comply with a legal obligation or prevent imminent harm. You may appeal content removal or account restrictions through our appeals process, and we will review your appeal within 14 business days.', 'EU Digital Services Act (DSA) Articles 17 and 20 require platforms to provide statements of reasons for content moderation decisions and an internal complaint-handling system. UK Online Safety Act 2023 imposes duties regarding freedom of expression. First Amendment considerations in the US limit government mandates on content moderation but do not apply to private companies directly.', '[-0.004434767,0.04213798,-0.005224436,0.009578208,-0.034879215,0.05476277,-0.035