INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-4002-4a00-8000-000000000019', 'This Lease shall automatically renew for successive one-year terms unless Tenant provides written notice of non-renewal at least 120 days prior to the expiration of the then-current term. Failure to provide timely notice shall constitute Tenant''s irrevocable agreement to the renewal term and any associated rent increase.', 'termination', '["lease"]'::jsonb, 'yellow', 'A 120-day (four-month) opt-out window is unusually long and easy to miss. Most people are not thinking about lease renewal four months in advance. If you miss the deadline by even one day, you are locked into another full year at whatever the new rent is, with no ability to change your mind. The word ''irrevocable'' means once the deadline passes, you cannot negotiate or exit even if your circumstances change dramatically.', 'This Lease shall automatically renew on a month-to-month basis at the expiration of the initial term, unless either party provides written notice of non-renewal at least 60 days prior to the end of the current term. Landlord shall send Tenant a written reminder of the renewal date and any proposed changes at least 90 days before the term expires.', 'New York GOL Section 5-905 requires landlords to give 15-30 day notice of auto-renewal terms for leases over one month. California Civil Code Section 1945 converts to month-to-month at expiration if no new agreement is signed. UK Consumer Rights Act 2015 Schedule 2 paragraph 10 targets terms enabling automatic extension where the deadline for opting out is unreasonably early.', '[-0.07318334,0.050280698,-0.023130562,-0.005166104,-0.046233043,0.022752633,0.005978033,-0.03528986,0.034364972,0.052381657,-0.001971473,-0.012441127,-0.014591067,-0.030326845,-0.014082888,0.04862258,-0.015533726,0.019731274,0.060829893,0.037712883,0.05