INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5f6a7b8-c9d0-4e1f-a2b3-c4d5e6f7a8b9', 'We reserve the right, at our sole discretion, to modify, suspend, or discontinue, temporarily or permanently, the Services (or any part thereof) at any time and for any reason, with or without notice. You agree that we shall not be liable to you or to any third party for any modification, suspension, or discontinuation of the Services. We further reserve the right to modify these Terms at any time. Your continued use of the Services following the posting of revised Terms constitutes your acceptance of and agreement to the revised Terms.', 'unilateral_changes', '["tos"]'::jsonb, 'red', 'This gives the company total power to change the deal at any time without telling you. They can shut down the service you''re paying for, change the terms to be less favorable, or remove features, all with zero accountability. ''Continued use equals acceptance'' means you could be bound by new terms you never read just by logging in.', 'We may update these Terms from time to time. We will notify you of material changes at least 30 days before they take effect, via email or prominent notice within the Services. If you do not agree with the updated Terms, you may terminate your account and receive a pro-rated refund for any prepaid fees. Continued use of the Services after the effective date constitutes acceptance of the updated Terms. We will maintain an archived history of prior versions of these Terms.', 'EU Unfair Contract Terms Directive Annex 1(j) flags terms enabling unilateral changes without valid reason specified in the contract. CJEU case RWE Vertrieb (C-92/11) held that unilateral variation clauses must provide a right of withdrawal. UK CRA 2015 Schedule 2 para 11 grey-lists terms allowing the trader to alter the contract unilaterally. FTC Act Section 5 may consider u