INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5e3f4a5-b6c7-4d8e-b9a0-b1c2d3e4f5a6', 'The Company reserves the right to introduce, modify, or increase fees for use of the Services or any features thereof at any time. Any fee changes will be effective immediately upon posting to the Company''s website. Your continued use of the Services following any fee change constitutes your acceptance of the new fee structure. The Company is under no obligation to notify you individually of fee changes.', 'unilateral_changes', '["tos"]'::jsonb, 'red', 'This lets the company raise prices at any time without notifying you personally. By simply posting a fee change somewhere on their website, they claim you''ve agreed. You could discover a doubled subscription fee on your credit card statement with no prior warning and no ability to object.', 'We may change our fees with at least 30 days'' advance notice sent directly to your registered email address. Fee increases will not apply to your current billing period. If you do not agree with a fee change, you may cancel your subscription before the new fee takes effect and receive a pro-rated refund for any prepaid period.', 'EU Consumer Rights Directive (2011/83/EU) requires clear information about total costs. EU Unfair Contract Terms Directive Annex 1(d) flags terms permitting the seller to alter the contract unilaterally without a valid reason. UK CRA 2015 Schedule 2 para 12 grey-lists terms permitting price increases after conclusion of contract without right to cancel. FTC Act Section 5 considers failure to disclose material fee changes a deceptive practice.', '[-0.06907211,0.071097635,-0.012644279,-0.001058946,-0.01786535,0.027980097,-0.042651035,-0.033757016,0.020324504,0.012071248,0.012875483,-0.02846823,-0.026809419,-0.057281926,0.08247942,0.011900096,-0.001009593,0.003305778,0.028292956,0.036032736,-0.045