INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('e5c5d6e7-f8a9-4b0c-91e2-f3a4b5c6d7e8', 'You agree that we may communicate with you electronically regarding your account, the Services, and any legal or regulatory matters. You consent to receive all agreements, notices, disclosures, and other communications electronically, including via email to your registered address, in-app notifications, or by posting to our website. You agree that all such electronic communications satisfy any legal requirement that communications be in writing. It is your sole responsibility to ensure your email address is current and to monitor for communications from us.', 'unilateral_changes', '["tos"]'::jsonb, 'yellow', 'While electronic communication is standard, this clause shifts all responsibility for staying informed onto you. If the company sends a critical notice to an old email or buries a terms change in a website post, they''ve fulfilled their obligation. Combined with ''continued use equals acceptance,'' you could unknowingly agree to dramatically worse terms because you missed an in-app banner.', 'We will send important notices regarding material changes to the Terms, account status, or legal matters via email to your registered address. Material changes to the Terms will also be communicated via prominent in-app notification at least 30 days before taking effect. You may request to receive notices via postal mail in addition to electronic delivery.', 'EU Consumer Rights Directive (2011/83/EU) Article 8 requires durable medium for contractual information. CJEU case Content Services (C-49/11) clarified that merely providing a website link does not satisfy the durable medium requirement. UK CRA 2015 Section 64(5) requires terms to be transparent and prominent. US E-SIGN Act (15 USC Section 7001) requires affirmative consent to electronic records.', '[-0.0887176