INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3e7f8a9-b0c1-4d2e-af4a-6b7c8d9e0f1a', 'This Agreement constitutes a mutual non-disclosure agreement between the parties. Each party agrees to protect the other party''s Confidential Information in accordance with the terms hereof. Notwithstanding the foregoing, the determination of what constitutes Confidential Information shall be made solely by the Disclosing Party in its absolute discretion, and Company A reserves the right to designate any information shared by either party as Confidential Information subject to the protections of this Agreement.', 'unilateral_obligations', '["nda"]'::jsonb, 'red', 'This NDA calls itself ''mutual'' — implying both sides have equal rights — but then gives one party (Company A) total control over what counts as confidential for BOTH parties. Company A can retroactively designate your own information as confidential under this agreement, effectively using your NDA against you. If someone controls the definition of what''s protected, the agreement isn''t mutual in any meaningful sense.', 'This Agreement constitutes a mutual non-disclosure agreement. Each party, as Disclosing Party, shall determine what information it discloses constitutes its own Confidential Information, subject to the definition and exclusions set forth in Section [X]. Neither party shall have any right or authority to designate the other party''s information as Confidential Information.', 'US: Restatement (Second) of Contracts Section 208 — unconscionable where one party has disproportionate control. Illusory promise doctrine — agreements where one party has sole discretion may lack consideration. EU: Unfair Contract Terms Directive 93/13/EEC Article 3(1) — significant imbalance in parties'' rights and obligations. Annex para. 1(j) — enabling unilateral alteration of terms. UK: CRA 2015 Schedul