INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3a9b0c1-d2e3-4f4a-8b6c-8d9e0f1a2b3c', 'The Receiving Party acknowledges and agrees that the obligations imposed upon it under this Agreement are one-way in nature, and that the Disclosing Party shall have no corresponding obligations of confidentiality with respect to any information disclosed by the Receiving Party to the Disclosing Party during the course of discussions or negotiations contemplated hereunder.', 'unilateral_obligations', '["nda"]'::jsonb, 'yellow', 'This creates a completely one-sided arrangement: you must keep their secrets, but they have zero obligation to protect yours. If you share sensitive information about your business during negotiations — financials, strategies, technology — they can freely use or disclose it. In many business discussions, both sides inevitably share sensitive information, so a one-way NDA can leave you dangerously exposed.', 'Each party acknowledges that it may receive Confidential Information from the other party in connection with the discussions contemplated hereunder. Accordingly, the obligations of confidentiality and non-use set forth herein shall apply equally and reciprocally to both parties with respect to Confidential Information received from the other party.', 'US: One-way NDAs are generally enforceable when parties have unequal bargaining power, but courts consider the totality of circumstances under Restatement (Second) of Contracts Section 208. EU: Unfair Contract Terms Directive 93/13/EEC Article 3(1) — significant imbalance in the parties'' rights and obligations contrary to good faith. UK: CRA 2015 Part 2 — fairness requirement applies to all consumer and some B2B contracts.', '[0.008632882,-0.060176175,-0.006962608,0.008886871,-0.06247103,0.004713442,-0.061642513,0.03276497,-0.007280685,0.059802692,-0.039062098,-0.022201855,-0.030615