INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('c3f8a9b0-c1d2-4e3f-ba5b-7c8d9e0f1a2b', 'The Receiving Party shall protect the Confidential Information using the highest degree of care and security measures available, including but not limited to encryption, physical access controls, background checks on all personnel who may access Confidential Information, and annual third-party security audits, all at the Receiving Party''s sole cost and expense.', 'unilateral_obligations', '["nda"]'::jsonb, 'yellow', 'Instead of the standard ''reasonable care'' obligation, this demands the absolute highest security measures available — encryption, physical access controls, background checks, and annual third-party security audits — all at your expense. For a small business or startup, these measures could cost tens of thousands of dollars annually. The standard in NDA law is ''reasonable'' care (often defined as the same care you use for your own confidential information), not the maximum theoretically possible.', 'The Receiving Party shall protect the Confidential Information using at least the same degree of care it uses to protect its own confidential information of a similar nature, but in no event less than a reasonable degree of care. Such measures shall include appropriate administrative, technical, and physical safeguards proportionate to the sensitivity of the Confidential Information.', 'US: UTSA requires ''reasonable measures'' to maintain secrecy — not the highest possible measures. Restatement (Third) of Unfair Competition Section 39 comment g. EU: Trade Secrets Directive 2016/943 Article 2(1)(c) — the holder must take ''reasonable steps under the circumstances'' to keep information secret. UK: Trade Secrets Regulations 2018 mirror the EU standard of reasonable steps.', '[-0.024457697,0.04357964,-0.025396453,0.009625492,-0.05530148,0.012758902,-0