INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-9002-4a00-a000-000000000038', 'Landlord may, at its sole discretion, change utility providers, submetering arrangements, or billing methods at any time during the lease term. Any increased costs resulting from such changes shall be borne exclusively by Tenant. Tenant shall pay utility charges billed by Landlord within 5 days of invoice without right to dispute the amount.', 'utilities', '["lease"]'::jsonb, 'yellow', 'Giving the landlord unilateral control over utility billing with no right to dispute is a recipe for overcharging. If the landlord switches to a more expensive provider or adds a markup to utility pass-through charges, you pay the difference with no recourse. Removing your right to dispute charges means you cannot challenge billing errors or inflated amounts. Five days is also an unreasonably short payment window.', 'Utility providers and metering arrangements in effect at lease commencement shall not be materially changed without 60 days'' written notice to Tenant. If Landlord bills Tenant for utilities, Landlord shall provide detailed billing statements reflecting actual usage and actual provider costs without markup. Tenant shall have 30 days to pay utility invoices and may dispute any charge by providing written notice to Landlord within that period.', 'New York Public Service Law Section 52 regulates utility resale and submetering. California PUC Section 739.5 regulates master-metered properties. UK Gas Act 1986 and Electricity Act 1989 regulate maximum resale prices for utilities. EU Directive 93/13/EEC Annex paragraphs (j) and (l) prohibit unilateral contract changes and price increases without consumer right to cancel.', '[-0.038734145,0.04219101,0.01404425,-0.041728474,-0.069241725,0.017128378,-0.06676796,-0.018471807,0.021612437,-0.016512167,0.05084935,-0.033928756,-