INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('a1b2c3d4-9001-4a00-9000-000000000037', 'Tenant shall be responsible for payment of all utilities, including water, sewer, gas, electricity, trash removal, internet, and cable, as well as a proportionate share of common area utility costs, building-wide HVAC, hallway lighting, elevator operation, and landscaping irrigation, as determined by Landlord.', 'utilities', '["lease"]'::jsonb, 'yellow', 'Paying your own apartment''s utilities is standard. But paying a ''proportionate share'' of common area costs -- hallways, elevators, parking lot lights, landscaping -- is essentially paying for the landlord''s building operating costs with no cap and no transparency. Since the landlord determines your ''proportionate share,'' there is no accountability. These costs can be substantial in large buildings and effectively become a hidden rent increase that is hard to verify or dispute.', 'Tenant shall be responsible for utilities individually metered to the Premises, including electricity, gas, and internet. Landlord shall be responsible for water, sewer, trash removal, and all common area utility costs, which are included in the monthly rent. If any common area charges are to be passed through to tenants, the amount shall be specified in Schedule B of this Lease, subject to an annual cap of 3% increase, and Landlord shall provide annual documentation of actual costs.', 'California Civil Code Section 1940.9 requires separate utility meters and prohibits landlords from charging tenants for other tenants'' utility usage. New York Multiple Dwelling Law Section 75-a regulates utility submetering. UK Landlord and Tenant Act 1985 Section 18-30 regulates service charges and requires consultation for large expenditures. EU Directive 93/13/EEC Annex paragraph (l) targets unilateral price changes.', '[-0.01823309,0.05050