INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2b2b3b4-b5b6-47b8-89ba-bbbc0d0e0f10', 'Contractor retroactively assigns to Client all intellectual property rights in any work, materials, or deliverables created by Contractor prior to the Effective Date of this Agreement that relate to, are similar to, or could be useful in connection with the Services, including but not limited to prior research, prototypes, code, designs, and methodologies.', 'work_for_hire', '["freelance"]'::jsonb, 'red', 'This claims ownership of work you created BEFORE the contract even started -- anything that ''could be useful'' for the project. If you did similar work for a previous client, built a personal project in the same space, or developed any relevant tools beforehand, this clause claims it all. It''s retroactive IP seizure with no additional compensation.', 'This Agreement applies only to Work Product created after the Effective Date in performance of the Services. Contractor''s pre-existing intellectual property is listed in Exhibit A and remains the sole property of Contractor. Contractor grants Client a non-exclusive license to use any pre-existing IP incorporated into the Work Product.', 'Retroactive assignment of pre-existing IP without separate consideration may fail for lack of consideration under basic contract law (Restatement (Second) of Contracts Section 71). UK Copyright, Designs and Patents Act 1988 Section 91 requires that assignment of future copyright identify the specific work. EU Directive 93/13/EEC Annex paragraph 1(b) addresses inappropriate exclusion or limitation of the consumer''s legal rights.', '[-0.036742806,-0.018056834,-0.04162133,0.022029776,-0.03676567,0.017090296,-0.015629003,0.008390707,-0.01181845,0.03464056,-0.040720146,-0.008916357,-0.04018987,-0.007152858,0.010268959,-0.027462933,-0.049520183,0.001118515,0.013894004,0.02265637