INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2c2c3c4-c5c6-47c8-89ca-cbcc0d0e0f10', 'Contractor represents and warrants that Contractor has not developed and will not develop any intellectual property similar to the Work Product for any other client. Contractor assigns to Client any intellectual property developed by Contractor that is substantially similar to the Work Product, regardless of when such intellectual property was created.', 'work_for_hire', '["freelance"]'::jsonb, 'red', 'This claims ownership of any similar work you do for anyone, past or future. Freelancers by nature do similar work across clients -- a developer who builds e-commerce sites can''t avoid creating ''similar'' work. This clause could give the client ownership of deliverables you created for other paying clients, both before and after this engagement.', 'Contractor warrants that the Work Product shall be original and shall not infringe the intellectual property rights of any third party. Contractor is free to perform similar services for other clients, provided that Contractor does not use Client''s Confidential Information in such work.', 'Prohibiting similar work for other clients functions as a non-compete and is subject to reasonableness analysis under Restatement (Second) of Contracts Section 188. California Business and Professions Code Section 16600 would void this restraint. Claiming IP created for other clients raises tortious interference with existing contracts. EU Directive 93/13/EEC Article 3(1) addresses significant imbalance.', '[0.005195954,-0.028534135,-0.031049035,0.020502863,-0.037091326,-0.014089558,-0.029942643,-0.004517347,-0.018690372,0.016832806,-0.008721264,-0.0417863,0.010173096,-0.033446833,0.019580515,0.015508861,-0.019267295,-0.0243397,0.015221836,-0.016423646,-0.014016774,-0.036104478,-0.029282104,0.030780476,0.016727174,-0.02813478,0.