INSERT INTO knowledge_patterns (id, clause_pattern, category, contract_type, risk_level, why_risky, safer_alternative, jurisdiction_notes, embedding, created_at) VALUES ('b2a2a3a4-a5a6-47a8-89aa-abac0d0e0f10', 'Contractor acknowledges that all Work Product created under this Agreement shall be considered ''work made for hire'' as defined by the United States Copyright Act. To the extent any Work Product is not deemed a work made for hire, Contractor hereby assigns all right, title, and interest in such Work Product to Client.', 'work_for_hire', '["freelance"]'::jsonb, 'yellow', 'The US Copyright Act only allows ''work for hire'' for independent contractors in 9 specific categories (like translations, tests, atlases, and contributions to collective works). Most freelance work -- custom software, standalone design, original content -- does NOT qualify. Calling it ''work for hire'' when it legally isn''t could cause IP ownership disputes later. The backup assignment clause helps, but the mislabeling creates confusion.', 'Upon receipt of full payment, Contractor assigns to Client all right, title, and interest in the final, approved Work Product created under the applicable Statement of Work. Contractor retains ownership of pre-existing intellectual property and general-purpose tools, granting Client a non-exclusive license to use them as incorporated in the Work Product.', 'Under 17 U.S.C. Section 101, work for hire for independent contractors is limited to nine categories: (1) contribution to a collective work, (2) part of a motion picture, (3) translation, (4) supplementary work, (5) compilation, (6) instructional text, (7) test, (8) answer material for a test, (9) atlas. The Supreme Court in Community for Creative Non-Violence v Reid (1989) established that the common-law agency test determines employee vs. contractor status. Mislabeling work as ''work for hire'' can also be an indicator of misclassification.', '[-0.004586452,0.022462703,-0.019722357,0.036710437,-0.